resource "aws_route53_log_query_configuration" "primary_zone_logging" {
  zone_id = aws_route53_zone.primary.zone_id
  log_query_config {
    cloudwatch_logs_log_group_arn = aws_cloudwatch_log_group.route53_logs.arn
    cloudwatch_logs_resource_policy_arn = aws_cloudwatch_log_resource_policy.route53_logging_policy.arn
  }
}

resource "aws_route53_zone" "primary" {
  name = "example.com"
  comment = "Primary zone for example.com"
}

resource "aws_cloudwatch_log_group" "route53_logs" {
  name              = "aws_route53_example_com"
  retention_in_days = 30
}

resource "aws_cloudwatch_log_resource_policy" "route53_logging_policy" {
  policy_name     = "route53-query-logging-policy"
  policy_document = <<POLICY_DOCUMENT
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Principal": {
        "Service": "route53.amazonaws.com"
      },
      "Action": [
        "logs:CreateLogStream",
        "logs:PutLogEvents"
      ],
      "Resource": [
        "${aws_cloudwatch_log_group.route53_logs.arn}:*"
      ]
    }
  ]
}
POLICY_DOCUMENT
}

