terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create an Elastic Load Balancer (ELB)
resource "aws_lb" "main" {
  name               = "main-elb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.elb.id]
  subnets            = [aws_subnet.public1.id, aws_subnet.public2.id] # Replace with your subnet IDs

  enable_deletion_protection = false # Set to true if you want to prevent accidental deletion
}

# Security group for the ELB
resource "aws_security_group" "elb" {
  name        = "elb-sg"
  description = "Allow HTTP traffic to ELB"
  vpc_id      = aws_vpc.main.id # Replace with your VPC ID

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Route 53 Hosted Zone
resource "aws_route53_zone" "primary" {
  name = "example.com" # Replace with your domain name
}

# Route 53 Record (Alias record pointing to the ELB)
resource "aws_route53_record" "main" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "www" # Replace with your desired subdomain
  type    = "A"

  alias {
    name                   = aws_lb.main.dns_name
    zone_id                = aws_lb.main.zone_id
    evaluate_target_health = true
  }
}

# Example VPC and Subnets (required for ELB)
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "public1" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "public2" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

