terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  alias = "main"
  region = "us-west-1"
}

provider "aws" {
  alias  = "us-east"
  region = "us-east-1"
}

provider "aws" {
  alias  = "eu-central"
  region = "eu-central-1"
}

provider "aws" {
  alias  = "ap-southeast"
  region = "ap-southeast-1"
}

# Create hosted zone in us-west-1
resource "aws_route53_zone" "main" {
  provider = aws.main
  name      = "main.example.com"
}

# Create primary RDS instance in us-west-1
resource "aws_db_instance" "primary" {
  provider = aws.main
  identifier             = "primary"
  engine                 = "postgres"
  engine_version         = "15.4"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  db_name                = "maindb"
  username               = "admin"
  password               = "securepassword123"
  skip_final_snapshot    = true
  publicly_accessible    = false
  multi_az              = true
  storage_encrypted      = true
  backup_retention_period = 7
  copy_tags_to_snapshot  = true
  tags = {
    Name = "primary"
  }
}

# Create replica RDS instances in different regions
resource "aws_db_instance" "replica_us_east" {
  provider = aws.us-east
  identifier             = "replica_us_east"
  engine                 = "postgres"
  engine_version         = "15.4"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  db_name                = "maindb"
  username               = "admin"
  password               = "securepassword123"
  skip_final_snapshot    = true
  publicly_accessible    = false
  replication_source_identifier = aws_db_instance.primary.identifier
  copy_tags_to_snapshot  = true
  tags = {
    Name = "replica_us_east"
  }
}

resource "aws_db_instance" "replica_eu_central" {
  provider = aws.eu-central
  identifier             = "replica_eu_central"
  engine                 = "postgres"
  engine_version         = "15.4"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  db_name                = "maindb"
  username               = "admin"
  password               = "securepassword123"
  skip_final_snapshot    = true
  publicly_accessible    = false
  replication_source_identifier = aws_db_instance.primary.identifier
  copy_tags_to_snapshot  = true
  tags = {
    Name = "replica_eu_central"
  }
}

resource "aws_db_instance" "replica_ap_southeast" {
  provider = aws.ap-southeast
  identifier             = "replica_ap_southeast"
  engine                 = "postgres"
  engine_version         = "15.4"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  db_name                = "maindb"
  username               = "admin"
  password               = "securepassword123"
  skip_final_snapshot    = true
  publicly_accessible    = false
  replication_source_identifier = aws_db_instance.primary.identifier
  copy_tags_to_snapshot  = true
  tags = {
    Name = "replica_ap_southeast"
  }
}

# Create DNS records for each replica
resource "aws_route53_record" "primary" {
  provider = aws.main
  zone_id = aws_route53_zone.main.zone_id
  name    = "primary.main.example.com"
  type    = "A"
  alias {
    name                   = aws_db_instance.primary.endpoint
    zone_id                = aws_db_instance.primary.option_group.zone_id
    evaluate_target_health = false
  }
}

resource "aws_route53_record" "replica_us_east" {
  provider = aws.main
  zone_id = aws_route53_zone.main.zone_id
  name    = "replica-us-east.main.example.com"
  type    = "A"
  alias {
    name                   = aws_db_instance.replica_us_east.endpoint
    zone_id                = aws_db_instance.replica_us_east.option_group.zone_id
    evaluate_target_health = false
  }
}

resource "aws_route53_record" "replica_eu_central" {
  provider = aws.main
  zone_id = aws_route53_zone.main.zone_id
  name    = "replica-eu-central.main.example.com"
  type    = "A"
  alias {
    name                   = aws_db_instance.replica_eu_central.endpoint
    zone_id                = aws_db_instance.replica_eu_central.option_group.zone_id
    evaluate_target_health = false
  }
}

resource "aws_route53_record" "replica_ap_southeast" {
  provider = aws.main
  zone_id = aws_route53_zone.main.zone_id
  name    = "replica-ap-southeast.main.example.com"
  type    = "A"
  alias {
    name                   = aws_db_instance.replica_ap_southeast.endpoint
    zone_id                = aws_db_instance.replica_ap_southeast.option_group.zone_id
    evaluate_target_health = false
  }
}

# Create weighted routing policy for the main domain
resource "aws_route53_record" "weighted_routing" {
  provider = aws.main
  zone_id = aws_route53_zone.main.zone_id
  name    = "db.main.example.com"
  type    = "A"

  alias {
    name                   = aws_db_instance.primary.endpoint
    zone_id                = aws_db_instance.primary.option_group.zone_id
    evaluate_target_health = false
  }

  set_identifier = "weighted-routing"

  failover_routing_policy {
    type = "PRIMARY"
  }

  health_check_id = aws_route53_health_check.primary.id
}

resource "aws_route53_health_check" "primary" {
  provider = aws.main
  fqdn             = aws_db_instance.primary.endpoint
  type             = "HTTPS"
  resource_path    = "/health"
  fully_qualified_domain_name = aws_db_instance.primary.endpoint
  port             = 5432
  request_interval = 30
  failure_threshold = 3
}

resource "aws_route53_record" "replica_us_east_weighted" {
  provider = aws.main
  zone_id = aws_route53_zone.main.zone_id
  name    = "db.main.example.com"
  type    = "A"

  alias {
    name                   = aws_db_instance.replica_us_east.endpoint
    zone_id                = aws_db_instance.replica_us_east.option_group.zone_id
    evaluate_target_health = false
  }

  set_identifier = "weighted-routing"
  weight          = 33
}

resource "aws_route53_record" "replica_eu_central_weighted" {
  provider = aws.main
  zone_id = aws_route53_zone.main.zone_id
  name    = "db.main.example.com"
  type    = "A"

  alias {
    name                   = aws_db_instance.replica_eu_central.endpoint
    zone_id                = aws_db_instance.replica_eu_central.option_group.zone_id
    evaluate_target_health = false
  }

  set_identifier = "weighted-routing"
  weight          = 33
}

resource "aws_route53_record" "replica_ap_southeast_weighted" {
  provider = aws.main
  zone_id = aws_route53_zone.main.zone_id
  name    = "db.main.example.com"
  type    = "A"

  alias {
    name                   = aws_db_instance.replica_ap_southeast.endpoint
    zone_id                = aws_db_instance.replica_ap_southeast.option_group.zone_id
    evaluate_target_health = false
  }

  set_identifier = "weighted-routing"
  weight          = 33
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
      configuration_aliases = [ aws.main, aws.us_east, aws.eu_central, aws.ap_southeast ]
    }
  }

  required_version = "~> 1.9.8"
}


provider "aws" {
  alias = "main"
  region = "us-west-2" 

  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

provider "aws" {
  alias  = "us_east"
  region = "us-east-1" # Example region for US East

  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

provider "aws" {
  alias  = "eu_central"
  region = "eu-central-1" # Example region for EU Central

  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

provider "aws" {
  alias  = "ap_southeast"
  region = "ap-southeast-1" # Example region for AP Southeast

  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_db_instance" "primary" {
  provider = aws.main
  identifier = "master"
  allocated_storage    = 20
  engine               = "postgres"
  instance_class       = "db.t3.micro"
  username             = "dbadmin"
  password             = "your_password_here"
  skip_final_snapshot  = true
  backup_retention_period  = 7
}

resource "aws_db_instance" "replica_us_east" {
  provider             = aws.us_east
  replicate_source_db  = aws_db_instance.primary.arn
  instance_class       = "db.t3.micro"
  identifier           = "mydb-replica-us-east"
  skip_final_snapshot  = true
}

resource "aws_db_instance" "replica_eu_central" {
  provider             = aws.eu_central
  replicate_source_db  = aws_db_instance.primary.arn
  instance_class       = "db.t3.micro"
  identifier           = "mydb-replica-eu-central"
  skip_final_snapshot  = true
}

resource "aws_db_instance" "replica_ap_southeast" {
  provider             = aws.ap_southeast
  replicate_source_db  = aws_db_instance.primary.arn

  instance_class       = "db.t3.micro"
  identifier           = "mydb-replica-ap-southeast"
  skip_final_snapshot  = true
}

# Route53 Hosted Zone
resource "aws_route53_zone" "main" {
  provider = aws.main
  name = "example53.com"
}


# Route53 Records for each RDS Read Replica with a Weighted Routing Policy
resource "aws_route53_record" "replica_us_east_cname" {
  provider = aws.main

  zone_id = aws_route53_zone.main.zone_id
  name    = "us.east.example53.com"
  type    = "CNAME"
  records = [aws_db_instance.replica_us_east.endpoint]
  ttl     = "60"
  weighted_routing_policy {
    weight = 30
  }
  set_identifier = "replica-us-east"
}

resource "aws_route53_record" "replica_eu_central_cname" {
  provider = aws.main

  zone_id = aws_route53_zone.main.zone_id
  name    = "eu.central.example53.com"
  type    = "CNAME"
  records = [aws_db_instance.replica_eu_central.endpoint]
  ttl     = "60"
  weighted_routing_policy {
    weight = 30
  }
  set_identifier = "replica-eu-central"
}

resource "aws_route53_record" "replica_ap_southeast_cname" {
  provider = aws.main

  zone_id = aws_route53_zone.main.zone_id
  name    = "ap.southeast.example53.com"
  type    = "CNAME"
  records = [aws_db_instance.replica_ap_southeast.endpoint]
  ttl     = "60"
  weighted_routing_policy {
    weight = 30
  }
  set_identifier = "replica-ap-southeast"
}

