  name      = "main.example.com"
}

# Create primary RDS instance in us-west-1
resource "aws_db_instance" "primary" {
  provider = aws.main
  identifier             = "primary"
  engine                 = "postgres"
  engine_version         = "15.4"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  db_name                = "maindb"
  username               = "admin"
  password               = "securepassword123"
  skip_final_snapshot    = true
  publicly_accessible    = false
  multi_az              = true
  storage_encrypted      = true
  backup_retention_period = 7
  copy_tags_to_snapshot  = true
  tags = {
    Name = "primary"
  }
}

# Create replica RDS instances in different regions
resource "aws_db_instance" "replica_us_east" {
  provider = aws.us-east
  identifier             = "replica_us_east"
  engine                 = "postgres"
  engine_version         = "15.4"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  db_name                = "maindb"
  username               = "admin"
  password               = "securepassword123"
  skip_final_snapshot    = true
  publicly_accessible    = false
  replication_source_identifier = aws_db_instance.primary.identifier
  copy_tags_to_snapshot  = true
  tags = {
    Name = "replica_us_east"
  }
}

resource "aws_db_instance" "replica_eu_central" {
  provider = aws.eu-central
