  }
}

# Create DNS records for each replica
resource "aws_route53_record" "primary" {
  provider = aws.main
  zone_id = aws_route53_zone.main.zone_id
  name    = "primary.main.example.com"
  type    = "A"
  alias {
    name                   = aws_db_instance.primary.endpoint
    zone_id                = aws_db_instance.primary.option_group.zone_id
    evaluate_target_health = false
  }
}

resource "aws_route53_record" "replica_us_east" {
  provider = aws.main
  zone_id = aws_route53_zone.main.zone_id
  name    = "replica-us-east.main.example.com"
  type    = "A"
  alias {
