provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create a hosted zone for the public database
resource "aws_route53_zone" "public" {
  name = "example.com" # Replace with your domain name
  comment = "Public hosted zone for external database access"
}

# Create a hosted zone for the private database
resource "aws_route53_zone" "private" {
  name = "private.example.com" # Replace with your private domain name
  comment = "Private hosted zone for internal database access"
}

# Create a Route 53 record for the public database
resource "aws_route53_record" "public_db" {
  zone_id = aws_route53_zone.public.zone_id
  name    = "public-db.example.com" # Replace with your desired public endpoint
  type    = "A"

  alias {
    name                   = aws_rds_instance.public.endpoint
    zone_id                = aws_rds_instance.public.endpoint_zone_id
    evaluate_target_health = true
  }
}

# Create a Route 53 record for the private database (using VPC association)
resource "aws_route53_record" "private_db" {
  zone_id = aws_route53_zone.private.zone_id
  name    = "internal-db.example.com" # Replace with your desired internal endpoint
  type    = "A"

  alias {
    name                   = aws_rds_instance.internal.endpoint
    zone_id                = aws_rds_instance.internal.endpoint_zone_id
    evaluate_target_health = true
  }

  depends_on = [aws_route53_zone.private]
}

# Create a VPC for the private database
resource "aws_vpc" "private_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
}

# Create a subnet group for the private database
resource "aws_db_subnet_group" "main" {
  name       = "main"
  subnet_ids = [aws_subnet.private_subnet.id] # Ensure this subnet is in a private subnet
  depends_on = [aws_subnet.private_subnet]
}

# Create a private subnet for the private database
resource "aws_subnet" "private_subnet" {
  vpc_id            = aws_vpc.private_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a" # Change to your preferred AZ
}

# Create a public RDS instance for external users
resource "aws_db_instance" "public" {
  identifier             = "public-db"
  engine                 = "postgres" # Change to your preferred database engine
  engine_version         = "14.5"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  db_name                = "publicdb"
  username               = "admin"
  password               = "your_secure_password" # Change to a secure password
  publicly_accessible    = true
  skip_final_snapshot    = true
  db_subnet_group_name   = aws_db_subnet_group.main.name
}

# Create an internal RDS instance for internal users
resource "aws_db_instance" "internal" {
  identifier             = "internal-db"
  engine                 = "postgres" # Change to your preferred database engine
  engine_version         = "14.5"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  db_name                = "internaldb"
  username               = "admin"
  password               = "your_secure_password" # Change to a secure password
  publicly_accessible    = false
  skip_final_snapshot    = true
  db_subnet_group_name   = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.internal_db.id]
}

# Security group for internal database
resource "aws_security_group" "internal_db" {
  name        = "internal-db-sg"
  description = "Allow internal access to the database"
  vpc_id      = aws_vpc.private_vpc.id

  ingress {
    from_port   = 5432 # PostgreSQL default port
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Adjust to your internal network CIDR
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Route 53 health check for the public database
resource "aws_route53_health_check" "public_db_health_check" {
  health_check_config {
    type               = "HTTPS"
    resource_path      = "/health" # Replace with your health check endpoint
    fully_qualified_domain_name = aws_route53_record.public_db.fqdn
    port               = "443"
    request_interval   = "30"
    failure_threshold  = "3"
    resource_id        = aws_route53_record.public_db.fqdn
    measurement_interval = "30"
    enable_sni         = true
  }
}

# Route 53 health check for the private database
resource "aws_route53_health_check" "private_db_health_check" {
  health_check_config {
    type               = "HTTPS"
    resource_path      = "/health" # Replace with your health check endpoint
    fully_qualified_domain_name = aws_route53_record.private_db.fqdn
    port               = "443"
    request_interval   = "30"
    failure_threshold  = "3"
    resource_id        = aws_route53_record.private_db.fqdn
    measurement_interval = "30"
    enable_sni         = true
  }
}

