provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create hosted zone for the domain
resource "aws_route53_zone" "main" {
  name = "example.com" # Replace with your domain name
}

# Create primary database instance record
resource "aws_route53_record" "primary" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "primary-db.example.com" # Replace with your primary DB endpoint
  type    = "CNAME"
  ttl     = 300
  records = ["primary-db.example.com"] # Replace with your actual primary DB endpoint
}

# Create replica-1 database instance record
resource "aws_route53_record" "replica_1" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "replica-1-db.example.com" # Replace with your replica-1 DB endpoint
  type    = "CNAME"
  ttl     = 300
  records = ["replica-1-db.example.com"] # Replace with your actual replica-1 DB endpoint
}

# Create replica-2 database instance record
resource "aws_route53_record" "replica_2" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "replica-2-db.example.com" # Replace with your replica-2 DB endpoint
  type    = "CNAME"
  ttl     = 300
  records = ["replica-2-db.example.com"] # Replace with your actual replica-2 DB endpoint
}

# Create weighted routing policy for the main database endpoint
resource "aws_route53_record" "main_db_weighted" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "db.example.com" # Replace with your main DB endpoint
  type    = "CNAME"
  ttl     = 300

  alias {
    name                   = aws_route53_record.primary.fqdn
    zone_id                = aws_route53_record.primary.zone_id
    evaluate_target_health = true
    weight                 = 60 # 60% traffic to primary
  }

  set_identifier = "weighted-policy"

  health_check_id = aws_route53_health_check.primary.id
}

resource "aws_route53_record" "main_db_weighted_replica_1" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "db.example.com" # Same as above
  type    = "CNAME"
  ttl     = 300

  alias {
    name                   = aws_route53_record.replica_1.fqdn
    zone_id                = aws_route53_record.replica_1.zone_id
    evaluate_target_health = true
    weight                 = 20 # 20% traffic to replica-1
  }

  set_identifier = "weighted-policy"
}

resource "aws_route53_record" "main_db_weighted_replica_2" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "db.example.com" # Same as above
  type    = "CNAME"
  ttl     = 300

  alias {
    name                   = aws_route53_record.replica_2.fqdn
    zone_id                = aws_route53_record.replica_2.zone_id
    evaluate_target_health = true
    weight                 = 20 # 20% traffic to replica-2
  }

  set_identifier = "weighted-policy"
}

# Health check for primary DB
resource "aws_route53_health_check" "primary" {
  health_check_config {
    type                     = "HTTPS"
    resource_path            = "/health" # Replace with your health check endpoint
    fully_qualified_domain_name = aws_route53_record.primary.fqdn
    request_interval         = 30
    failure_threshold        = 3
    port                     = "443"
  }
}

# Health check for replica-1 DB
resource "aws_route53_health_check" "replica_1" {
  health_check_config {
    type                     = "HTTPS"
    resource_path            = "/health" # Replace with your health check endpoint
    fully_qualified_domain_name = aws_route53_record.replica_1.fqdn
    request_interval         = 30
    failure_threshold        = 3
    port                     = "443"
  }
}

# Health check for replica-2 DB
resource "aws_route53_health_check" "replica_2" {
  health_check_config {
    type                     = "HTTPS"
    resource_path            = "/health" # Replace with your health check endpoint
    fully_qualified_domain_name = aws_route53_record.replica_2.fqdn
    request_interval         = 30
    failure_threshold        = 3
    port                     = "443"
  }
}

# Create weighted routing policy for the main zone
resource "aws_route53_record" "main_weighted" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "main.example.com" # Replace with your main domain
  type    = "A"

  alias {
    name                   = aws_route53_record.main_db_weighted.fqdn
    zone_id                = aws_route53_record.main_db_weighted.zone_id
