# IAM Role for Elastic Beanstalk
resource "aws_iam_role" "eb_ec2_role" {
  name = "eb_ec2_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Instance Profile for Elastic Beanstalk
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "eb_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}

# IAM Policy for Elastic Beanstalk
resource "aws_iam_role_policy_attachment" "eb_ec2_role_attachment" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSElasticBeanstalkEnhancedHealth"
}

# Elastic Beanstalk Application
resource "aws_elasticbeanstalk_application" "my_application" {
  name        = "my_application"
  description = "My Elastic Beanstalk Application"
}

# Elastic Beanstalk Environment
resource "aws_elasticbeanstalk_environment" "my_environment" {
  name                = "my-env"
  application         = aws_elasticbeanstalk_application.my_application.name
  solution_stack_name = "64bit Amazon Linux 2 v3.4.1 running Node.js 14" # Change to your preferred stack
  option_settings = [
    {
      namespace = "aws:autoscaling:launchconfiguration",
      option_name = "IamInstanceProfile",
      value = aws_iam_instance_profile.eb_ec2_profile.name
    },
    {
      namespace = "aws:autoscaling:launchconfiguration",
      option_name = "InstanceType",
      value = "t3.micro"
    },
    {
      namespace = "aws:elasticbeanstalk:environment",
      option_name = "EnvironmentType",
      value = "LoadBalanced"
    }
  ]
  depends_on = [aws_elasticbeanstalk_application.my_application]
}

