terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "app" {
  name        = "blue-green-app"
  description = "Blue/Green Deployment Application"
}

# Create Blue Environment
resource "aws_elastic_beanstalk_environment" "blue" {
  name                = "blue"
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = "64bit Amazon Linux 2 v5.8.0 running Node.js 18" # Adjust as needed

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = "aws-elasticbeanstalk-ec2-role"
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "InstanceType"
    value     = "t3.micro"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "EnvironmentType"
    value     = "LoadBalanced"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment:process:default"
    name      = "HealthCheckPath"
    value     = "/health"
  }
}

# Create Green Environment
resource "aws_elastic_beanstalk_environment" "green" {
  name                = "green"
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = "64bit Amazon Linux 2 v5.8.0 running Node.js 18" # Adjust as needed

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = "aws-elasticbeanstalk-ec2-role"
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "InstanceType"
    value     = "t3.micro"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "EnvironmentType"
    value     = "LoadBalanced"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment:process:default"
    name      = "HealthCheckPath"
    value     = "/health"
  }
}

# Create Route53 Hosted Zone
resource "aws_route53_zone" "app_zone" {
  name = "example.com" # Replace with your domain
}

# Create ALB for Blue Environment
resource "aws_lb" "blue_alb" {
  name               = "blue-alb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb.id]
  subnets            = aws_subnet.public[*].id
}

# Create ALB for Green Environment
resource "aws_lb" "green_alb" {
  name               = "green-alb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb.id]
  subnets            = aws_subnet.public[*].id
}

# Create Target Groups for Blue and Green Environments
resource "aws_lb_target_group" "blue_tg" {
  name     = "blue-tg"
  port     = 80
  protocol = "HTTP"
  vpc_id   = aws_vpc.main.id
}

resource "aws_lb_target_group" "green_tg" {
  name     = "green-tg"
  port     = 80
  protocol = "HTTP"
  vpc_id   = aws_vpc.main.id
}

# Attach ALBs to Blue and Green Environments
resource "aws_elastic_beanstalk_environment" "blue_alb_attachment" {
  environment_id = aws_elastic_beanstalk_environment.blue.id
  setting {
    namespace = "aws:elbv2:listener:443"
    name      = "DefaultProcess"
    value     = "blue-tg"
  }
}

resource "aws_elastic_beanstalk_environment" "green_alb_attachment" {
  environment_id = aws_elastic_beanstalk_environment.green.id
  setting {
    namespace = "aws:elbv2:listener:443"
    name      = "DefaultProcess"
    value     = "green-tg"
  }
}

# Create Route53 Record Set for Weighted Routing
resource "aws_route53_record" "weighted_record" {
  zone_id = aws_route53_zone.app_zone.zone_id
  name    = "app.example.com" # Replace with your subdomain
  type    = "A"

  alias {
    name                   = aws_lb.blue.dns_name
    zone_id                = aws_lb.blue.zone_id
    evaluate_target_health = true
  }

  set_identifier = "blue"

  weight = 100 # Initially all traffic to Blue
}

resource "aws_route53_record" "weighted_record_green" {
  zone_id = aws_route53_zone.app_zone.zone_id
