  alias {
    name                   = aws_lb.green.dns_name
    zone_id                = aws_lb.green.zone_id
    evaluate_target_health = true
  }

  set_identifier = "green"

  weight = 0 # Initially no traffic to Green
}

# Create Route53 Weighted Routing Policy
resource "aws_route53_health_check" "blue_health_check" {
  fqdn              = aws_lb.blue.dns_name
  type              = "HTTPS"
  resource_path     = "/health"
  fully_qualified_domain_name = aws_lb.blue.dns_name
  request_interval  = "30"
  failure_threshold = "3"
}

resource "aws_route53_health_check" "green_health_check" {
  fqdn              = aws_lb.green.dns_name
