terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Default region for AWS provider, will be overridden per environment
}

# --- US West Environment (us-west-2) ---
resource "aws_elastic_beanstalk_application" "us_west_app" {
  name        = "multi-region-app"
  description = "Multi-region Elastic Beanstalk Application"
}

resource "aws_elastic_beanstalk_environment" "us_west" {
  name                = "us_west"
  application         = aws_elastic_beanstalk_application.us_west_app.name
  solution_stack_name = "64bit Amazon Linux 2 v5.7.0 running Node.js 18"
  region             = "us-west-2"

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_instance_profile.name
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "InstanceType"
    value     = "t3.micro"
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "VPCId"
    value     = aws_vpc.us_west.id
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "Subnets"
    value     = join(",", aws_subnet.us_west.*.id)
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "ELBSubnets"
    value     = join(",", aws_subnet.us_west.*.id)
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "LoadBalancerType"
    value     = "application"
  }
}

# --- EU Central Environment (eu-central-1) ---
resource "aws_elastic_beanstalk_application" "eu_central_app" {
  name        = "multi-region-app"
  description = "Multi-region Elastic Beanstalk Application"
}

resource "aws_elastic_beanstalk_environment" "eu_central" {
  name                = "eu_central"
  application         = aws_elastic_beanstalk_application.eu_central_app.name
  solution_stack_name = "64bit Amazon Linux 2 v5.7.0 running Node.js 18"
  region             = "eu-central-1"

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_instance_profile.name
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "InstanceType"
    value     = "t3.micro"
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "VPCId"
    value     = aws_vpc.eu_central.id
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "Subnets"
    value     = join(",", aws_subnet.eu_central.*.id)
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "ELBSubnets"
    value     = join(",", aws_subnet.eu_central.*.id)
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "LoadBalancerType"
    value     = "application"
  }
}

# --- VPC and Subnets for US West ---
resource "aws_vpc" "us_west" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  region               = "us-west-2"
  tags = {
    Name = "us_west_vpc"
  }
}

resource "aws_subnet" "us_west" {
  count                   = 2
  vpc_id                  = aws_vpc.us_west.id
  cidr_block              = "10.0.${count.index}.0/24"
  availability_zone       = data.aws_availability_zones.us_west.names[count.index]
  map_public_ip_on_launch = true
  region                  = "us-west-2"
  tags = {
    Name = "us_west_subnet_${count.index}"
  }
}

# --- VPC and Subnets for EU Central ---
resource "aws_vpc" "eu_central" {
  cidr_block           = "10.1.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  region               = "eu-central-1"
  tags = {
    Name = "eu_central_vpc"
  }
}

resource "aws_subnet" "eu_central" {
  count                   = 2
  vpc_id                  = aws_vpc.eu_central.id
  cidr_block              = "10.1.${count.index}.0/24"
  availability_zone       = data.aws_availability_zones.eu_central.names[count.index]
  map_public_ip_on_launch = true
  region                  = "eu-central-1"
  tags = {
    Name = "eu_central_subnet_${count.index}"
  }
}

# --- IAM Instance Profile for Elastic Beanstalk ---
resource "aws_iam_role" "eb_role" {
  name = "elastic_beanstalk_role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_instance_profile" "eb_instance_profile" {
  name = "elastic_beanstalk_instance_profile"
  role = aws_iam_role.eb_role.name
}

# --- Route53 Resources for Geolocation Routing ---
resource "aws_route53_zone" "primary" {
  name = "example.com"
}

resource "aws_route53_record" "geolocation" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = aws_route53_zone.primary.name
  type    = "A"

  alias {
    name                   = aws_lb.us_west.dns_name
    zone_id                = aws_lb.us_west.zone_id
    evaluate_target_health = true
  }

  set_identifier = "us_west"

  failover_routing_policy {
    region = "us-west-2"
  }
}

resource "aws_route53_record" "geolocation_eu" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = aws_route53_zone.primary.name
  type    = "A"

  alias {
    name                   = aws_lb.eu_central.dns_name
    zone_id                = aws_lb.eu_central.zone_id
    evaluate_target_health = true
  }

  set_identifier = "eu_central"

  failover_routing_policy {
    region = "eu-central-1"
  }
}

resource "aws_route53_record" "geolocation_primary" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = aws_route53_zone.primary.name
  type    = "A"

  alias {
    name                   = aws_lb.us_west.dns_name
    zone_id                = aws_lb.us_west.zone_id
    evaluate_target_health = true
  }

  failover_routing_policy {
    primary = true
  }
}

# --- Application Load Balancers for Elastic Beanstalk ---
resource "aws_lb" "us_west" {
  name               = "us_west-alb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.eb_sg.id]
  subnets            = aws_subnet.us_west.*.id
  region             = "us-west-2"
}

resource "aws_lb" "eu_central" {
  name               = "eu_central-alb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.eb_sg.id]
  subnets            = aws_subnet.eu_central.*.id
  region             = "eu-central-1"
}

# --- Security Group for Elastic Beanstalk ---
resource "aws_security_group" "eb_sg" {
  name        = "elastic_beanstalk_sg"
  description = "Allow HTTP and HTTPS traffic"
  vpc_id      = aws_vpc.us_west.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "elastic_beanstalk_sg"
  }
}

# --- Data Sources for Availability Zones ---
data "aws_availability_zones" "us_west" {
  state = "available"
  region = "us-west-2"
}

data "aws_availability_zones" "eu_central" {
  state = "available"
  region = "eu-central-1"
}
