provider "aws" {
  region = "us-east-1"
}

# IAM Role for Elastic Beanstalk
resource "aws_iam_role" "eb_role" {
  name = "eb_role_for_blue_green"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "elasticbeanstalk.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Instance Profile
resource "aws_iam_instance_profile" "ec2_eb_profile1" {
  name = "ec2_eb_profile1"
  role = aws_iam_role.eb_role.name
}

# IAM Policy for RDS access
resource "aws_iam_role_policy" "rds_access" {
  name = "rds_access_policy"
  role = aws_iam_role.eb_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "rds:DescribeDBInstances",
          "rds:CreateDBSnapshot",
          "rds:DeleteDBSnapshot"
        ],
        Resource = "*"
      }
    ]
  })
}

# RDS Database Subnet Group
resource "aws_db_subnet_group" "my_db_subnet_group" {
  name       = "my_db_subnet_group"
  subnet_ids = ["subnet-12345678", "subnet-87654321"] # Replace with your subnet IDs

  tags = {
    Name = "my_db_subnet_group"
  }
}

# RDS Database
resource "aws_db_instance" "my_db" {
  identifier             = "my_db"
  engine                 = "postgres"
  engine_version         = "13.4"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  db_name                = "mydatabase"
  username               = "admin"
  password               = "your_secure_password" # Replace with a secure password
  parameter_group_name   = "default.postgres13"
  skip_final_snapshot    = true
  db_subnet_group_name   = aws_db_subnet_group.my_db_subnet_group.name
  vpc_security_group_ids = ["sg-12345678"] # Replace with your security group ID

  tags = {
    Name = "my_db"
  }
}

# Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "my_app" {
  name        = "my_blue_green_app"
  description = "Blue/Green Deployment Application"
}

# Elastic Beanstalk Application Version
resource "aws_elastic_beanstalk_application_version" "app_version" {
  name        = "app_version_1"
  application = aws_elastic_beanstalk_application.my_app.name
  source_bundle {
    s3_bucket = "your-s3-bucket-name" # Replace with your S3 bucket name
    s3_key    = "your-app-version.zip" # Replace with your application zip file path
  }
}

# Elastic Beanstalk Environment (Blue)
resource "aws_elastic_beanstalk_environment" "blue_env" {
  name                = "blue-environment"
  application         = aws_elastic_beanstalk_application.my_app.name
  application_version = aws_elastic_beanstalk_application_version.app_version.name
  environment_tier    = "WebServer"
  solution_stack_name = "64bit Amazon Linux 2 v3.4.1 running Node.js 14"

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.ec2_eb_profile1.name
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "InstanceType"
    value     = "t3.micro"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "EnvironmentType"
    value     = "BlueGreen"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment:process:default"
    name      = "HealthCheckPath"
    value     = "/"
  }

  setting {
    namespace = "aws:elasticbeanstalk:command"
    name      = "DeploymentPolicy"
    value     = "Rolling"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment:process:default"
    name      = "Port"
    value     = "8080"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "LoadBalancerType"
    value     = "application"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment:process:default"
    name      = "Protocol"
    value     = "HTTP"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "LoadBalancerListeners"
    value     = "[{"Protocol": "HTTP", "LoadBalancerPort": 80, "InstancePort": 8080, "SSLCertificateId": ""}]"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "LoadBalancerConnectionIdleTimeout"
    value     = "60"
  }

  setting {
    namespace = "aws:rds:dbinstance"
    name      = "DBInstanceIdentifier"
    value     = aws_db_instance.my_db.identifier
  }

  setting {
    namespace = "aws:rds:dbinstance"
    name      = "DBName"
    value     = aws_db_instance.my_db.db_name
  }

  setting {
    namespace = "aws:rds:dbinstance"
    name      = "DBUsername"
    value     = aws_db_instance.my_db.username
  }

  setting {
    namespace = "aws:rds:dbinstance"
    name      = "DBPassword"
    value     = aws_db_instance.my_db.password
  }

  setting {
    namespace = "aws:rds:dbinstance"
    name      = "DBPort"
    value     = aws_db_instance.my_db.port
  }

  setting {
    namespace = "aws:rds:dbinstance"
    name      = "DBInstanceClass"
    value     = aws_db_instance.my_db.instance_class
  }

  setting {
    namespace = "aws:rds:dbinstance"
    name      = "AllocatedStorage"
    value     = aws_db_instance.my_db.allocated_storage
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "OptionSettings"
    value     = jsonencode([
      {
        Namespace = "aws:autoscaling:launchconfiguration"
        OptionName = "EC2KeyName"
        OptionValue = "your-key-pair-name" # Replace with your EC2 key pair name
      },
      {
        Namespace = "aws:elasticbeanstalk:environment"
        OptionName = "LoadBalancerType"
        OptionValue = "application"
      }
    ])
  }
}

# Lambda Function for taking RDS Snapshot
resource "aws_lambda_function" "take_db_snapshot" {
  function_name = "take_db_snapshot"
  role          = aws_iam_role.eb_role.arn
  handler       = "index.handler"
  runtime       = "nodejs14.x"
  filename      = "data.zip" # Replace with your Lambda function zip file path

  environment {
    variables = {
      DB_IDENTIFIER = aws_db_instance.my_db.identifier
    }
  }
}

# CloudWatch Event Rule for triggering Lambda before deployment
resource "aws_cloudwatch_event_rule" "before_deployment" {
  name        = "before_deployment_trigger"
  description = "Trigger Lambda before deployment"

  event_pattern = jsonencode({
    source      = ["aws.elasticbeanstalk"]
    detail-type = ["Elastic Beanstalk deployment status change"]
    detail = {
      DeploymentId = ["*"]
      EnvironmentName = [aws_elasticbeanstalk_environment.blue_env.name]
      Status = ["InProgress"]
    }
  })
}

# CloudWatch Event Target for Lambda
resource "aws_cloudwatch_event_target" "trigger_lambda" {
  rule      = aws_cloudwatch_event_rule.before_deployment.name
  target_id = "InvokeLambda"
  arn       = aws_lambda_function.take_db_snapshot.arn
}

# Lambda Permission for CloudWatch Event
resource "aws_lambda_permission" "allow_cloudwatch" {
  statement_id  = "AllowExecutionFromCloudWatch"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.take_db_snapshot.function_name
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.before_deployment.arn
}

# Elastic Beanstalk Environment (Green)
resource "aws_elastic_beanstalk_environment" "green_env" {
