```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Create VPC
resource "aws_vpc" "eb_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "eb_vpc"
  }
}

# Create Internet Gateway
resource "aws_internet_gateway" "eb_igw" {
  vpc_id = aws_vpc.eb_vpc.id
  tags = {
    Name = "eb_igw"
  }
}

# Create Public Subnets
resource "aws_subnet" "eb_subnet_public_1" {
  vpc_id            = aws_vpc.eb_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "eb_subnet_public_1"
  }
}

resource "aws_subnet" "eb_subnet_public_2" {
  vpc_id            = aws_vpc.eb_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "eb_subnet_public_2"
  }
}

# Create Route Table
resource "aws_route_table" "eb_public_rt" {
  vpc_id = aws_vpc.eb_vpc.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.eb_igw.id
  }
  tags = {
    Name = "eb_public_rt"
  }
}

# Associate Route Table with Public Subnets
resource "aws_route_table_association" "eb_public_rt_association_1" {
  subnet_id      = aws_subnet.eb_subnet_public_1.id
  route_table_id = aws_route_table.eb_public_rt.id
}

resource "aws_route_table_association" "eb_public_rt_association_2" {
  subnet_id      = aws_subnet.eb_subnet_public_2.id
  route_table_id = aws_route_table.eb_public_rt.id
}

# Create Security Group for Elastic Beanstalk
resource "aws_security_group" "eb_env_sg" {
  name        = "eb_env_sg"
  description = "Allow inbound traffic for Elastic Beanstalk"
  vpc_id      = aws_vpc.eb_vpc.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "eb_env_sg"
  }
}

# Create Security Group for RDS
resource "aws_security_group" "eb_rds_sg" {
  name        = "eb_rds_sg"
  description = "Allow inbound traffic to RDS"
  vpc_id      = aws_vpc.eb_vpc.id

  ingress {
    from_port       = 5432
    to_port         = 5432
    protocol        = "tcp"
    security_groups = [aws_security_group.eb_env_sg.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "eb_rds_sg"
  }
}

# Create RDS Subnet Group
resource "aws_db_subnet_group" "eb_rds_subnet_group" {
  name       = "eb_rds_subnet_group"
  subnet_ids = [aws_subnet.eb_subnet_public_1.id, aws_subnet.eb_subnet_public_2.id]

  tags = {
    Name = "eb_rds_subnet_group"
  }
}

# Create RDS Instance
resource "aws_db_instance" "shared_rds" {
  allocated_storage    = 20
  engine               = "postgres"
  engine_version       = "13.4"
  instance_class       = "db.t3.micro"
  db_name              = "shared_db"
  username             = "admin"
  password             = "your_password_here" # Change this to a secure password
  parameter_group_name = "default.postgres13"
  skip_final_snapshot  = true
  vpc_security_group_ids = [aws_security_group.eb_rds_sg.id]
  db_subnet_group_name  = aws_db_subnet_group.eb_rds_subnet_group.name
  publicly_accessible   = false
  tags = {
    Name = "shared_rds"
  }
}

# Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "eb_app" {
  name        = "eb_app"
  description = "Elastic Beanstalk Application"
}

# Elastic Beanstalk Environment Configuration
resource "aws_elastic_beanstalk_environment" "eb_env_1" {
  name                = "eb_env_1"
  application         = aws_elastic_beanstalk_application.eb_app.name
  solution_stack_name = "64bit Amazon Linux 2 v3.4.1 running Node.js 14"
  option_setting {
    namespace = "aws:autoscaling:launchconfiguration"
    option_name = "IamInstanceProfile"
    value = "aws-elasticbeanstalk-ec2-role"
  }
  option_setting {
    namespace = "aws:autoscaling:launchconfiguration"
    option_name = "SecurityGroups"
    value = aws_security_group.eb_env_sg.id
  }
  option_setting {
    namespace = "aws:autoscaling:launchconfiguration"
    option_name = "InstanceType"
    value = "t3.micro"
  }
  option_setting {
    namespace = "aws:autoscaling:launchconfiguration"
    option_name = "EC2KeyName"
    value = "your_key_pair" # Replace with your key pair name
  }
  option_setting {
    namespace = "aws:autoscaling:launchconfiguration"
    option_name = "EC2Subnets"
    value = "${aws_subnet.eb_subnet_public_1.id},${aws_subnet.eb_subnet_public_2.id}"
  }
  option_setting {
    namespace = "aws:elasticbeanstalk:environment"
    option_name = "LoadBalancerType"
    value = "application"
  }
  option_setting {
    namespace = "aws:elasticbeanstalk:environment:process:default"
    option_name = "HealthCheckPath"
    value = "/"
  }
  option_setting {
    namespace = "aws:elasticbeanstalk:environment"
    option_name = "EnvironmentType"
    value = "LoadBalanced"
  }
  option_setting {
    namespace = "aws:rds:iam:db"
    option_name = "DBName"
    value = aws_db_instance.shared_rds.db_name
  }
  option_setting {
    namespace = "aws:rds:iam:db"
    option_name = "DBClusterIdentifier"
    value = aws_db_instance.shared_rds.id
  }
  option_setting {
    namespace = "aws:rds:iam:db"
    option_name = "DBPort"
    value = aws_db_instance.shared_rds.port
  }
  option_setting {
    namespace = "aws:rds:iam:db"
    option_name = "DBEngine"
    value = aws_db_instance.shared_rds.engine
  }
  option_setting {
    namespace = "aws:rds:iam:db"
    option_name = "DBUsername"
    value = aws_db_instance.shared_rds.username
  }
  option_setting {
    namespace = "aws:rds:iam:db"
    option_name = "DBInstanceIdentifier"
    value = aws_db_instance.shared_rds.id
  }
  depends_on = [aws_db_instance.shared_rds]
}

resource "aws_elastic_beanstalk_environment" "eb_env_2" {
  name                = "eb_env_2"
  application         = aws_elastic_beanstalk_application.eb_app.name
  solution_stack_name = "64bit Amazon Linux 2 v3.4.1 running Node.js 14"
