  alias {
    name                   = aws_elastic_beanstalk_environment.myenv_eu_west.cname
    zone_id                = aws_elastic_beanstalk_environment.myenv_eu_west.cname_zone_id
    evaluate_target_health = true
  }
}

# Route 53 Failover Record (Latency-based)
resource "aws_route53_record" "failover" {
  provider = aws.us_east
  zone_id   = aws_route53_zone.app_domain.zone_id
  name      = "app.example.com" # Replace with your subdomain
  type      = "A"

  alias {
    name                   = aws_route53_record.us_east_alias.name
    zone_id                = aws_route53_record.us_east_alias.zone_id
    evaluate_target_health = true
    failover_routing_policy {
      region = "us-east-1"
    }
  }
}

resource "aws_route53_record" "failover_eu" {
  provider = aws.eu_west
  zone_id   = aws_route53_zone.app_domain.zone_id
  name      = "app.example.com" # Replace with your subdomain
  type      = "A"

  alias {
    name                   = aws_route53_record.eu_west_alias.name
    zone_id                = aws_route53_record.eu_west_alias.zone_id
    evaluate_target_health = true
    failover_routing_policy {
      region = "eu-west-1"
    }
  }
}

# Route 53 Latency-based Routing
resource "aws_route53_record" "latency_routing" {
  provider = aws.us_east
  zone_id   = aws_route53_zone.app_domain.zone_id
  name      = "app.example.com" # Replace with your subdomain
  type      = "A"
  ttl       = 300

  set_identifier = "latency"

  failover_routing_policy {
    region = "us-east-1"
  }

  health_check_id = aws_route53_health_check.latency_health_check.id
}

resource "aws_route53_health_check" "latency_health_check" {
  provider = aws.us_east
  health_check_config {
    type                     = "HTTPS"
    resource_path            = "/health" # Adjust to your health check endpoint
    fully_qualified_domain_name = aws_elastic_beanstalk_environment.myenv_us_east.cname
    request_interval         = 30
    failure_threshold        = 3
  }
}

resource "aws_route53_record" "latency_routing_eu" {
  provider = aws.eu_west
  zone_id   = aws_route53_zone.app_domain.zone_id
  name      = "app.example.com" # Replace with your subdomain
  type      = "A"
  ttl       = 300

