# IAM Instance Profile
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "eb_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}

# IAM Policy for Elastic Beanstalk
resource "aws_iam_policy" "eb_ec2_policy" {
  name        = "eb_ec2_policy"
  description = "Policy for Elastic Beanstalk EC2 instances"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = [
          "elasticbeanstalk:*",
          "ec2:*",
          "s3:*",
          "cloudwatch:*",
          "logs:*",
          "autoscaling:*",
          "iam:PassRole"
        ]
        Resource = "*"
      }
    ]
  })
}

# Attach the policy to the IAM role
resource "aws_iam_role_policy_attachment" "eb_ec2_attach" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = aws_iam_policy.eb_ec2_policy.arn
}

# Elastic Beanstalk Application
resource "aws_elasticbeanstalk_application" "my_application" {
  name        = "my_application"
  description = "My Elastic Beanstalk Application"
}

# Elastic Beanstalk Application Version
resource "aws_elasticbeanstalk_application_version" "app_version" {
  name        = "app_version_1"
  application = aws_elasticbeanstalk_application.my_application.name
  source_bundle {
    application = aws_elasticbeanstalk_application.my_application.name
    s3_bucket  = "your-s3-bucket-name" # Replace with your S3 bucket name
    s3_key     = "your-application.zip" # Replace with your application file
  }
}

# Elastic Beanstalk Environment
resource "aws_elasticbeanstalk_environment" "webserver_env" {
  name                = "webserver-env"
  application         = aws_elasticbeanstalk_application.my_application.name
  application_version = aws_elasticbeanstalk_application_version.app_version.version
  instance_type       = "t3.micro"
  cname_prefix        = "webserver-app"

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "VPCId"
    value     = "vpc-xxxxxxxx" # Replace with your VPC ID
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "Subnets"
    value     = "subnet-xxxxxxxx,subnet-yyyyyyyy" # Replace with your subnet IDs
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "SecurityGroups"
    value     = "sg-xxxxxxxx" # Replace with your security group ID
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "EnvironmentType"
    value     = "LoadBalanced"
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "InstanceType"
    value     = "t3.micro"
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "EC2KeyName"
    value     = "your-key-pair-name" # Replace with your EC2 key pair name
  }
}

