provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create a new Elastic Beanstalk application
resource "aws_elastic_beanstalk_application" "go_app" {
  name        = "go-application"
  description = "Elastic Beanstalk application for Go"
}

# Create an Elastic Beanstalk application version
resource "aws_elastic_beanstalk_application_version" "go_app_version" {
  name        = "go-app-v1"
  application = aws_elastic_beanstalk_application.go_app.name
  description = "Version 1 of the Go application"

  origin      = "s3"
  bucket      = aws_s3_bucket.go_app_bucket.bucket
  version_label = "go-app-v1"

  depends_on = [aws_s3_bucket_object.go_app_zip]
}

# Create an S3 bucket for storing application files
resource "aws_s3_bucket" "go_app_bucket" {
  bucket = "go-app-${random_id.bucket_suffix.hex}"
}

# Generate a random suffix for the bucket name
resource "random_id" "bucket_suffix" {
  byte_length = 8
}

# Upload a sample Go application zip file to S3
resource "aws_s3_bucket_object" "go_app_zip" {
  bucket = aws_s3_bucket.go_app_bucket.bucket
  key    = "go-app.zip"
  source = "path/to/your/go-app.zip" # Replace with the path to your Go application zip file
  etag   = filemd5("path/to/your/go-app.zip") # Replace with the path to your Go application zip file
}

# Create an Elastic Beanstalk environment configuration
resource "aws_elastic_beanstalk_environment" "go_app_env" {
  name                = "go-app-env"
  application         = aws_elastic_beanstalk_application.go_app.name
  version_label       = aws_elastic_beanstalk_application_version.go_app_version.version_label
  solution_stack_name = "Go running on 64bit Amazon Linux 2 v5.8.0 running Go 1.19 (Managed Updates)" # Updated to latest Go version

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "InstanceType"
    value     = "t3.micro"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "EnvironmentType"
    value     = "LoadBalanced"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment:process:default"
    name      = "HealthCheckPath"
    value     = "/"
  }

  setting {
    namespace = "aws:elasticbeanstalk:container:go"
    name      = "GoVersion"
    value     = "1.19" # Ensure this matches the solution stack
  }

  setting {
    namespace = "aws:elasticbeanstalk:container:go"
    name      = "App"
    value     = "main" # Default main.go file
  }

  setting {
    namespace = "aws:elasticbeanstalk:container:go"
    name      = "Port"
    value     = "8080" # Default Go web server port
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "LoadBalancerType"
    value     = "application"
  }

  depends_on = [aws_elastic_beanstalk_application_version.go_app_version]
}

# Create an IAM instance profile for Elastic Beanstalk
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "go-app-ec2-profile"
  role = aws_iam_role.eb_ec2_role.name
}

# Create an IAM role for Elastic Beanstalk EC2 instances
resource "aws_iam_role" "eb_ec2_role" {
  name = "go-app-ec2-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

# Attach basic policies to the IAM role
resource "aws_iam_role_policy_attachment" "eb_ec2_AmazonEC2Role" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSElasticBeanstalkEnhancedHealth"
}

resource "aws_iam_role_policy_attachment" "eb_ec2_AmazonS3ReadOnly" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3ReadOnlyAccess"
}

# Output the Elastic Beanstalk environment URL
output "eb_environment_url" {
  value = aws_elastic_beanstalk_environment.go_app.cname
}

