resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "go-app-ec2-profile"
  role = aws_iam_role.eb_ec2_role.name
}

# Create an IAM role for Elastic Beanstalk EC2 instances
resource "aws_iam_role" "eb_ec2_role" {
  name = "go-app-ec2-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

# Attach basic policies to the IAM role
resource "aws_iam_role_policy_attachment" "eb_ec2_AmazonEC2Role" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSElasticBeanstalkEnhancedHealth"
}

resource "aws_iam_role_policy_attachment" "eb_ec2_AmazonS3ReadOnly" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3ReadOnlyAccess"
}

# Output the Elastic Beanstalk environment URL
output "eb_environment_url" {
  value = aws_elastic_beanstalk_environment.go_app.cname
}
