  resource_group_name     = azurerm_resource_group.web_app_rg.name
  location                = azurerm_resource_group.web_app_rg.location
  size                    = "Standard_B1s"
  admin_username          = "adminuser"
  admin_ssh_key           = file("~/.ssh/id_rsa.pub")
  disable_password_authentication = true

  os_disk {
    caching              = "ReadWrite"
    storage_account_type = "Standard_LRS"
  }

  source_image_reference {
    publisher = "Canonical"
    offer     = "UbuntuServer"
    sku       = "18.04-LTS"
    version   = "latest"
  }

  network_interface_ids = [azurerm_network_interface.web_app_nic[count.index].id]

  custom_data = base64encode(<<-EOF
              #!/bin/bash
              apt-get update -y
              apt-get install -y nginx
              systemctl start nginx
              systemctl enable nginx
              EOF
  )
}

resource "azurerm_availability_set" "web_app_avset" {
  name                = "web-app-avset"
  location            = azurerm_resource_group.web_app_rg.location
  resource_group_name = azurerm_resource_group.web_app_rg.name
  managed             = true
  platform_fault_domain_count = 2
  platform_update_domain_count = 2
}

resource "azurerm_availability_set_instance" "web_app_avset_instance" {
  count              = 2
  id                 = azurerm_linux_virtual_machine.web_app_vm[count.index].id
  availability_set_id = azurerm_availability_set.web_app_avset.id
}

resource "azurerm_lb" "web_app_lb" {
  name                = "web-app-lb"
  location            = azurerm_resource_group.web_app_rg.location
  resource_group_name = azurerm_resource_group.web_app_rg.name
  frontend_ip_configuration {
    name                 = "PublicIPAddress"
    public_ip_address_id = azurerm_public_ip.web_app_pip.id
  }
}

resource "azurerm_lb_backend_address_pool" "web_app_bap" {
  loadbalancer_id = azurerm_lb.web_app_lb.id
  name            = "BackEndAddressPool"
}

resource "azurerm_network_interface_backend_address_pool_association" "web_app_nic_bap" {
  count                   = 2
  network_interface_id    = azurerm_network_interface.web_app_nic[count.index].id
  ip_configuration_name   = "internal"
  backend_address_pool_id = azurerm_lb_backend_address_pool.web_app_bap.id
}

resource "azurerm_lb_probe" "web_app_probe" {
  loadbalancer_id     = azurerm_lb.web_app_lb.id
  name                = "HTTP-Probe"
  port                = 80
  protocol            = "Http"
  path                = "/"
  interval_in_seconds = 5
  number_of_probes    = 2
}

resource "azurerm_lb_rule" "web_app_rule" {
  loadbalancer_id             = azurerm_lb.web_app_lb.id
  name                        = "HTTP-Rule"
  protocol                    = "Tcp"
  frontend_port               = 80
  backend_port                = 80
  frontend_ip_configuration_name = "PublicIPAddress"
  backend_address_pool_ids    = [azurerm_lb_backend_address_pool.web_app_bap.id]
  probe_id                    = azurerm_lb_probe.web_app_probe.id
}

# Google Cloud Configuration
provider "google" {
  project = "your-project-id" # Replace with your GCP project ID
  region  = "us-central1"
}

resource "google_compute_network" "web_app_network" {
  name                    = "web-app-network"
  auto_create_subnetworks = false
}

resource "google_compute_subnetwork" "web_app_subnetwork" {
  count         = 2
  name          = "web-app-subnetwork-${count.index}"
  ip_cidr_range = "10.1.${count.index}.0/24"
  region        = "us-central1"
  network       = google_compute_network.web_app_network.id
}

resource "google_compute_firewall" "web_app_firewall" {
  name    = "web-app-firewall"
  network = google_compute_network.web_app_network.name

  allow {
    protocol = "tcp"
    ports    = ["80", "443"]
  }

  source_ranges = ["0.0.0.0/0"]
  target_tags   = ["web-app"]
}

resource "google_compute_instance_template" "web_app_template" {
  name        = "web-app-template"
  machine_type = "f1-micro"
  region      = "us-central1"

  disk {
    source_image = "projects/ubuntu-os-cloud/global/images/family/ubuntu-2004-lts"
    auto_delete  = true
    boot         = true
  }

  network_interface {
    network    = google_compute_network.web_app_network.id
    subnetwork = google_compute_subnetwork.web_app_subnetwork[0].id
    access_config {
      // Ephemeral public IP
    }
  }

  metadata_startup_script = <<-EOT
              #!/bin/bash
              sudo apt-get update
              sudo apt-get install -y nginx
              sudo systemctl start nginx
              sudo systemctl enable nginx
              EOT

  tags = ["web-app"]
}

resource "google_compute_region_instance_group_manager" "web_app_igm" {
  name               = "web-app-igm"
  base_instance_name = "web-app-instance"
  version {
    instance_template = google_compute_instance_template.web_app_template.self_link
  }
  region             = "us-central1"
  target_size        = 2
  named_ports {
    name = "http"
    port = 80
  }
}

resource "google_compute_region_autoscaler" "web_app_autoscaler" {
  name   = "web-app-autoscaler"
  region = "us-central1"
  target = google_compute_region_instance_group_manager.web_app_igm.self_link

  autoscaling_policy {
    max_replicas    = 4
    min_replicas    = 2
    cooldown_period = 100
    cpu_utilization {
      target = 0.6
    }
  }
}

resource "google_compute_global_forwarding_rule" "web_app_forwarding_rule" {
  name        = "web-app-forwarding-rule"
  target      = google_compute_region_instance_group_manager.web_app_igm.self_link
  port_range  = "80-80"
  ip_address  = google_compute_global_address.web_app_address.address
}

resource "google_compute_global_address" "web_app_address" {
  name = "web-app-address"
}
