resource "aws_codebuild_project" "example_project" {
  name          = "example-codebuild-project"
  description   = "Example CodeBuild project with GitHub source"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:6.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "ENV_VAR_1"
      value = "value1"
    }

    environment_variable {
      name  = "ENV_VAR_2"
      value = "value2"
    }
  }

  source {
    type      = "GITHUB"
    location  = "https://github.com/your-username/your-repo.git"
    git_clone_depth = 1
    buildspec = <<-EOT
      version: 0.2
      phases:
        install:
          runtime-versions:
            python: 3.8
          commands:
            - echo "Installing dependencies..."
            - pip install -r requirements.txt
        pre_build:
          commands:
            - echo "Pre-build phase..."
        build:
          commands:
            - echo "Building the application..."
            - echo "Build completed on `date`"
      artifacts:
        files: '**/*'
      cache:
        paths: [
          '/root/.cache/pip',
          '/usr/local/lib/python3.8/site-packages/**/*'
        ]
    EOT
  }

  cache {
    type     = "LOCAL"
    modes    = ["LOCAL_DOCKER_LAYER_CACHE", "LOCAL_SOURCE_CACHE"]
    paths    = ["/root/.cache", "/usr/local/lib/python3.8/site-packages"]
  }
}

