        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for CodeBuild
resource "aws_iam_policy" "codebuild_policy" {
  name        = "codebuild_example_policy"
  description = "Policy for CodeBuild access"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ],
        Resource = "*"
      },
      {
        Effect = "Allow",
        Action = [
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:PutObject",
          "s3:PutObjectAcl"
        ],
        Resource = [
          "arn:aws:s3:::my-codebuild-source-bucket/*",
          "arn:aws:s3:::my-codebuild-build-output-bucket/*"
        ]
      },
      {
        Effect = "Allow",
        Action = [
          "codecommit:GitPullRef",
          "codecommit:GitPushRef",
          "codecommit:GetBranch",
          "codecommit:GetCommit",
          "codecommit:ListBranches"
        ],
        Resource = "*"
      }
    ]
  })
}

# Attach IAM Policy to Role
resource "aws_iam_role_policy_attachment" "codebuild_attach" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = aws_iam_policy.codebuild_policy.arn
}

# S3 Bucket for Source and Build Output (Example)
resource "aws_s3_bucket" "source_bucket" {
  bucket = "my-codebuild-source-bucket"
}

resource "aws_s3_bucket" "build_output_bucket" {
  bucket = "my-codebuild-build-output-bucket"
}

# CodeBuild Project
resource "aws_codebuild_project" "example_project" {
  name          = "example-codebuild-project"
  description   = "Example CodeBuild project with GitHub source"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:6.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "SOURCE_REPO"
      value = "https://github.com/example/repo.git"
    }
  }

  source {
    type      = "GITHUB"
    location  = "https://github.com/example/repo.git"
    git_clone_depth = 1

    git_submodules_config {
      fetch_submodules = true
    }
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/example-codebuild-project"
      stream_name = "build-log-stream"
    }
  }

  cache {
    type     = "LOCAL"
    modes    = ["LOCAL_DOCKER_LAYER_CACHE", "LOCAL_SOURCE_CACHE"]
  }
}

