        Action   = [
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:PutObject"
        ]
        Resource = [
          "arn:aws:s3:::my-build-input-bucket/*",
          "arn:aws:s3:::my-build-output-bucket/*"
        ]
      },
      {
        Effect   = "Allow"
        Action   = [
          "codebuild:BatchGetBuilds",
          "codebuild:StartBuild"
        ]
        Resource = "*"
      }
    ]
  })
}

# Attach policy to the IAM role
resource "aws_iam_role_policy_attachment" "codebuild_policy_attach" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = aws_iam_policy.codebuild_policy.arn
}

# S3 Buckets for build input/output (example)
resource "aws_s3_bucket" "input_bucket" {
  bucket = "my-build-input-bucket"
}

resource "aws_s3_bucket" "output_bucket" {
  bucket = "my-build-output-bucket"
}

# CodeBuild Project
resource "aws_codebuild_project" "example_project" {
  name          = "example-codebuild-project"
  description   = "Example CodeBuild project with batch configuration"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "S3"
    location = aws_s3_bucket.output_bucket.bucket
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:6.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "SERVICE_ROLE"
    privileged_mode             = true

    environment_variable {
      name  = "INPUT_BUCKET"
      value = aws_s3_bucket.input_bucket.bucket
    }

    environment_variable {
      name  = "OUTPUT_BUCKET"
      value = aws_s3_bucket.output_bucket.bucket
    }
  }

  source {
    type      = "S3"
    location  = aws_s3_bucket.input_bucket.bucket
    git_clone_depth = 0
  }

  cache {
    type     = "LOCAL"
    modes    = ["LOCAL_DOCKER_LAYER_CACHE", "LOCAL_SOURCE_CACHE"]
  }

  batch {
    build_spec = <<-EOT
      version: 0.2
      phases:
        install:
          runtime-versions:
            python: 3.9
          commands:
            - echo "Installing dependencies..."
            - pip install --upgrade pip
            - pip install -r requirements.txt
        pre_build:
          commands:
            - echo "Pre-build phase..."
        build:
          commands:
            - echo "Building the application..."
            - python -m pytest tests/
        post_build:
          commands:
            - echo "Post-build phase..."
            - echo "Build completed on `date`"
      artifacts:
        files: '**/*'
      cache:
        paths:
          - '/root/.cache/pip/**/*'
    EOT
  }
}

