  name        = "PizzaOrderBot"
  description = "A Lex bot for ordering pizza with follow-up questions"
  dataPrivacy {
    child_directed        = false
    enabling_parental_control = false
    governing_law         = "US"
    privacy_policy_url    = "https://example.com/privacy-policy"
  }
  role_arn = aws_iam_role.lex_bot_role.arn
  idlesessionttlseconds = 300
  locale_id             = "en_US"
}

resource "aws_lex_intent" "order_pizza_intent" {
  bot_id      = aws_lex_bot.pizza_order_bot.id
  name        = "OrderPizzaIntent"
  description = "Intent for ordering pizza"
  sample_utterances = [
    "order a pizza",
    "I want to order a pizza",
    "Can I get a pizza?",
    "Pizza please"
  ]
}

resource "aws_lex_intent" "followup_question_intent" {
  bot_id      = aws_lex_bot.pizza_order_bot.id
  name        = "FollowupQuestionIntent"
  description = "Follow-up questions about pizza order"
  sample_utterances = [
    "What size?",
    "Do you have vegetarian options?",
    "What toppings do you offer?",
    "Can I add extra cheese?"
  ]
}

resource "aws_lex_slot_type" "pizza_size_slot" {
  name        = "PizzaSize"
  description = "Slot type for pizza size"
  value_elimination_mode = "None"
}

resource "aws_lex_slot_type" "toppings_slot" {
  name        = "Toppings"
  description = "Slot type for pizza toppings"
  value_elimination_mode = "None"
}

resource "aws_lex_slot_type" "vegetarian_slot" {
  name        = "Vegetarian"
  description = "Slot type for vegetarian preference"
  value_elimination_mode = "None"
  value_elimination_rules = [
    {
      regex_pattern = "yes|y|yeah|sure"
      value          = "Yes"
    },
    {
      regex_pattern = "no|n|nope"
      value          = "No"
    }
  ]
}

