resource "aws_lex_slot_type" "pizza_vegetarian_slot" {
  name        = "PizzaVegetarian"
  description = "Slot type for vegetarian preference"
  value_elimination_mode = "None"
  value_elimination_rules = [
    {
      regex_pattern = "yes|y|yeah|sure"
      value          = "Yes"
