extracted_code:
terraform {
  required_version = ">= 1.0.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_lex_bot" "pizza_order_bot" {
  name        = "PizzaOrderBot"
  description = "A Lex bot for ordering pizzas"
  role_arn    = aws_iam_role.lex_bot_role.arn
  data_privacy {
    child_directed = false
  }
  idle_session_ttl_in_seconds = 300 # 5 minutes
}

resource "aws_lex_bot_version" "pizza_order_bot_version" {
  bot_id      = aws_lex_bot.pizza_order_bot.id
  bot_version = "1.0"
}

resource "aws_lex_intent" "greeting_intent" {
  name        = "GreetingIntent"
  bot_id      = aws_lex_bot.pizza_order_bot.id
  sample_utterances = ["hello", "hi", "hey", "greetings"]
  description = "User greets the bot"
}

resource "aws_lex_intent" "order_pizza_intent" {
  name        = "OrderPizzaIntent"
  bot_id      = aws_lex_bot.pizza_order_bot.id
  sample_utterances = [
    "order a pizza",
    "I want to order a pizza",
    "pizza please",
    "I'd like to order a pizza"
  ]
  description = "User wants to order a pizza"
}

resource "aws_lex_intent" "pizza_type_intent" {
  name        = "PizzaTypeIntent"
  bot_id      = aws_lex_bot.pizza_order_bot.id
  sample_utterances = [
    "cheese pizza",
    "pepperoni pizza",
    "vegetarian pizza",
    "I want {pizza_type}"
  ]
  description = "User specifies the type of pizza"
  input_slot {
    name     = "pizza_type"
    type     = "AMAZON.SearchQuery"
  }
}

resource "aws_lex_intent" "size_intent" {
  name        = "SizeIntent"
  bot_id      = aws_lex_bot.pizza_order_bot.id
  sample_utterances = [
    "large pizza",
    "medium pizza",
    "small pizza",
    "I want a {size} pizza"
  ]
  description = "User specifies the size of the pizza"
  input_slot {
    name     = "size"
    type     = "AMAZON.SearchQuery"
  }
}

resource "aws_lex_intent" "confirm_order_intent" {
  name        = "ConfirmOrderIntent"
  bot_id      = aws_lex_bot.pizza_order_bot.id
  sample_utterances = [
    "confirm order",
    "yes, proceed with the order",
    "go ahead and order it"
  ]
  description = "User confirms the order"
}

resource "aws_lex_intent" "cancel_intent" {
  name        = "CancelIntent"
  bot_id      = aws_lex_bot.pizza_order_bot.id
  sample_utterances = [
    "cancel",
    "no, cancel",
    "nevermind"
  ]
  description = "User cancels the order"
}

