terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_lex_bot" "trip_booking_bot" {
  name               = "TripBookingBot"
  description        = "Lex bot for booking trips with user input"
  idempotency_settings {
    enable_idempotency = true
  }
  role_arn           = aws_iam_role.lex_bot_role.arn
  data_privacy {
    child_directed    = false
  }
  lifecycle {
    ignore_changes = [last_updated_date]
  }
}

resource "aws_lex_intent" "greeting_intent" {
  name               = "GreetingIntent"
  sample_utterances  = ["hello", "hi", "hey", "greetings"]
  parent_intent_signature {
    name = aws_lex_bot.trip_booking_bot.name
  }
  sample_utterances = ["hello", "hi", "hey", "greetings"]
  input_dialog_mode = "MULTI_VALUE"
}

resource "aws_lex_intent" "booking_intent" {
  name               = "BookingIntent"
  sample_utterances  = [
    "book a trip to {destination}",
    "I want to book a trip to {destination} on {date}",
    "Book me a flight to {destination} departing {date}",
    "I'd like to book a trip to {destination} for {date}"
  ]
  parent_intent_signature {
    name = aws_lex_bot.trip_booking_bot.name
  }
  input_dialog_mode = "MULTI_VALUE"
  slots {
    destination {
      name = "destination"
      slot_type = aws_lex_slot_type.destination_slot_type.name
      value_eligibility = "VALUE_PROVIDED"
    }
    departure_date {
      name = "departure_date"
      slot_type = aws_lex_slot_type.date_slot_type.name
      value_eligibility = "VALUE_PROVIDED"
    }
    return_date {
      name = "return_date"
      slot_type = aws_lex_slot_type.date_slot_type.name
      value_eligibility = "VALUE_PROVIDED"
    }
    number_of_passengers {
      name = "number_of_passengers"
      slot_type = aws_lex_slot_type.number_slot_type.name
      value_eligibility = "VALUE_PROVIDED"
    }
    travel_class {
      name = "travel_class"
      slot_type = aws_lex_slot_type.travel_class_slot_type.name
      value_eligibility = "VALUE_PROVIDED"
    }
  }
  fulfillment_activity {
    type = "ReturnIntent"
  }
}

