provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_lex_bot" "trip_booking_bot" {
  name               = "TripBookingBot"
  description        = "Lex bot for booking trips with user input"
  idempotency_settings {
    enable_idempotency = true
  }
  role_arn           = aws_iam_role.lex_bot_role.arn
  data_privacy {
    child_directed    = false
  }
  lifecycle {
    ignore_changes = [last_updated_date]
  }
}

resource "aws_lex_intent" "greeting_intent" {
  name               = "GreetingIntent"
  sample_utterances  = ["hello", "hi", "hey", "greetings"]
  parent_intent_signature {
    name = aws_lex_bot.trip_booking_bot.name
  }
  sample_utterances = ["hello", "hi", "hey", "greetings"]
  input_dialog_mode = "MULTI_VALUE"
}

resource "aws_lex_intent" "booking_intent" {
  name               = "BookingIntent"
  sample_utterances  = [
    "book a trip to {destination}",
    "I want to book a trip to {destination} on {date}",
    "Book me a flight to {destination} departing {date}",
    "I'd like to book a trip to {destination} for {date}"
  ]
  parent_intent_signature {
    name = aws_lex_bot.trip_booking_bot.name
  }
  input_dialog_mode = "MULTI_VALUE"
  slots {
    destination {
      name = "destination"
      slot_type = aws_lex_slot_type.destination_slot_type.name
      value_eligibility = "VALUE_PROVIDED"
    }
    departure_date {
      name = "departure_date"
      slot_type = aws_lex_slot_type.date_slot_type.name
      value_eligibility = "VALUE_PROVIDED"
    }
    return_date {
      name = "return_date"
      slot_type = aws_lex_slot_type.date_slot_type.name
      value_eligibility = "VALUE_PROVIDED"
    }
    number_of_passengers {
      name = "number_of_passengers"
      slot_type = aws_lex_slot_type.number_slot_type.name
      value_eligibility = "VALUE_PROVIDED"
    }
    travel_class {
      name = "travel_class"
      slot_type = aws_lex_slot_type.travel_class_slot_type.name
      value_eligibility = "VALUE_PROVIDED"
    }
  }
  fulfillment_activity {
    type = "ReturnIntent"
  }
}

resource "aws_lex_slot_type" "destination_slot_type" {
  name     = "Destination"
  value_eligibility = "VALUE_PROVIDED"
  enum_value {
    value = "New York"
  }
  enum_value {
    value = "London"
  }
  enum_value {
    value = "Paris"
  }
  enum_value {
    value = "Tokyo"
  }
  enum_value {
    value = "Sydney"
  }
  enum_value {
    value = "Dubai"
  }
}

resource "aws_lex_slot_type" "date_slot_type" {
  name     = "Date"
  value_eligibility = "VALUE_PROVIDED"
  enum_value {
    value = "2023-12-25"
  }
  enum_value {
    value = "2024-01-01"
  }
  enum_value {
    value = "2024-07-04"
  }
}

resource "aws_lex_slot_type" "number_slot_type" {
  name     = "NumberOfPassengers"
  value_eligibility = "VALUE_PROVIDED"
  enum_value {
    value = "1"
  }
  enum_value {
    value = "2"
  }
  enum_value {
    value = "3"
  }
  enum_value {
    value = "4"
  }
}

resource "aws_lex_slot_type" "travel_class_slot_type" {
  name     = "TravelClass"
  value_eligibility = "VALUE_PROVIDED"
  enum_value {
    value = "Economy"
  }
  enum_value {
    value = "Business"
  }
  enum_value {
    value = "First"
  }
}

resource "aws_lex_slot_type" "confirmation_slot_type" {
  name     = "Confirmation"
  value_eligibility = "VALUE_PROVIDED"
  enum_value {
    value = "Yes"
  }
  enum_value {
    value = "No"
  }
}

resource "aws_lex_intent" "confirmation_intent" {
  name               = "ConfirmationIntent"
  sample_utterances  = ["yes", "confirm", "okay", "proceed", "no", "cancel"]
  parent_intent_signature {
    name = aws_lex_bot.trip_booking_bot.name
  }
  slots {
    confirmation {
