# Define a simple fulfillment lambda function for demonstration purposes
resource "aws_cloudwatch_log_group" "lex_lambda_log_group" {
  name = "/aws/lambda/KidsPizzaOrderBotFulfillment"
}

resource "aws_iam_role" "lex_lambda_role" {
  name = "KidsPizzaOrderBotLambdaRole"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lex_lambda_basic_execution" {
  role       = aws_iam_role.lex_lambda_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

resource "aws_lambda_function" "lex_fulfillment" {
  function_name = "KidsPizzaOrderBotFulfillment"
  runtime       = "nodejs18.x"
  handler       = "index.handler"
  role          = aws_iam_role.lex_lambda_role.arn
  filename      = "data/lambda_fulfillment_function.zip" # You need to upload your fulfillment code here
  environment {
    variables = {
      LOG_GROUP_NAME = aws_cloudwatch_log_group.lex_lambda_log_group.name
    }
  }
}

resource "aws_lex_bot_alias" "kids_pizza_order_bot_alias" {
  name          = "KidsPizzaOrderBotAlias"
  bot_name      = aws_lex_bot.kids_pizza_order_bot.name
  description   = "Alias for the Kids Pizza Order Bot"
  enabled       = true
  bot_version   = aws_lex_bot.kids_pizza_order_bot.version
  lambda_function_arn = aws_lambda_function.lex_fulfillment.arn
}
