provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create IAM role for Lambda
resource "aws_iam_role" "lex_lambda_role" {
  name = "lex-pizza-order-lambda-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# Attach basic Lambda execution policy
resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lex_lambda_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# Create Lambda function for pizza ordering
resource "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "lambda_function.zip"
  source {
    content  = <<-EOT
      def lambda_handler(event, context):
          intent_name = event.get('currentIntent', {}).get('name')
          slots = event.get('currentIntent', {}).get('slots', {})

          if intent_name == 'OrderPizzaIntent':
              size = slots.get('Size', '').lower()
              toppings = slots.get('Toppings', '').lower().split(',')
              crust = slots.get('Crust', '').lower()

              response = {
                  "sessionAttributes": {
                      "selectedSize": size,
                      "selectedToppings": toppings,
                      "selectedCrust": crust
                  },
                  "dialogAction": {
                      "type": "Close",
                      "fulfillmentState": "Fulfilled",
                      "message": {
                          "contentType": "PlainText",
                          "content": f"Thank you! Your {size} pizza with {', '.join(toppings)} toppings and {crust} crust is on the way!"
                      }
                  }
              }
              return response
          else:
              return {
                  "sessionAttributes": {},
                  "dialogAction": {
                      "type": "Close",
                      "fulfillmentState": "Failed",
                      "message": {
                          "contentType": "PlainText",
                          "content": "Sorry, I didn't understand that."
                      }
                  }
              }
      EOT
    filename = "lambda_function.py"
  }
}

resource "aws_lambda_function" "pizza_order_lambda" {
  filename      = archive_file.lambda_zip.output_path
  function_name = "pizza-order-lambda"
  role          = aws_iam_role.lex_lambda_role.arn
  handler       = "lambda_function.lambda_handler"
  runtime       = "python3.9"
  timeout       = 10
}

# Create IAM permission for Lex to invoke Lambda
resource "aws_lambda_permission" "lex_invoke_lambda" {
  statement_id  = "AllowExecutionFromLex"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.pizza_order_lambda.function_name
  principal     = "lex.amazonaws.com"
  source_arn    = aws_lex_bot.pizza_bot.arn
}

# Create Lex bot for pizza ordering
resource "aws_lex_bot" "pizza_bot" {
  name        = "PizzaOrderBot"
  description = "Bot for ordering pizzas"
  role_arn    = aws_lex_bot_role.arn
  dataPrivacy {
    child_directed = false
  }
  depends_on = [aws_lex_bot_role]
}

# Create IAM role for Lex bot
resource "aws_iam_role" "lex_bot_role" {
  name = "lex-pizza-bot-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = [
            "lex.amazonaws.com"
          ]
        }
      }
    ]
  })
}

# Attach Lex bot execution policy
resource "aws_iam_role_policy_attachment" "lex_bot_execution" {
  role       = aws_iam_role.lex_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLexBotRole"
}

# Create Lex bot alias
resource "aws_lex_bot_alias" "pizza_bot_alias" {
  name         = "PizzaOrderBotAlias"
  bot_name     = aws_lex_bot.pizza_bot.name
  description  = "Alias for PizzaOrderBot"
  bot_version  = aws_lex_bot_version.pizza_bot_version.version
  enabled      = true
  depends_on   = [aws_lex_bot_version.pizza_bot_version]
}

# Create Lex bot version
resource "aws_lex_bot_version" "pizza_bot_version" {
  bot_name     = aws_lex_bot.pizza_bot.name
  bot_version  = "1.0"
  depends_on   = [aws_lex_bot.pizza_bot]
}

# Create Lex intent for ordering pizza
resource "aws_lex_intent" "order_pizza" {
  name        = "OrderPizzaIntent"
  sample_utterances = [
    "I want a {Size} pizza with {Toppings}",
    "Order a {Size} pizza with {Toppings} and {Crust}",
    "Can I get a {Size} pizza with {Toppings}?"
  ]
  parent_intent_signature = "OrderPizzaIntent"
  slots {
    name     = "Size"
    type     = "AMAZON.SearchQuery"
    value_elimination_strategy = "ELIMINATE_ALL"
  }
  slots {
    name     = "Toppings"
    type     = "AMAZON.SearchQuery"
    value_elimination_strategy = "ELIMINATE_ALL"
  }
  slots {
    name     = "Crust"
    type     = "AMAZON.SearchQuery"
    value_elimination_strategy = "ELIMINATE_ALL"
  }
  fulfillment_activity {
    type = "LambdaFunction"
    lambda_function_arn = aws_lambda_function.pizza_order_lambda.arn
  }
}

