  region = "us-east-1" # Change to your preferred region
}

resource "aws_s3_bucket" "firehose_bucket" {
  bucket = "firehose-delivery-stream-bucket-${random_id.bucket_suffix.hex}" # Unique bucket name
}

resource "random_id" "bucket_suffix" {
  byte_length = 4
}

resource "aws_iam_role" "firehose_role" {
  name = "firehose_elasticsearch_destination_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "firehose_s3_access" {
  role       = aws_iam_role.firehose_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3FullAccess"
}

resource "aws_iam_role_policy_attachment" "firehose_es_access" {
  role       = aws_iam_role.firehose_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonOpenSearchServiceFullAccess"
}

resource "aws_kinesis_firehose_delivery_stream" "elasticsearch_destination" {
  name        = "elasticsearch-destination-stream"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.firehose_bucket.arn
    prefix     = "firehose-data/"
    buffering_hints {
      size    = 5
      interval = 300
    }
    error_output_prefix = "firehose-errors/"
  }

  tags = {
    Name = "FirehoseToElasticsearch"
  }
}

resource "aws_kinesis_firehose_delivery_stream" "elasticsearch_destination_stream" {
  name        = "elasticsearch-destination-stream"
  destination = "elasticsearch"

  elasticsearch_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    domain_arn = "arn:aws:es:us-east-1:123456789012:domain/your-elasticsearch-domain" # Replace with your Elasticsearch domain ARN
    index_name = "firehose-data"
    type_name  = "doc"
    retry_options {
      interval_in_seconds = 30
    }
    buffer_hints {
      size_in_mb   = 5
      interval_in_seconds = 300
    }
    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = "/aws/kinesisfirehose/${aws_kinesis_firehose_delivery_stream.elasticsearch_destination_stream.name}"
      log_stream_name = "delivery"
    }
    s3_configuration {
      role_arn   = aws_iam_role.firehose_role.arn
      bucket_arn = aws_s3_bucket.firehose_bucket.arn
      prefix     = "firehose-data/"
      buffering_hints {
        size    = 5
        interval = 300
      }
      error_output_prefix = "firehose-errors/"
    }
  }
}

resource "aws_elasticsearch_domain" "example" {
  domain_name           = "firehose-elasticsearch-domain"
  elasticsearch_version = "8.11" # Use a supported version

  cluster_config {
    instance_type = "t3.small.elasticsearch"
    instance_count = 1
  }

  ebs_options {
    ebs_enabled = true
    volume_size = 10
    volume_type = "gp2"
  }

  snapshot_options {
    automated_snapshot_start_hour = 23
  }

  vpc_options {
    security_group_ids = [aws_security_group.elasticsearch_sg.id]
    subnet_ids         = ["subnet-12345678", "subnet-87654321"] # Replace with your subnet IDs
  }

  access_policies = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          AWS = aws_iam_role.firehose_role.arn
        }
        Action = [
          "es:ESHttpPost",
          "es:ESHttpPut"
        ]
        Resource = "arn:aws:es:${var.region}:${data.aws_caller_identity.current.account_id}:domain/${aws_elasticsearch_domain.example.domain_name}/*"
      }
    ]
  })
}

resource "aws_security_group" "elasticsearch_sg" {
  name        = "elasticsearch-sg"
  description = "Allow traffic to Elasticsearch domain"

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

data "aws_caller_identity" "current" {}

