terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_kinesis_firehose_delivery_stream" "splunk_delivery_stream" {
  name        = "splunk-delivery-stream"
  destination = "splunk"

  splunk_configuration {
    hec_token = var.splunk_hec_token          # Replace with your Splunk HEC token
    hec_endpoint = var.splunk_hec_endpoint    # Replace with your Splunk HEC endpoint (e.g., "https://<your-splunk-instance>:8088")
    hec_endpoint_type = "Raw"                # or "HttpApi" if using Splunk Cloud HTTP Event Collector
    index_name = var.splunk_index_name       # Replace with your Splunk index name
    index_rotation_period = "OneDay"        # or "OneWeek", "OneMonth"
    retry_options {
      duration = 300 # Retry duration in seconds (5 minutes)
    }
    buffering_hints {
      size_in_mb   = 5
      interval_in_seconds = 300
    }
    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = "/aws/kinesisfirehose/${aws_kinesis_firehose_delivery_stream.splunk_delivery_stream.name}"
      log_stream_name = "SplunkDeliveryStreamLogs"
    }
    error_output_prefix = "splunk-error-"
    processing_configuration {
      enabled = "false" # Disable processing configuration unless you need transformations
    }
  }

  kms_key_arn = "arn:aws:kms:us-east-1:123456789012:key/your-kms-key-id" # Replace with your KMS key ARN (optional but recommended)
  server_side_encryption {
    enabled  = true
    key_type = "KMS"
  }
}

variable "splunk_hec_token" {
  description = "Splunk HTTP Event Collector (HEC) token"
  type        = string
  sensitive   = true
}

variable "splunk_hec_endpoint" {
  description = "Splunk HEC endpoint (e.g., 'https://<your-splunk-instance>:8088')"
  type        = string
}

variable "splunk_index_name" {
  description = "Splunk index name for storing the data"
  type        = string
}

