terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_kinesis_firehose_delivery_stream" "elasticsearch_destination" {
  name        = "elasticsearch-destination-stream"
  destination = "extended_s3_compatible"

  elasticsearch_configuration {
    endpoint        = "https://${var.elasticsearch_domain}:443" # Replace with your Elasticsearch domain
    role_arn        = aws_iam_role.firehose_elasticsearch_role.arn
    buffer_size     = 5 # MB
    buffer_interval = 300 # seconds
    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = "/aws/kinesisfirehose/${aws_kinesis_firehose_delivery_stream.elasticsearch_destination.name}"
      log_stream_name = "delivery"
    }
    s3_backup_mode = "FailedDocumentsOnly"
    s3_configuration {
      role_arn   = aws_iam_role.firehose_s3_backup_role.arn
      bucket_arn = aws_s3_bucket.firehose_backup_bucket.arn
      prefix     = "firehose-backup/"
      error_output_prefix = "firehose-error-backup/"
    }
    vpc_configuration {
      security_group_ids = [aws_security_group.firehose_elasticsearch_sg.id]
      subnet_ids         = [aws_subnet.firehose_subnet_1.id, aws_subnet.firehose_subnet_2.id]
    }
    type_name = "ES"
  }

  http_source_configuration {
    url           = var.http_source_url # Replace with your HTTP source URL
    buffer_size   = 5                   # MB
    buffer_interval = 300                # seconds
    processing_configuration {
      enabled = "false"
    }
  }
}

