    protocol    = "tcp"
    cidr_blocks = ["169.254.169.128/32"] # Kinesis Firehose VPC endpoint CIDR
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_vpc" "firehose_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "firehose-vpc"
  }
}

resource "aws_subnet" "firehose_subnet_1" {
  vpc_id     = aws_vpc.firehose_vpc.id
  cidr_block = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "firehose-subnet-1"
  }
}

resource "aws_subnet" "firehose_subnet_2" {
  vpc_id     = aws_vpc.firehose_vpc.id
  cidr_block = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "firehose-subnet-2"
  }
}

resource "aws_internet_gateway" "firehose_igw" {
  vpc_id = aws_vpc.firehose_vpc.id
}

resource "aws_route_table" "firehose_route_table" {
  vpc_id = aws_vpc.firehose_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.firehose_igw.id
  }
}

resource "aws_route_table_association" "firehose_subnet_1_association" {
  subnet_id      = aws_subnet.firehose_subnet_1.id
  route_table_id = aws_route_table.firehose_route_table.id
}

resource "aws_route_table_association" "firehose_subnet_2_association" {
  subnet_id      = aws_subnet.firehose_subnet_2.id
  route_table_id = aws_route_table.firehose_route_table.id
}
