        Effect = "Allow",
        Action = [
          "s3:PutObject",
          "s3:GetBucketLocation",
          "s3:ListBucket"
        ],
        Resource = [
          "arn:aws:s3:::your-backup-bucket-name", # Replace with your S3 bucket name
          "arn:aws:s3:::your-backup-bucket-name/*"
        ]
      },
      {
        Effect = "Allow",
        Action = [
          "logs:PutLogEvents",
          "logs:CreateLogGroup",
          "logs:CreateLogStream"
        ],
        Resource = "*"
      },
      {
        Effect = "Allow",
        Action = [
          "opensearch:ESHttpPost",
          "opensearch:ESHttpPut"
        ],
        Resource = "arn:aws:opensearch:us-east-1:123456789012:domain/your-opensearch-domain-name/*" # Replace with your OpenSearch domain ARN
      },
      {
        Effect = "Allow",
        Action = [
          "kms:Decrypt",
          "kms:GenerateDataKey"
        ],
        Resource = [
          "arn:aws:kms:us-east-1:123456789012:key/your-kms-key-id", # Replace with your KMS key ARN
          "arn:aws:kms:us-east-1:123456789012:key/your-opensearch-kms-key-id" # Replace with your OpenSearch KMS key ARN
        ]
      }
    ]
  })
}

resource "aws_opensearch_cluster" "example" {
  domain_name    = "your-opensearch-domain-name" # Replace with your desired OpenSearch domain name
  version        = "OpenSearch_1.3" # Replace with your desired OpenSearch version

  cluster_config {
    instance_type          = "t3.small.search" # Replace with your desired instance type
    instance_count         = 1
    zone_awareness_enabled = false
  }

  vpc_options {
    security_group_ids = [aws_security_group.opensearch_sg.id]
    subnet_ids         = ["subnet-12345678", "subnet-87654321"] # Replace with your VPC subnet IDs
  }

  encrypt_at_rest {
    enabled = true
  }

  node_to_node_encryption {
    enabled = true
  }

  tags = {
    Name = "OpenSearch-Cluster"
  }
}

resource "aws_security_group" "opensearch_sg" {
  name        = "opensearch-sg"
  description = "Security group for OpenSearch cluster"
  vpc_id      = "vpc-12345678" # Replace with your VPC ID

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict this to your VPC CIDR in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "OpenSearch-Security-Group"
  }
}
