terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_kinesis_firehose_delivery_stream" "s3_destination" {
  name        = "my-extended-s3-destination-stream"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_s3_role.arn
    bucket_arn = "arn:aws:s3:::your-bucket-name" # Replace with your S3 bucket ARN
    prefix     = "firehose-data/"               # Optional prefix for files in S3

    buffering_hints {
      size    = 5                  # Size in MB (1-128)
      interval = 300               # Interval in seconds (60-900)
    }

    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = "/aws/kinesisfirehose/${aws_kinesis_firehose_delivery_stream.s3_destination.name}"
      log_stream_name = "S3Delivery"
    }

    compression_format = "GZIP" # Optional: "UNCOMPRESSED", "GZIP", or "ZIP"

    error_output_prefix = "firehose-errors/" # Optional prefix for error files

    processing_configuration {
      enabled = "true"

      processors {
        type = "Lambda"

        parameters {
          parameter_name  = "LambdaArn"
          parameter_value = aws_lambda_function.firehose_processor.arn
        }
      }
    }
  }
}

resource "aws_iam_role" "firehose_s3_role" {
  name = "firehose_s3_delivery_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "firehose_s3_policy" {
  role       = aws_iam_role.firehose_s3_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3FullAccess"
}

resource "aws_lambda_function" "firehose_processor" {
  filename      = "lambda_function.zip" # Replace with your Lambda function zip file
  function_name = "firehose-processor"
  role          = aws_iam_role.lambda_exec.arn
  handler       = "index.handler"
  runtime       = "nodejs18.x" # Adjust runtime as needed

  environment {
    variables = {
      INPUT_BUCKET = "your-input-bucket" # Optional: For processing input data
    }
  }
}

resource "aws_iam_role" "lambda_exec" {
  name = "firehose_lambda_exec_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_exec.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

resource "aws_iam_role_policy" "lambda_s3_access" {
  name = "firehose_lambda_s3_access"
  role = aws_iam_role.lambda_exec.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:ListBucket"
        ],
        Resource = [
          "arn:aws:s3:::your-bucket-name", # Replace with your bucket ARN
          "arn:aws:s3:::your-bucket-name/*"
        ]
      }
    ]
  })
}

