resource "aws_kinesisanalytics_application" "basic_app" {
  name = "basic-kinesis-analytics-app"

  runtime_environment {
    type = "SQL-1_0"
    scala_version = "2.11"
    storage_committer_configuration {
      commit_interval = 1000
      max_buffer_size = 10485760 # 10MB
    }
  }

  service_execution_role_arn = aws_iam_role.kinesis_analytics_role.arn

  application_description = "Basic Kinesis Analytics Application for processing and analyzing data streams"
  application_code_s3_location {
    bucket_arn = aws_s3_bucket.app_code.arn
    bucket_name = aws_s3_bucket.app_code.bucket
    file_key    = "application-code.zip"
    version_id  = aws_s3_object.app_code.version_id
  }

  tags = {
    Name        = "BasicKinesisAnalyticsApp"
    Environment = "Development"
  }
}

resource "aws_iam_role" "kinesis_analytics_role" {
  name = "kinesis-analytics-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "kinesis_analytics_attach" {
  role       = aws_iam_role.kinesis_analytics_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonKinesisAnalyticsServiceRolePolicy"
}

