  bucket = "kinesis-analytics-app-code-${random_id.bucket_suffix.hex}"
}

resource "aws_s3_object" "app_code" {
  bucket = aws_s3_bucket.app_code.bucket
  key    = "application-code.zip"
  source = "path/to/your/application-code.zip" # Replace with your actual application code path
  etag   = filemd5("path/to/your/application-code.zip") # Replace with your actual application code path
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

