provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# IAM Role for Kinesis Analytics Application
resource "aws_iam_role" "kinesis_analytics_role" {
  name = "kinesis-analytics-sql-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for Kinesis Analytics Application
resource "aws_iam_policy" "kinesis_analytics_policy" {
  name        = "kinesis-analytics-sql-policy"
  description = "Policy for Kinesis Analytics SQL Application"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = [
          "kinesis:GetRecords",
          "kinesis:GetShardIterator",
          "kinesis:DescribeStream",
          "kinesis:ListStreams"
        ]
        Resource = "*"
      },
      {
        Effect   = "Allow"
        Action   = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents",
          "logs:DescribeLogStreams"
        ]
        Resource = "*"
      },
      {
        Effect   = "Allow"
        Action   = [
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          "arn:aws:s3:::your-sql-application-bucket/*",
          "arn:aws:s3:::your-sql-application-bucket"
        ]
      }
    ]
  })
}

# Attach IAM Policy to Role
resource "aws_iam_role_policy_attachment" "kinesis_analytics_attachment" {
  role       = aws_iam_role.kinesis_analytics_role.name
  policy_arn = aws_iam_policy.kinesis_analytics_policy.arn
}

# Kinesis Data Stream (Input Stream for Analytics)
resource "aws_kinesis_stream" "input_stream" {
  name             = "sql-input-stream"
  shard_count      = 1 # Adjust based on expected throughput
  retention_period = 24 # Hours
}

# Kinesis Analytics Application
resource "aws_kinesisanalyticsv2_application" "sql_application" {
  name = "sql-analytics-application"

  runtime_environment {
    type = "SQL-1_0"
    revision = aws_kinesisanalyticsv2_application_version.sql_application_revision.revision_id
  }

  service_execution_role_arn = aws_iam_role.kinesis_analytics_role.arn

  application_description = "SQL-based Kinesis Analytics Application for processing SQL data"
  application_code_location {
    s3_location {
      bucket_arn = "arn:aws:s3:::your-sql-application-bucket" # Replace with your bucket ARN
      file_key   = "sql-application-code.zip" # Path to your SQL application code in S3
    }
  }
}

# Kinesis Analytics Application Version
resource "aws_kinesisanalyticsv2_application_version" "sql_application_revision" {
  application_name = aws_kinesisanalyticsv2_application.sql_application.name
  application_version_id = "1"
  configuration {
    runtime_environment = "SQL-1_0"
    service_execution_role_arn = aws_iam_role.kinesis_analytics_role.arn
    application_code_location {
      s3_location {
        bucket_arn = "arn:aws:s3:::your-sql-application-bucket" # Replace with your bucket ARN
        file_key   = "sql-application-code.zip" # Path to your SQL application code in S3
      }
    }
    environment_properties = {
      "sqlApplicationName" = aws_kinesisanalyticsv2_application.sql_application.name
      "inputStreamName"    = aws_kinesis_stream.input_stream.name
    }
  }
}

# Kinesis Analytics Application Input
resource "aws_kinesisanalyticsv2_application_input" "sql_application_input" {
  application_name = aws_kinesisanalyticsv2_application.sql_application.name
  name             = "input-stream"
  input_schema {
    record_format {
      record_format_type = "JSON"
      mapping_parameters {
        json_mapping_parameters {
          type = "DYNAMIC"
        }
      }
    }
  }
  input_parallelism {
    parallelism_factor = 1
  }
  input_schema_update_mode = "UpdateAlreadyExists"
  kinesis_stream_input {
    resource_arn = aws_kinesis_stream.input_stream.arn
    name         = aws_kinesis_stream.input_stream.name
  }
}

# Kinesis Analytics Application Output (Optional: Configure if you need to output processed data)
resource "aws_kinesisanalyticsv2_application_output" "sql_application_output" {
  application_name = aws_kinesisanalyticsv2_application.sql_application.name
  name             = "output-stream"
  output_schema {
    record_format {
      record_format_type = "JSON"
      mapping_parameters {
        json_mapping_parameters {
          type = "DYNAMIC"
        }
      }
    }
  }
  output_parallelism {
    parallelism_factor = 1
  }
  output_schema_update_mode = "UpdateAlreadyExists"
  kinesis_stream_output {
    resource_arn = aws_kinesis_stream.input_stream.arn # Reuse the same stream or create a new one
    name         = "output-stream"
  }
}

