terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create an IAM role for Kinesis Analytics
resource "aws_iam_role" "kinesis_analytics_role" {
  name = "kinesis-analytics-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      }
    ]
  })
}

# Attach basic policies to the IAM role
resource "aws_iam_role_policy_attachment" "kinesis_analytics_cloudwatch" {
  role       = aws_iam_role.kinesis_analytics_role.name
  policy_arn = "arn:aws:iam::aws:policy/CloudWatchLogsFullAccess"
}

resource "aws_iam_role_policy_attachment" "kinesis_analytics_kinesis" {
  role       = aws_iam_role.kinesis_analytics_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonKinesisFullAccess"
}

# Create a CloudWatch Log Group for Kinesis Analytics
resource "aws_cloudwatch_log_group" "kinesis_analytics_log_group" {
  name              = "/aws/kinesisanalytics/${var.application_name}"
  retention_in_days = 7 # Adjust retention as needed
}

# Create a Kinesis Data Stream (required for Kinesis Analytics)
resource "aws_kinesis_stream" "analytics_stream" {
  name             = "${var.application_name}-stream"
  shard_count      = 1 # Adjust based on throughput needs
  retention_period = 24 # Hours (default is 24)
}

# Create the Kinesis Analytics Application
resource "aws_kinesisanalytics_application" "basic_app" {
  name = var.application_name

  application_mode {
    batch_window_in_seconds = 60 # Adjust as needed
    checkpoint_configuration {
      checkpoint_interval_in_seconds = 60
      checkpointing_enabled          = true
    }
    language = "SQL-1_0"
    realtime_window_in_seconds     = 0
  }

  runtime_environment {
    scala_version = "2.11"
    storage_committer {
      cloudwatch_logs {
        cloudwatch_logs_configuration {
          cloudwatch_logs_role_arn = aws_iam_role.kinesis_analytics_role.arn
          log_stream_name          = aws_cloudwatch_log_group.kinesis_analytics_log_group.name
        }
      }
    }
  }

  service_execution_role_arn = aws_iam_role.kinesis_analytics_role.arn

  application_configuration {
    application_name = var.application_name
    service_scaling_configuration {
      application_target {
        target_id = "Target_0"
        target_value = 100 # Adjust based on your needs
      }
    }
  }
}

# Create a Kinesis Analytics Application Input (Stream)
resource "aws_kinesisanalytics_application_input" "stream_input" {
  application_name = aws_kinesisanalytics_application.basic_app.name
  input_schema {
    record_column {
      mapping = "record"
      name    = "record"
    }
    record_format {
      record_format_type = "JSON"
    }
  }
  input_parallelism {
    parallelism_factor = 1
  }
  name = "StreamInput"
  stream_source {
    stream_arn = aws_kinesis_stream.analytics_stream.arn
    stream_name = aws_kinesis_stream.analytics_stream.name
  }
}

# Create a Kinesis Analytics Application Output (CloudWatch Logs)
resource "aws_kinesisanalytics_application_output" "log_output" {
  application_name = aws_kinesisanalytics_application.basic_app.name
  output_schema {
    record_column {
      mapping = "record"
      name    = "record"
    }
    record_format {
      record_format_type = "JSON"
    }
  }
  name = "LogOutput"
  output_parallelism {
    parallelism_factor = 1
  }
  cloudwatch_logs_configuration {
    cloudwatch_logs_role_arn = aws_iam_role.kinesis_analytics_role.arn
    log_group_arn            = aws_cloudwatch_log_group.kinesis_analytics_log_group.arn
    log_stream_name          = aws_cloudwatch_log_group.kinesis_analytics_log_group.name
  }
}

# Variables
variable "application_name" {
  description = "Name of the Kinesis Analytics Application"
  type        = string
  default     = "basic-kinesis-analytics-app"
}

