      # }
    }
  }

  # Optional: Configure additional settings
  description = "Proxy data source for Kendra"
  tags = {
    Environment = "Production"
    Purpose     = "Search Proxy"
  }
}

# Optional: IAM Role for Kendra Proxy (if using AWS_IAM authentication)
