resource "aws_route53_health_check" "primary_health_check" {
  name = "primary-health-check" # Health check name
  fqdn = "primary.example.com"  # Replace with your FQDN
  type = "HTTPS"                # Change to appropriate protocol (HTTP, HTTPS, TCP, etc.)
  resource_path = "/health"      # Health check endpoint path
  failure_threshold = "3"        # Number of consecutive failures before marking as unhealthy
  port = "443"                   # Port for the health check
  fully_qualified_domain = true  # Set to true if FQDN is fully qualified
  request_interval = "30"        # Interval between health checks in seconds
  tags = {
    Name = "primary-health-check"
  }
}

# Create a failover routing policy for the primary resource
resource "aws_route53_record" "primary_failover" {
  zone_id = aws_route53zone.primary.zone_id
  name    = "primary.example.com" # Replace with your FQDN
  type    = "A"

  alias {
    name                   = aws_lb.primary.dns_name # Replace with your load balancer or resource DNS name
    zone_id                = aws_lb.primary.zone_id # Replace with your load balancer or resource zone ID
    evaluate_target_health = true
    failover_routing_policy {
      type = "PRIMARY"
    }
  }

  health_check_id = aws_route53_health_check.primary_health_check.id
  set_identifier   = "primary"
  failover_routing_policy {
    type = "PRIMARY"
  }
}

# Create a secondary failover record (example for secondary resource)
resource "aws_route53_record" "secondary_failover" {
  zone_id = aws_route53zone.primary.zone_id
  name    = "primary.example.com" # Same FQDN as primary
  type    = "A"

  alias {
    name                   = aws_lb.secondary.dns_name # Replace with your secondary load balancer or resource DNS name
    zone_id                = aws_lb.secondary.zone_id # Replace with your secondary load balancer or resource zone ID
    evaluate_target_health = true
    failover_routing_policy {
      type = "SECONDARY"
    }
  }

  health_check_id = aws_route53_health_check.secondary_health_check.id # Replace with secondary health check ID
  set_identifier   = "secondary"
  failover_routing_policy {
    type = "SECONDARY"
  }
}

