terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Create a hosted zone for the primary domain
resource "aws_route53_zone" "primary" {
  name = "primary.example.com" # Replace with your domain name
}

# Create latency-based routing policy records for us-east-1 and eu-central-1
resource "aws_route53_record" "primary_latency" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "primary.example.com" # Replace with your domain name
  type    = "A"

  alias {
    name                   = aws_lb.primary.dns_name
    zone_id                = aws_lb.primary.zone_id
    evaluate_target_health = true
  }

  set_identifier = "primary-latency"

  failover_routing_policy {
    type = "LATENCY"
  }

  latency_routing_policy {
    region = "us-east-1"
    region_code = "us-east-1"
  }

  latency_routing_policy {
    region = "eu-central-1"
    region_code = "eu-central-1"
  }
}

# Create a load balancer for us-east-1 (primary endpoint)
resource "aws_lb" "primary" {
  name               = "primary-lb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.lb.id]
  subnets            = aws_subnet.public[*].id
}

# Create a load balancer for eu-central-1 (secondary endpoint)
resource "aws_lb" "secondary" {
  name               = "secondary-lb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.lb.id]
  subnets            = aws_subnet.public[*].id
  region             = "eu-central-1"
}

# Create a security group for the load balancer
resource "aws_security_group" "lb" {
  name        = "lb-sg"
  description = "Allow HTTP traffic"
  vpc_id      = aws_vpc.primary.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Create a VPC for the primary region
resource "aws_vpc" "primary" {
  cidr_block = "10.0.0.0/16"
  region     = "us-east-1"
}

# Create subnets for the primary region
resource "aws_subnet" "public" {
  count             = 2
  vpc_id            = aws_vpc.primary.id
  cidr_block        = "10.0.${count.index}.0/24"
  availability_zone = element(["us-east-1a", "us-east-1b"], count.index)
}

# Create a VPC for the secondary region (eu-central-1)
resource "aws_vpc" "secondary" {
  cidr_block = "10.1.0.0/16"
  region     = "eu-central-1"
}

# Create subnets for the secondary region
resource "aws_subnet" "public_secondary" {
  count             = 2
  vpc_id            = aws_vpc.secondary.id
  cidr_block        = "10.1.${count.index}.0/24"
  availability_zone = element(["eu-central-1a", "eu-central-1b"], count.index)
  region            = "eu-central-1"
}

# Create a Route53 health check for the primary endpoint
resource "aws_route53_health_check" "primary" {
  health_check_config {
    type                     = "HTTPS"
    resource_path            = "/"
    fully_qualified_domain_name = "primary.example.com" # Replace with your primary endpoint domain
    request_interval         = 30
    failure_threshold        = 3
    port                      = 443
    region                    = "us-east-1"
  }
}

# Create a Route53 health check for the secondary endpoint
resource "aws_route53_health_check" "secondary" {
  health_check_config {
    type                     = "HTTPS"
    resource_path            = "/"
    fully_qualified_domain_name = "secondary.example.com" # Replace with your secondary endpoint domain
    request_interval         = 30
    failure_threshold        = 3
    port                      = 443
    region                    = "eu-central-1"
  }
}

# Create a weighted routing policy record for the primary endpoint
resource "aws_route53_record" "primary_weighted" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "primary.example.com" # Replace with your domain name
  type    = "A"

  alias {
    name                   = aws_lb.primary.dns_name
    zone_id                = aws_lb.primary.zone_id
    evaluate_target_health = true
  }

  set_identifier = "primary-weight"

  weighted_routing_policy {
    weight = 50 # 50% weight for us-east-1
  }
}

# Create a weighted routing policy record for the secondary endpoint
resource "aws_route53_record" "secondary_weighted" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "primary.example.com" # Replace with your domain name
  type    = "A"

  alias {
    name                   = aws_lb.secondary.dns_name
    zone_id                = aws_lb.secondary.zone_id
    evaluate_target_health = true
  }

  set_identifier = "secondary-weight"

  weighted_routing_policy {
    weight = 50 # 50% weight for eu-central-1
  }
}

# Use latency-based routing policy for the primary domain
resource "aws_route53_record" "primary_latency_alias" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "primary.example.com" # Replace with your domain name
  type    = "A"

  alias {
    name                   = aws_lb.primary.dns_name
    zone_id                = aws_lb.primary.zone_id
    evaluate_target_health = true
  }

  set_identifier = "primary-latency"

  latency_routing_policy {
    region = "us-east-1"
  }

  latency_routing_policy {
    region = "eu-central-1"
  }
}

