terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create a Traffic Policy
resource "aws_route53_traffic_policy" "example_policy" {
  name = "example-traffic-policy"

  # Define the policy rules (example: weighted routing)
  rules {
    name = "weighted-rule"

    # Weighted routing rule
    weighted {
      weight = 100 # 100% traffic to this rule
      key    = "us-east-1"
    }

    weighted {
      weight = 0   # 0% traffic to this rule (disabled)
      key    = "eu-west-1"
    }

    # Optional: Add latency-based routing
    latency {
      region = "us-east-1"
      key    = "us-east-1"
    }

    latency {
      region = "eu-west-1"
      key    = "eu-west-1"
    }

    # Optional: Add geolocation-based routing
    geolocation {
      country_code = "US"
      key          = "us-east-1"
    }

    geolocation {
      country_code = "EU"
      key          = "eu-west-1"
    }

