terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    helm = {
      source  = "hashicorp/helm"
      version = "~> 2.9"
    }
    kubernetes = {
      source  = "hashicorp/kubernetes"
      version = "~> 2.24"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Specify your desired region here
}

# Retrieve current AWS caller identity
data "aws_caller_identity" "current" {}

# Fetch latest stable ECR image (optional)
data "aws_ecr_repository" "eks_image_repo" {
  name = "your-eks-image-repo" # Replace with your ECR repository name
}

data "aws_ecr_repository" "stable_image" {
  name = data.aws_ecr_repository.eks_image_repo.name
}

data "aws_ecr_image" "stable" {
  repository_name = data.aws_ecr_repository.stable_image.name
  image_tag       = "stable"
}

# Local variables
locals {
  image_tag       = data.aws_ecr_image.stable.image_tag
  aws_tags        = {
    Environment = "production"
    Terraform   = "true"
  }
  workspace_name  = terraform.workspace
}

# EKS Module Configuration
module "eks" {
  source  = "terraform-aws-modules/eks/aws"
  version = "~> 19.0"

  cluster_name    = "my-eks-cluster"
  cluster_version = "1.28"

  vpc_id     = "vpc-12345678" # Replace with your VPC ID
  subnet_ids = ["subnet-12345678", "subnet-87654321"] # Replace with your subnet IDs

  node_groups = {
    eks_nodes = {
      desired_capacity = 2
      max_capacity     = 3
      min_capacity     = 1
      instance_type    = "t3.medium"
      capacity_type    = "ON_DEMAND"
    }
  }

  cluster_addons = {
    kube-proxy = {
      most_recent = true
    }
    vpc-cni = {
      most_recent = true
    }
  }

  tags = local.aws_tags
}

# Retrieve EKS cluster information
data "aws_eks_cluster" "cluster" {
  name = module.eks.cluster_id
}

# Retrieve EKS cluster authentication data
data "aws_eks_cluster_auth" "cluster_auth" {
  name = module.eks.cluster_id
}

# Configure Kubernetes provider
provider "kubernetes" {
  host                   = data.aws_eks_cluster.cluster.endpoint
  cluster_ca_certificate = base64decode(data.aws_eks_cluster.cluster.certificate_authority[0].data)
  token                  = data.aws_eks_cluster_auth.cluster_auth.token
}

# Configure Helm provider
provider "helm" {
  kubernetes {
    host                   = data.aws_eks_cluster.cluster.endpoint
    cluster_ca_certificate = base64decode(data.aws_eks_cluster.cluster.certificate_authority[0].data)
    token                  = data.aws_eks_cluster_auth.cluster_auth.token
  }
}

