provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create an IAM OIDC provider for the EKS cluster
resource "aws_iam_openid_connect_provider" "example_oidc" {
  client_id_list  = ["sts.amazonaws.com"] # Required for AWS STS
  thumbprint_list = ["thumbprint"] # Replace with actual thumbprint(s) of the cluster's certificate
  url             = "https://oidc.eks.<region>.amazonaws.com/id/<cluster-id>" # Replace <region> and <cluster-id> with actual values

  # Example: For cluster named "example" in us-east-1, the URL would be:
  # url = "https://oidc.eks.us-east-1.amazonaws.com/id/EXAMPLECLUSTERID"
}

# Example EKS cluster (assuming it already exists or is created elsewhere)
data "aws_eks_cluster" "example" {
  name = "example"
}

# Example IAM role for the OIDC provider (optional, adjust as needed)
resource "aws_iam_role" "example_oidc_role" {
  name = "example-eks-oidc-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect    = "Allow"
        Principal = {
          Federated = aws_iam_openid_connect_provider.example_oidc.arn
        }
        Action    = "sts:AssumeRoleWithWebIdentity"
        Condition = {
          StringEquals = {
            "${replace(aws_iam_openid_connect_provider.example_oidc.url, "https://", "")}sub" = "system:serviceaccount:kube-system:example-sa" # Adjust as needed
          }
        }
      }
    ]
  })
}

# Example IAM policy attachment (optional, adjust as needed)
resource "aws_iam_role_policy_attachment" "example_oidc_attach" {
  role       = aws_iam_role.example_oidc_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSClusterPolicy" # Example policy, replace as needed
}

# Output the OIDC provider ARN for reference
output "oidc_provider_arn" {
  value = aws_iam_openid_connect_provider.example_oidc.arn
}

