# Define the IAM policy document for assuming a role by EKS pods
resource "aws_iam_policy" "example" {
  name        = "example-pod-identity-policy"
  description = "Policy for EKS pods to assume IAM roles"

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Effect = "Allow",
        Principal = {
          Federated = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:oidc-provider/${replace(data.aws_eks_cluster.example.identity[0].oidc_issuer, "https://", "")}"
        },
        Action = "sts:AssumeRoleWithWebIdentity",
        Condition = {
          StringEquals = {
            "${replace(data.aws_eks_cluster.example.identity[0].oidc_issuer, "https://", "")}:sub" = "system:serviceaccount:default:example-sa"
          }
        }
      }
    ]
  })
}

# Get current AWS account ID
data "aws_caller_identity" "current" {}

# Get EKS cluster details (assuming cluster named "example" exists)
data "aws_eks_cluster" "example" {
  name = "example"
}

# Create IAM role for EKS pods
resource "aws_iam_role" "example" {
  name = "example-pod-identity-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRoleWithWebIdentity",
        Effect = "Allow",
        Principal = {
          Federated = aws_iam_policy.example.arn
        },
        Condition = {
          StringEquals = {
            "${replace(data.aws_eks_cluster.example.identity[0].oidc_issuer, "https://", "")}:sub" = "system:serviceaccount:default:example-sa"
          }
        }
      }
    ]
  })
}

# Attach S3 read-only policy to the IAM role
resource "aws_iam_role_policy_attachment" "example_s3_readonly" {
  role       = aws_iam_role.example.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3ReadOnlyAccess"
}

# Define EKS pod identity association
resource "aws_eks_pod_identity_association" "example" {
  cluster_name = data.aws_eks_cluster.example.name
  namespace    = "default"
  service_account = "example-sa"
  role_arn      = aws_iam_role.example.arn
}
