provider "aws" {
  region = "us-east-1"
}

# IAM Role for EKS
resource "aws_iam_role" "demo_eks" {
  name = "demo_eks_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = [
            "eks.amazonaws.com",
            "ec2.amazonaws.com"
          ]
        }
      }
    ]
  })
}

# IAM Role Policy Attachments for EKS
resource "aws_iam_role_policy_attachment" "AmazonEKSClusterPolicy" {
  role       = aws_iam_role.demo_eks.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSClusterPolicy"
}

resource "aws_iam_role_policy_attachment" "AmazonEKSVPCResourceController" {
  role       = aws_iam_role.demo_eks.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSVPCResourceController"
}

# VPC Configuration
resource "aws_vpc" "demo_eks_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "demo_eks_vpc"
  }
}

resource "aws_subnet" "demo_eks_subnet" {
  count                   = 3
  vpc_id                  = aws_vpc.demo_eks_vpc.id
  cidr_block              = "10.0.${count.index}.0/24"
  availability_zone       = element(data.aws_availability_zones.available.names, count.index)
  map_public_ip_on_launch = true
  tags = {
    Name = "demo_eks_subnet_${count.index}"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_internet_gateway" "demo_eks_gw" {
  vpc_id = aws_vpc.demo_eks_vpc.id
  tags = {
    Name = "demo_eks_gw"
  }
}

resource "aws_route_table" "demo_eks_route_table" {
