  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.demo_eks_gw.id
  }

  tags = {
    Name = "demo_eks_route_table"
  }
}

resource "aws_route_table_association" "demo_eks_route_association" {
