provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create VPC for EKS cluster
resource "aws_vpc" "example_vpc" {
  cidr_block = "10.0.0.0/16"
  enable_dns_support = true
  enable_dns_hostnames = true
  tags = {
    Name = "example-vpc"
  }
}

# Create subnet for EKS cluster
resource "aws_subnet" "example_subnet" {
  vpc_id            = aws_vpc.example_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a" # Change to your preferred AZ
  tags = {
    Name = "example-subnet"
  }
}

# Create IAM role for EKS cluster
resource "aws_iam_role" "eks_role" {
  name = "example-eks-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Effect = "Allow",
        Principal = {
          Service = "eks.amazonaws.com"
        }
      }
    ]
  })
  tags = {
    Name = "example-eks-role"
    AttributeName = "example"
  }
}

# Attach AmazonEKSClusterPolicy to the IAM role
resource "aws_iam_role_policy_attachment" "eks_cluster_policy" {
  role       = aws_iam_role.eks_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSClusterPolicy"
}

# Create EKS cluster
resource "aws_eks_cluster" "example" {
  name     = "example"
  role_arn = aws_iam_role.eks_role.arn
  vpc_config {
    subnet_ids = [aws_subnet.example_subnet.id]
  }
  depends_on = [
    aws_iam_role_policy_attachment.eks_cluster_policy,
  ]
  depends_on = [
    aws_vpc.example_vpc,
    aws_subnet.example_subnet,
  ]
  endpoint {
    public_access  = true
    private_access = false
  }
}
```

