variable "bucket_suffix" {
  description = "Suffix for the CloudGoat and web data bucket names"
  type        = string
  default     = "test"
}

variable "local_order_data_path" {
  description = "Local path to the order_data2.csv file"
  type        = string
}

provider "aws" {
  region = "us-east-1"
}

# CloudGoat data bucket
resource "aws_s3_bucket" "cloudgoat_data" {
  bucket = "cloudgoat-data-${var.bucket_suffix}"
}

resource "aws_s3_bucket_acl" "cloudgoat_data_acl" {
  bucket = aws_s3_bucket.cloudgoat_data.id
  acl    = "private"
}

resource "aws_s3_bucket_ownership_controls" "cloudgoat_data_ownership" {
  bucket = aws_s3_bucket.cloudgoat_data.id
  rule {
    object_ownership = "BucketOwnerEnforced"
  }
}

# Web data bucket
resource "aws_s3_bucket" "web_data" {
  bucket = "web-data-${var.bucket_suffix}"
}

resource "aws_s3_bucket_acl" "web_data_acl" {
  bucket = aws_s3_bucket.web_data.id
  acl    = "private"
}

resource "aws_s3_bucket_public_access_block" "web_data_public_access" {
  bucket = aws_s3_bucket.web_data.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Upload order_data2.csv to web data bucket
resource "aws_s3_object" "order_data" {
  bucket = aws_s3_bucket.web_data.id
  key    = "order_data2.csv"
  source = var.local_order_data_path
  etag   = filemd5(var.local_order_data_path)
}

# Bucket policy for web data bucket
resource "aws_s3_bucket_policy" "web_data_policy" {
  bucket = aws_s3_bucket.web_data.id
  policy = data.aws_iam_policy_document.web_data_policy_document.json
}

data "aws_iam_policy_document" "web_data_policy_document" {
  statement {
    actions   = ["s3:PutObject"]
    resources = ["${aws_s3_bucket.web_data.arn}/*"]

    principals {
      type        = "*"
      identifiers = ["*"]
    }
  }
}
