provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create a KMS key with a specific description and deletion window
resource "aws_kms_key" "s3_encryption_key" {
  description             = "KMS key for encrypting S3 bucket objects"
  deletion_window_in_days = 30 # 30-day deletion window
  enable_key_rotation     = true
}

# Create an S3 bucket with the specified name
resource "aws_s3_bucket" "encrypted_bucket" {
  bucket = "my-encrypted-bucket-${random_id.bucket_suffix.hex}" # Unique bucket name with random suffix
}

# Generate a random suffix to ensure bucket name uniqueness
resource "random_id" "bucket_suffix" {
  byte_length = 8
}

# Enable server-side encryption for the S3 bucket using the KMS key
resource "aws_s3_bucket_server_side_encryption_configuration" "bucket_encryption" {
  bucket = aws_s3_bucket.encrypted_bucket.id

  rule {
    apply_server_side_encryption_by_default {
      kms_master_key_id = aws_kms_key.s3_encryption_key.arn
      sse_algorithm     = "aws:kms" # AWS-managed KMS algorithm
    }
  }
}

# Ensure the bucket uses the encryption configuration
resource "aws_s3_bucket_versioning" "bucket_versioning" {
  bucket = aws_s3_bucket.encrypted_bucket.id

  versioning_configuration {
    status = "Enabled"
  }
}

# Optional: Block public access to the S3 bucket
resource "aws_s3_bucket_public_access_block" "bucket_public_access" {
  bucket = aws_s3_bucket.encrypted_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

