  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Define the first S3 bucket (private)
resource "aws_s3_bucket" "private_bucket" {
  bucket = "my-private-bucket-123456" # Replace with your unique bucket name
}

# Define the second S3 bucket (log delivery)
resource "aws_s3_bucket" "log_bucket" {
  bucket = "my-log-bucket-123456" # Replace with your unique bucket name
}

# Set ACL for the private bucket (private)
resource "aws_s3_bucket_acl" "private_bucket_acl" {
  bucket = aws_s3_bucket.private_bucket.id
  acl    = "private"
}

# Set ACL for the log bucket (allow log delivery writes)
resource "aws_s3_bucket_acl" "log_bucket_acl" {
  bucket = aws_s3_bucket.log_bucket.id
  acl    = "log-delivery-write"
}

# Enable versioning for the private bucket
resource "aws_s3_bucket_versioning" "private_bucket_versioning" {
  bucket = aws_s3_bucket.private_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

# Enable versioning for the log bucket
resource "aws_s3_bucket_versioning" "log_bucket_versioning" {
  bucket = aws_s3_bucket.log_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

# Configure logging for the private bucket to send logs to the log bucket
resource "aws_s3_bucket_logging" "private_bucket_logging" {
  bucket = aws_s3_bucket.private_bucket.id

  target_bucket = aws_s3_bucket.log_bucket.id
  target_prefix = "logs/private-bucket/" # Log file prefix
}

# Block public access for the private bucket
resource "aws_s3_bucket_public_access_block" "private_bucket_public_access_block" {
  bucket = aws_s3_bucket.private_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Block public access for the log bucket
resource "aws_s3_bucket_public_access_block" "log_bucket_public_access_block" {
  bucket = aws_s3_bucket.log_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}
```

