    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "default-sg"
  }
}

resource "aws_ebs_volume" "volume_subnet_a" {
  availability_zone = "us-east-1a"
  size              = 50
  tags = {
    Name = "ebs-volume-subnet-a"
  }
}

resource "aws_ebs_volume" "volume_subnet_b" {
  availability_zone = "us-east-1b"
  size              = 50
  tags = {
    Name = "ebs-volume-subnet-b"
  }
}

resource "aws_volume_attachment" "ebs_att_subnet_a" {
  device_name = "/dev/sdh"
  volume_id   = aws_ebs_volume.volume_subnet_a.id
  instance_id = aws_instance.instance_subnet_a.id
}

resource "aws_volume_attachment" "ebs_att_subnet_b" {
  device_name = "/dev/sdh"
  volume_id   = aws_ebs_volume.volume_subnet_b.id
  instance_id = aws_instance.instance_subnet_b.id
}
