provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "main-vpc"
  }
}

# Create Internet Gateway
resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.main.id
  tags = {
    Name = "main-igw"
  }
}

# Create Public Subnet (for NAT Gateway)
resource "aws_subnet" "public" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = true
  tags = {
    Name = "public-subnet"
  }
}

# Create Elastic IP for NAT Gateway
resource "aws_eip" "nat" {
  domain = "vpc"
}

# Create NAT Gateway
resource "aws_nat_gateway" "nat" {
  allocation_id = aws_eip.nat.id
  subnet_id     = aws_subnet.public.id
  tags = {
    Name = "main-nat-gateway"
  }
}

# Create Route Table for Private Subnets
resource "aws_route_table" "private" {
  vpc_id = aws_vpc.main.id
  route {
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.nat.id
  }
  tags = {
    Name = "private-route-table"
  }
}

# Create Private Subnets
resource "aws_subnet" "private" {
  count             = 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.${count.index + 2}.0/24"
  availability_zone = "us-east-1${count.index + 1}"
  tags = {
    Name = "private-subnet-${count.index + 1}"
  }
}

# Associate Route Table with Private Subnets
resource "aws_route_table_association" "private" {
  count          = 2
  subnet_id      = aws_subnet.private[count.index].id
  route_table_id = aws_route_table.private.id
}

# Create Security Group for EC2 instances
resource "aws_security_group" "ec2_sg" {
  name        = "ec2-security-group"
  description = "Allow SSH and HTTP traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "ec2-sg"
  }
}

# Create EFS File System
resource "aws_efs_file_system" "shared_storage" {
  creation_token = "shared-storage"
  encrypted      = true
  tags = {
    Name = "shared-storage-efs"
  }
}

# Create EFS Mount Targets
resource "aws_efs_mount_target" "mount_targets" {
  count          = 2
  file_system_id = aws_efs_file_system.shared_storage.id
  subnet_id      = aws_subnet.private[count.index].id
  security_groups = [aws_security_group.ec2_sg.id]
}

# Create EC2 Key Pair
resource "aws_key_pair" "ec2_key" {
  key_name   = "ec2-key-pair"
  public_key = file("~/.ssh/id_rsa.pub") # Replace with your public key path
}

# Create EC2 Instances
resource "aws_instance" "ec2_instances" {
  count         = 2
  ami           = data.aws_ami.amazon_linux_2.id
  instance_type = "t3.medium" # Newest AWS Linux 2 AMI as of 2023
  subnet_id     = aws_subnet.private[count.index].id
  key_name      = aws_key_pair.ec2_key.key_name
  vpc_security_group_ids = [aws_security_group.ec2_sg.id]
  iam_instance_profile = aws_iam_instance_profile.efs_access.name
  user_data = <<-EOF
              #!/bin/bash
              # Mount EFS
              sudo mkdir -p /mnt/shared-storage
              sudo mount -t efs ${aws_efs_file_system.shared_storage.dns_name}:/ /mnt/shared-storage
              echo "${aws_efs_file_system.shared_storage.dns_name}:/ /mnt/shared-storage efs defaults,_netdev 0 0" >> /etc/fstab
              EOF
  tags = {
    Name = "ec2-instance-${count.index + 1}"
  }
}

# Data Source for the latest Amazon Linux 2 AMI
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }
}

# IAM Role for EFS Access
resource "aws_iam_role" "efs_access_role" {
  name = "efs-access-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for EFS Access
resource "aws_iam_policy" "efs_access_policy" {
  name        = "efs-access-policy"
  description = "Policy for EFS access"
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "elasticfilesystem:ClientMount",
          "elasticfilesystem:ClientWrite"
        ]
        Resource = aws_efs_file_system.shared_storage.arn
      }
    ]
  })
}

# Attach IAM Policy to Role
resource "aws_iam_role_policy_attachment" "efs_access_attach" {
  role       = aws_iam_role.efs_access_role.name
  policy_arn = aws_iam_policy.efs_access_policy.arn
}

# Create IAM Instance Profile
resource "aws_iam_instance_profile" "efs_access" {
  name = "efs-access-profile"
  role = aws_iam_role.efs_access_role.name
}

