  cluster_id = var.cluster_id
  access_string = var.access_string
  access_string_type = var.access_string_type
  authentication_token = var.authentication_token
  password = var.password
  password_enabled = var.password_enabled
  tags = var.tags

  tags_all = merge(
    var.tags,
    {
      Name = "ElastiCache-User-Example"
    }
  )
}

variable "cluster_id" {
  description = "The ID of the ElastiCache cluster to which the user belongs."
  type        = string
}

variable "access_string" {
  description = "The access string for the user."
  type        = string
  default     = null
}

variable "access_string_type" {
  description = "The type of access string for the user. Valid values are 'accesskey' or 'seed'."
  type        = string
  default     = "accesskey"
}

variable "authentication_token" {
  description = "The authentication token for the user."
  type        = string
  default     = null
}

variable "password" {
  description = "The password for the user."
  type        = string
  sensitive   = true
  default     = null
}

variable "password_enabled" {
  description = "Whether the user's password is enabled."
  type        = bool
  default     = false
}

variable "tags" {
  description = "A map of tags to assign to the resource."
  type        = map(string)
  default     = {}
}

# IAM Policy for ElastiCache User (if needed)
resource "aws_iam_policy" "elasticache_user_policy" {
  name        = "ElastiCacheUserPolicy"
  description = "Policy for ElastiCache user access"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = [
          "elasticache:DescribeCacheClusters",
          "elasticache:DescribeCacheSubnetGroups",
          "elasticache:DescribeCacheParameterGroups",
          "elasticache:DescribeCacheSecurityGroups",
          "elasticache:ListTagsForResource"
        ]
        Resource = "*"
      }
    ]
  })
}

# IAM Role for ElastiCache User (if needed)
resource "aws_iam_role" "elasticache_user_role" {
  name = "ElastiCacheUserRole"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "elasticache.amazonaws.com"
        }
      }
    ]
  })
}

# Attach IAM Policy to Role (if needed)
resource "aws_iam_role_policy_attachment" "elasticache_user_attachment" {
  role       = aws_iam_role.elasticache_user_role.name
  policy_arn = aws_iam_policy.elasticache_user_policy.arn
}

