# main.tf

# Configure the AWS Provider
provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Associate an existing ElastiCache user with an existing user group
resource "aws_elasticache_user" "example_user" {
  cluster_id = "your-existing-cluster-id" # Replace with your existing ElastiCache cluster ID
  user_id     = "your-existing-user-id"   # Replace with your existing ElastiCache user ID
  user_name   = "your-existing-user-name" # Replace with your existing ElastiCache user name
}

resource "aws_elasticache_user_group" "example_group" {
  cluster_id = "your-existing-cluster-id" # Replace with your existing ElastiCache cluster ID
  user_group_id = "your-existing-group-id" # Replace with your existing ElastiCache user group ID
  user_group_name = "your-existing-group-name" # Replace with your existing ElastiCache user group name
}

# Associate the user with the group
resource "aws_elasticache_user_group_association" "example_association" {
  cluster_id     = "your-existing-cluster-id" # Replace with your existing ElastiCache cluster ID
  user_group_id  = aws_elasticache_user_group.example_group.user_group_id
  user_id        = aws_elasticache_user.example_user.user_id
}

# Note: The above code assumes you already have the user and group created.
# If you need to create the user and group first, additional resources would be required.
# For example, to create a user and group, you would use the following resources:

# resource "aws_elasticache_user" "new_user" {
