terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_redshift_cluster" "single_node" {
  cluster_identifier = "single-node-redshift-cluster"

  node_type          = "dc2.large" # Single node type for Redshift
  master_username    = "admin"     # Replace with your desired admin username
  master_password    = "YourSecurePassword123!" # Replace with a secure password
  database_name      = "devdb"     # Initial database name

  publicly_accessible = false # Set to true if you need public access (not recommended for production)

  skip_final_snapshot = true # Set to false if you want to create a final snapshot before deletion

  # Optional parameters
  cluster_parameter_group_name = aws_redshift_parameter_group.example.name
  vpc_security_group_ids      = [aws_security_group.redshift_sg.id]
  db_subnet_group_name        = aws_redshift_subnet_group.example.name
}

resource "aws_redshift_parameter_group" "example" {
  name        = "single-node-redshift-pg"
  description = "Parameter group for single node Redshift cluster"

  family = "redshift-1.0" # Adjust based on your Redshift version

  parameter {
    name  = "wlm_json_configuration"
    value = jsonencode({
      "version" : 1,
      "query_concurrency" : 5,
      "result_cache_mode" : "auto",
      "result_cache_max_size" : 10240,
      "result_cache_mode" : "auto",
      "result_cache_max_size" : 10240
    })
  }
}

resource "aws_security_group" "redshift_sg" {
  name        = "redshift-sg"
  description = "Security group for Redshift cluster"
  vpc_id      = aws_vpc.example.id # Replace with your VPC ID or create a VPC

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict this in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_vpc" "example" {
  cidr_block = "10.0.0.0/16"
  enable_dns_support = true
  enable_dns_hostnames = true
  tags = {
    Name = "redshift-vpc"
  }
}

resource "aws_subnet" "private" {
  count             = 2
  vpc_id            = aws_vpc.example.id
  cidr_block        = "10.0.${count.index}.0/24"
  availability_zone = element(data.aws_availability_zones.available.names, count.index)

  tags = {
    Name = "redshift-private-subnet-${count.index}"
  }
}

resource "aws_redshift_subnet_group" "example" {
  name       = "redshift-subnet-group"
  subnet_ids = aws_subnet.private[*].id
}

data "aws_availability_zones" "available" {
  state = "available"
}

