terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_redshift_cluster" "main" {
  cluster_identifier = "my-redshift-cluster"

  database_name      = "mydatabase"
  master_username    = "admin"
  master_password    = "YourSecurePassword123!" # Change to a secure password
  node_type          = "dc2.large" # For 2-node cluster, use dc2.large for each node
  cluster_type       = "multi-node"

  number_of_nodes    = 2

  publicly_accessible = false

  # Enable concurrency scaling with a limit of 60 minutes
  concurrency_scaling {
    enabled = true
    max_concurrency_scaling_spots = 100 # Adjust based on your needs
    max_parallel_query_count      = 8  # Adjust based on your needs
    scaling_increment             = 1  # Number of additional nodes to add
    timeout_minutes               = 60 # Limit concurrency scaling to 60 minutes
  }

  # Optional: Configure VPC settings if needed
  vpc_security_group_ids = ["sg-1234567890abcdef0"] # Replace with your VPC security group IDs

  # Optional: Configure subnet group if needed
  # subnet_group_name = aws_redshift_subnet_group.example.name

  # Optional: Configure parameter group for additional configurations
  parameter_group_name = aws_redshift_parameter_group.example.name

  # Optional: Configure logging
  logging {
    enable_logging = true
    s3_bucket_name  = "your-logging-bucket-name" # Replace with your S3 bucket name
    s3_copy_options {
      encryption_mode = "AES256"
    }
  }
}

resource "aws_redshift_parameter_group" "example" {
  name   = "my-redshift-param-group"
  family = "redshift-1.0" # Adjust family based on your Redshift version

  parameter {
    name  = "wlm_json_configuration"
    value = jsonencode({
      "query_concurrency": {
        "concurrency": 5,
        "timeout": 60
      }
