provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# IAM Role for Redshift to assume when cross-account access is needed
resource "aws_iam_role" "redshift_cross_account_role" {
  name = "redshift-cross-account-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          AWS = "arn:aws:iam::012345678910:root" # Replace with the target account ID
        }
      }
    ]
  })
}

# IAM Policy for Redshift cross-account access
resource "aws_iam_policy" "redshift_cross_account_policy" {
  name        = "redshift-cross-account-policy"
  description = "Policy for Redshift to access resources in another account"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = [
          "redshift:GetClusterCredentials",
          "redshift:DescribeClusters"
        ]
        Resource = "*"
      }
    ]
  })
}

# Attach the policy to the role
resource "aws_iam_role_policy_attachment" "attach_cross_account_policy" {
  role       = aws_iam_role.redshift_cross_account_role.name
  policy_arn = aws_iam_policy.redshift_cross_account_policy.arn
}

# Redshift Cluster
resource "aws_redshift_cluster" "example_cluster" {
  cluster_identifier = "example-redshift-cluster"
  database_name      = "devdb"
  master_username    = "admin"
  master_password    = "YourSecurePassword123!" # Change to a secure password
  node_type          = "dc2.large"
  cluster_type       = "multi-node"
  number_of_nodes    = 2

  publicly_accessible = false
  skip_final_snapshot = true # Set to false if you want to create a final snapshot

  # Enable enhanced VPC routing for private clusters
  vpc_security_group_ids = [aws_security_group.redshift_sg.id]

  # Optional: Configure IAM database authentication
  iam_roles = [aws_iam_role.redshift_cross_account_role.arn]

  # Optional: Configure maintenance window
  maintenance_window = "sun:03:00-sun:05:00"

  # Optional: Configure backup retention period
  automated_snapshot_retention_period = 7
}

# Security Group for Redshift
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-security-group"
  description = "Allow inbound traffic to Redshift cluster"
  vpc_id      = "vpc-12345678" # Replace with your VPC ID

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Replace with your VPC CIDR or allow specific IPs
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Redshift External Schema for cross-account access
resource "aws_redshift_external_schema" "example_external_schema" {
  name        = "external_schema"
  database    = aws_redshift_cluster.example_cluster.database_name
  external_schema_name = "external_schema"
  data_catalog_config {
    region = "us-east-1"
    role_arn = aws_iam_role.redshift_cross_account_role.arn
  }
}

# Redshift External Table (Example)
resource "aws_redshift_external_table" "example_external_table" {
  name        = "external_table"
  database    = aws_redshift_cluster.example_cluster.database_name
  schema      = aws_redshift_external_schema.example_external_schema.name
  external_schema_name = aws_redshift_external_schema.example_external_schema.external_schema_name
  s3_bucket   = "your-s3-bucket-name" # Replace with your S3 bucket
  s3_key_prefix = "path/to/your/data/"
  s3_parquet_compression = "NONE"
  s3_row_format = "PARQUET"
  s3_region = "us-east-1"
}

