  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "redshift-subnet-a"
  }
}

resource "aws_subnet" "redshift_subnet_b" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "redshift-subnet-b"
  }
}

# Internet Gateway
resource "aws_internet_gateway" "redshift_igw" {
  vpc_id = aws_vpc.redshift_vpc.id
  tags = {
    Name = "redshift-igw"
  }
}

# Route Table
resource "aws_route_table" "redshift_route_table" {
  vpc_id = aws_vpc.redshift_vpc.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.redshift_igw.id
  }
  tags = {
    Name = "redshift-route-table"
  }
}

# Route Table Association
resource "aws_route_table_association" "redshift_route_association_a" {
  subnet_id      = aws_subnet.redshift_subnet_a.id
  route_table_id = aws_route_table.redshift_route_table.id
}

resource "aws_route_table_association" "redshift_route_association_b" {
  subnet_id      = aws_subnet.redshift_subnet_b.id
  route_table_id = aws_route_table.redshift_route_table.id
}

# Security Group for Redshift
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-security-group"
  description = "Allow inbound traffic to Redshift"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict to specific IPs in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redshift-sg"
  }
}

# Redshift Cluster (Multi-AZ)
resource "aws_redshift_cluster" "highly_available_cluster" {
  cluster_identifier      = "highly-available-redshift-cluster"
  database_name           = "devdb"
  master_username         = "admin"
  master_password         = "YourSecurePassword123!" # Change this in production!
  node_type               = "dc2.large"
  cluster_type            = "multi-node"
  number_of_nodes         = 2
  publicly_accessible     = false
  vpc_security_group_ids = [aws_security_group.redshift_sg.id]
  subnet_ids              = [aws_subnet.redshift_subnet_a.id, aws_subnet.redshift_subnet_b.id]
  skip_final_snapshot     = true # Disable for production to create snapshots

  # Enable enhanced VPC routing for private connectivity
  vpc_security_group_ids = [aws_security_group.redshift_sg.id]

  # Enable multi-AZ deployment
  availability_zone = "us-east-1a" # Primary AZ
  skip_final_snapshot = true

  tags = {
    Name = "highly-available-redshift-cluster"
  }
}

# Redshift Cluster Parameter Group (Optional: Customize settings)
resource "aws_redshift_parameter_group" "custom_param_group" {
  name   = "custom-redshift-param-group"
  family = "redshift-1.0"

  parameter {
    name  = "wlm_json_configuration"
    value = '{"query_concurrency": 5}'
  }
}

# Associate Parameter Group with Cluster (Optional)
resource "aws_redshift_cluster_parameter_group_association" "param_association" {
  cluster_parameter_group_name = aws_redshift_parameter_group.custom_param_group.name
  cluster_identifier           = aws_redshift_cluster.highly_available_cluster.cluster_identifier
}
