provider "aws" {
  region = "us-east-1" # Change this to your preferred region
}

# IAM Role for Redshift
resource "aws_iam_role" "redshift_role" {
  name = "redshift-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "redshift.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for Redshift
resource "aws_iam_policy" "redshift_policy" {
  name        = "redshift-cluster-policy"
  description = "Policy for Redshift cluster permissions"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = [
          "s3:GetObject",
          "s3:ListBucket",
          "s3:PutObject",
          "s3:DeleteObject"
        ]
        Resource = [
          "arn:aws:s3:::your-bucket-name/*",
          "arn:aws:s3:::your-bucket-name"
        ]
      },
      {
        Effect   = "Allow"
        Action   = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents",
          "logs:DescribeLogStreams"
        ]
        Resource = "arn:aws:logs:*:*:*"
      }
    ]
  })
}

# Attach IAM Policy to IAM Role
resource "aws_iam_role_policy_attachment" "redshift_policy_attach" {
  role       = aws_iam_role.redshift_role.name
  policy_arn = aws_iam_policy.redshift_policy.arn
}

# Redshift Cluster
resource "aws_redshift_cluster" "example" {
  cluster_identifier = "example-cluster"
  database_name      = "dev"
  master_username    = "admin"
  master_password    = "YourSecurePassword123!" # Change this to a secure password
  node_type          = "dc2.large"
  cluster_type       = "single-node"

  iam_roles = [
    aws_iam_role.redshift_role.arn
  ]

  skip_final_snapshot = true # Set to false to create snapshots before deletion

  # Optional: Configure logging
  logging {
    bucket_arn    = "arn:aws:s3:::your-log-bucket-name" # Change this to your S3 bucket ARN
    s3_key_prefix = "redshift-logs"
    enable        = true
  }
}

