provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_lambda_function" "dynamodb_trigger_lambda" {
  function_name = "dynamodb-trigger-lambda"
  runtime       = "python3.9" # Change to your preferred runtime
  handler       = "lambda_function.lambda_handler"
  role          = aws_iam_role.lambda_exec.arn
  filename      = "lambda_function.zip" # Path to your Lambda deployment package

  environment {
    variables = {
      TABLE_NAME = "your-dynamodb-table-name" # Replace with your DynamoDB table name
    }
  }
}

resource "aws_iam_role" "lambda_exec" {
  name = "lambda_dynamodb_exec_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Effect = "Allow",
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_exec.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

resource "aws_iam_role_policy" "dynamodb_access" {
  name = "dynamodb_access_policy"
  role = aws_iam_role.lambda_exec.id

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "dynamodb:GetRecords",
          "dynamodb:GetShardIterator",
          "dynamodb:DescribeStream",
          "dynamodb:ListStreams"
        ],
        Resource = "arn:aws:dynamodb:${var.region}:${data.aws_caller_identity.current.account_id}:table/${var.table_name}/stream/*"
      },
      {
        Effect = "Allow",
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ],
        Resource = "*"
      }
    ]
  })
}

resource "aws_lambda_event_source_mapping" "dynamodb_stream" {
  event_source_arn  = "arn:aws:dynamodb:${var.region}:${data.aws_caller_identity.current.account_id}:table/${var.table_name}/stream/2018-05-29T00:00:00.000" # Replace with your table stream ARN
  function_name      = aws_lambda_function.dynamodb_trigger_lambda.arn
  starting_position  = "LATEST" # Options: "LATEST" or "TRIM_HORIZON"
  batch_size         = 100      # Adjust based on your needs
  maximum_batching_window_in_seconds = 300 # Adjust based on your needs
}

data "aws_caller_identity" "current" {}

variable "region" {
  description = "AWS region"
  type        = string
  default     = "us-east-1"
}

variable "table_name" {
  description = "Name of the DynamoDB table"
  type        = string
  default     = "your-dynamodb-table-name" # Replace with your DynamoDB table name
}

