  layer_name          = "lambda-layer-${var.environment_suffix}"
  description         = "Lambda Layer for shared dependencies"
  compatible_runtimes = var.compatible_runtimes
  filename            = "lambda_layer_payload.zip"
  source_code_hash    = filebase64sha256("lambda_layer_payload.zip")

  tags = {
    Environment = var.environment_suffix
    ManagedBy   = "Terraform"
  }
}

variable "environment_suffix" {
  description = "Environment suffix (e.g., dev, prod)"
  type        = string
  default     = "dev"
}

variable "compatible_runtimes" {
  description = "List of compatible Lambda runtimes"
  type        = list(string)
  default     = ["python3.8", "python3.9", "nodejs14.x"]
}
```

