provider "aws" {
  region = "us-east-1"  # Change to your preferred region
}

# IAM Role for Lambda
resource "aws_iam_role" "lambda_exec" {
  name = "lambda_exec_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for Lambda
resource "aws_iam_policy" "lambda_policy" {
  name        = "lambda_basic_execution"
  description = "Basic execution policy for Lambda"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ],
        Resource = "*"
      }
    ]
  })
}

# Attach IAM Policy to Role
resource "aws_iam_role_policy_attachment" "lambda_logs" {
  role       = aws_iam_role.lambda_exec.name
  policy_arn = aws_iam_policy.lambda_policy.arn
}

# Lambda Function
resource "aws_lambda_function" "example_lambda" {
  filename      = "lambda_function.zip"  # Replace with your Lambda deployment package
  function_name = "example_lambda_function"
  role          = aws_iam_role.lambda_exec.arn
  handler       = "index.handler"         # Replace with your handler (e.g., "index.handler" for Node.js)
  runtime       = "nodejs18.x"           # Change runtime to match your function (e.g., "python3.9", "nodejs18.x")
  source_code_hash = filebase64sha256("lambda_function.zip")  # Ensure this file exists in the same directory
}

# CloudWatch Event Rule for 15-minute interval
resource "aws_cloudwatch_event_rule" "every_15_minutes" {
  name                = "every-15-minutes"
  description         = "Fires every 15 minutes"
  schedule_expression = "rate(15 minutes)"
}

# CloudWatch Event Target for Lambda
resource "aws_cloudwatch_event_target" "lambda_target" {
  rule      = aws_cloudwatch_event_rule.every_15_minutes.name
  target_id = "lambda_target"
  arn       = aws_lambda_function.example_lambda.arn
}

# Permission for CloudWatch to invoke Lambda
resource "aws_lambda_permission" "allow_cloudwatch" {
  statement_id  = "AllowExecutionFromCloudWatch"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.example_lambda.function_name
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.every_15_minutes.arn
}

