  function_name = "lambda_js_function"
  role          = aws_iam_role.lambda_exec.arn
  handler       = "exports.handler" # Adjust based on your lambda.js exports
  runtime       = "nodejs18.x"      # Adjust runtime if needed (e.g., nodejs14.x, nodejs16.x)

  # For production, uncomment and use an S3 bucket instead of local file:
  # s3_bucket = "your-bucket-name"
  # s3_key    = "path/to/lambda.js"

  source_code_hash = filebase64sha256("lambda.js") # Required for local file updates
  timeout         = 30 # Default timeout in seconds
  memory_size     = 128 # Default memory in MB
}
