provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_cloudwatch_composite_alarm" "example_composite_alarm" {
  alarm_name          = "ExampleCompositeAlarm"
  alarm_description   = "Composite alarm example using multiple alarms"
  evaluation_periods  = 1
  namespace           = "AWS/EC2"
  comparison_operator = "GreaterThanThreshold"
  treat_missing_data = "missing"

  metric_query {
    id          = "m1"
    label       = "CPUUtilization"
    expression  = "STATS_METRIC('AWS/EC2', 'CPUUtilization', 'InstanceId', 'i-1234567890abcdef0', 'Average')"
    return_data = true
  }

  metric_query {
    id          = "m2"
    label       = "NetworkIn"
    expression  = "STATS_METRIC('AWS/EC2', 'NetworkIn', 'InstanceId', 'i-1234567890abcdef0', 'Average')"
    return_data = true
  }

  metric_query {
    id          = "m3"
    label       = "NetworkOut"
    expression  = "STATS_METRIC('AWS/EC2', 'NetworkOut', 'InstanceId', 'i-1234567890abcdef0', 'Average')"
    return_data = true
  }

  alarm_actions = [
    "arn:aws:sns:us-east-1:123456789012:MyTopic" # Replace with your SNS topic ARN
  ]

  ok_actions = [
    "arn:aws:sns:us-east-1:123456789012:MyTopic" # Replace with your SNS topic ARN
  ]

  insufficient_data_actions = [
    "arn:aws:sns:us-east-1:123456789012:MyTopic" # Replace with your SNS topic ARN
  ]

  alarm_description = "Composite alarm triggered when CPUUtilization > 70 OR NetworkIn + NetworkOut > 100"

  metric_query {
    id          = "m4"
    label       = "CombinedNetwork"
    expression  = "STATS_METRIC('AWS/EC2', 'NetworkIn', 'InstanceId', 'i-1234567890abcdef0', 'Average') + STATS_METRIC('AWS/EC2', 'NetworkOut', 'InstanceId', 'i-1234567890abcdef0', 'Average')"
    return_data = true
  }

  metric_query {
    id          = "m5"
    label       = "ThresholdCheck"
    expression  = "IF(STATS_METRIC('AWS/EC2', 'CPUUtilization', 'InstanceId', 'i-1234567890abcdef0', 'Average') > 70, 1, 0) OR IF(STATS_METRIC('AWS/EC2', 'NetworkIn', 'InstanceId', 'i-1234567890abcdef0', 'Average') + STATS_METRIC('AWS/EC2', 'NetworkOut', 'InstanceId', 'i-1234567890abcdef0', 'Average') > 100, 1, 0)"
    return_data = true
  }

  alarm_rule {
    metric {
      id          = "m5"
      return_data = true
    }
    comparison_operator = "GreaterThanThreshold"
    threshold           = 1
    evaluation_periods  = 1
    period              = 300 # 5 minutes
  }
}

