resource "aws_dynamodb_table" "contributor_insights_table" {
  name           = "contributor-insights-table" # Replace with your desired table name
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "PK" # Partition key (customize as needed)

  attribute {
    name = "PK"
    type = "S" # String type (adjust based on your PK type)
  }

  attribute {
    name = "SK"
    type = "S" # Sort key (optional, adjust based on needs)
  }

  # Enable Contributor Insights
  contributor_insights {
    enabled = true

    # Custom settings for Contributor Insights
    point_in_time_recovery {
      enabled = true
    }

    # Optional: Customize the retention period (default is 30 days)
    retention_period = 365 # Set to desired retention in days (1-365)
  }

  tags = {
    Name        = "ContributorInsightsTable"
    Environment = "Production" # Adjust as needed
  }
}

# Optional: IAM Policy for Contributor Insights access (attach to relevant roles)
resource "aws_iam_policy" "contributor_insights_policy" {
  name        = "contributor-insights-access-policy"
  description = "Policy for Contributor Insights access on DynamoDB"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = [
          "dynamodb:DescribeTable",
          "dynamodb:ListTables",
          "dynamodb:GetContributorInsights",
          "dynamodb:PutContributorInsights"
        ]
        Resource = aws_dynamodb_table.contributor_insights_table.arn
      }
    ]
  })
}

