provider "aws" {
  region = "us-west-1"
  alias  = "us-west-2"
}

provider "aws" {
  region = "us-west-2"
  alias  = "us-west-3"
}

resource "aws_dynamodb_table" "global_table" {
  name           = "global_table"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "id"

  attribute {
    name = "id"
    type = "S"
  }

  # Replicate the table to us-west-1 and us-west-2
  global_table {
    replication_group {
      region_name = "us-west-1"
      region_endpoint {
        endpoint = "dynamodb.us-west-1.amazonaws.com"
      }
    }
    replication_group {
      region_name = "us-west-2"
      region_endpoint {
        endpoint = "dynamodb.us-west-2.amazonaws.com"
      }
    }
  }
}

