      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_dynamodb_table" "streaming_destination_table" {
  name           = "MyStreamingDestinationTable" # Change to your desired table name
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "id" # Change to your hash key attribute

  attribute {
    name = "id"
    type = "S"
  }

  stream_specification {
    stream_enabled = true
    stream_view_type = "NEW_AND_OLD_IMAGES" # Adjust based on your needs
  }
}

resource "aws_kinesis_stream" "dynamodb_stream" {
  name             = "dynamodb-table-stream" # Change to your desired stream name
  shard_count      = 1 # Adjust based on expected throughput
  retention_period = 24 # Hours (default: 24)
}

resource "aws_kinesis_firehose_delivery_stream" "dynamodb_to_kinesis" {
  name        = "dynamodb-to-kinesis-delivery-stream" # Change to your desired stream name
  destination = "extended_s3" # For Kinesis Data Firehose to S3 (adjust if needed)

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.firehose_bucket.arn
    prefix     = "dynamodb-streams/" # Change as needed
    buffering_hints {
      size_in_mb   = 5
      interval_in_seconds = 300
    }
  }

  kinesis_stream_source_configuration {
    kinesis_stream_arn = aws_kinesis_stream.dynamodb_stream.arn
    role_arn           = aws_iam_role.firehose_role.arn
  }
}

resource "aws_s3_bucket" "firehose_bucket" {
  bucket = "dynamodb-firehose-bucket-${random_id.bucket_suffix.hex}" # Unique bucket name
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

resource "aws_iam_role" "firehose_role" {
  name = "firehose_dynamodb_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "firehose_s3_access" {
  role       = aws_iam_role.firehose_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3FullAccess"
}

resource "aws_iam_role_policy_attachment" "firehose_kinesis_access" {
  role       = aws_iam_role.firehose_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonKinesisFullAccess"
}

resource "aws_dynamodb_table_item_stream" "stream" {
  table_arn = aws_dynamodb_table.streaming_destination_table.arn
  destination {
    type = "KINESIS_STREAM"
    kinesis_stream_arn = aws_kinesis_stream.dynamodb_stream.arn
  }
}

