---
**Note:** The above code is a simplified example. In practice, you should:
1. Replace `us-east-1` and `eu-west-1` with your desired regions.
2. Use `terraform import` to import an existing global table and its replicas.
3. Ensure proper IAM permissions for DynamoDB operations.
4. Adjust attributes (`PK`, `SK`) to match your schema.

For a real-world setup, use the `aws_dynamodb_global_table` resource with the correct `replication_group` blocks for all regions. The example above is a simplified version for demonstration. Here's a corrected version:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

resource "aws_dynamodb_table" "global_table" {
  name           = "GlobalTableExample"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "PK"
  range_key      = "SK"

  attribute {
    name = "PK"
    type = "S"
  }

  attribute {
    name = "SK"
    type = "S"
  }

  global_table_settings {
    replication_group {
      region_name = "us-east-1"
    }
  }
}

resource "aws_dynamodb_global_table" "global_table_replication" {
  name = aws_dynamodb_table.global_table.name

  global_table_settings {
    replication_group {
      region_name = "us-east-1"
    }
  }

  global_table_settings {
    replication_group {
      region_name = "eu-west-1"
    }
  }

  depends_on = [aws_dynamodb_table.global_table]
}
```

