extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# IAM Role for SageMaker
resource "aws_iam_role" "sagemaker_role" {
  name = "sagemaker-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for SageMaker
resource "aws_iam_policy" "sagemaker_policy" {
  name        = "sagemaker-execution-policy"
  description = "Policy for SageMaker execution"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:ListBucket"
        ],
        Resource = [
          "arn:aws:s3:::your-model-bucket-name/*",
          "arn:aws:s3:::your-model-bucket-name"
        ]
      },
      {
        Effect = "Allow",
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents",
          "logs:DescribeLogStreams"
        ],
        Resource = ["arn:aws:logs:*:*:*"]
      }
    ]
  })
}

# Attach IAM Policy to Role
resource "aws_iam_role_policy_attachment" "sagemaker_attachment" {
  role       = aws_iam_role.sagemaker_role.name
  policy_arn = aws_iam_policy.sagemaker_policy.arn
}

# SageMaker Model
resource "aws_sagemaker_model" "example_model" {
  name               = "example-model"
  execution_role_arn = aws_iam_role.sagemaker_role.arn

  primary_container {
    image_uri         = "your-container-image-uri" # e.g., "763104351884.dkr.ecr.us-east-1.amazonaws.com/pytorch-inference:1.8.1-gpu-py38-cu110-ubuntu20.04"
    model_data_url    = "s3://your-model-bucket-name/path/to/model.tar.gz"
    environment = {
      SAGEMAKER_PROGRAM = "inference.py" # Your inference script
      SAGEMAKER_SUBMIT_DIRECTORY = "s3://your-model-bucket-name/path/to/code/"
    }
  }
}

# SageMaker Endpoint Configuration
resource "aws_sagemaker_endpoint_configuration" "example_config" {
  name = "example-endpoint-config"

  production_variants {
    variant_name           = "AllTraffic"
    model_name             = aws_sagemaker_model.example_model.name
    initial_instance_count = 1
    instance_type          = "ml.m5.large" # Adjust based on your model requirements
    initial_variant_weight = 1.0
  }

  async_inference_config {
    output_config {
      s3_output_path = "s3://your-model-bucket-name/output/"
    }
  }
}

# SageMaker Endpoint
resource "aws_sagemaker_endpoint" "example_endpoint" {
  name               = "example-endpoint"
  endpoint_config_name = aws_sagemaker_endpoint_configuration.example_config.name
}

# Output the endpoint name
