resource "aws_instance" "amazon_linux_2" {
  ami                    = "ami-0c55b159cbfafe1f0" # Latest Amazon Linux 2 AMI (as of Terraform 1.0+; verify latest via AWS CLI or API)
  instance_type          = "m5.2xlarge" # 2 vCPUs and 8 GiB memory (adjust based on your core/thread requirements)
  instance_market_options {
    market_type = "spot"
    spot_options {
      instance_interruption_behavior = "terminate"
      spot_instance_type             = "one-time"
    }
  }

  # Configure CPU settings (note: AWS EC2 does not expose direct core/thread settings; instance_type defines this)
  # For 2 vCPUs with 2 threads per core (total 4 threads), use m5.2xlarge or similar
  # If you need custom CPU options, consider AWS Dedicated Hosts or Bare Metal instances

  # Optional: User data to install latest Amazon Linux 2
  user_data = <<-EOF
              #!/bin/bash
              yum update -y
              yum install -y amazon-linux-extras
              amazon-linux-extras install -y lts
              EOF

  tags = {
    Name = "AmazonLinux2-CustomCPU"
  }
}

