    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "instance-sg"
  }
}

# Get the latest Amazon Linux 2 AMI ID
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }
}

# EC2 Instances
resource "aws_instance" "instance_a" {
  ami                    = data.aws_ami.amazon_linux_2.id
  instance_type          = "t2.micro"
  subnet_id              = aws_subnet.subnet_a.id
  vpc_security_group_ids = [aws_security_group.instance_sg.id]
  availability_zone      = "us-east-1a"
  tags = {
    Name = "al2-instance-us-east-1a"
  }
}

resource "aws_instance" "instance_b" {
  ami                    = data.aws_ami.amazon_linux_2.id
  instance_type          = "t2.micro"
  subnet_id              = aws_subnet.subnet_b.id
  vpc_security_group_ids = [aws_security_group.instance_sg.id]
  availability_zone      = "us-east-1b"
  tags = {
    Name = "al2-instance-us-east-1b"
  }
}

# EBS Volumes
resource "aws_ebs_volume" "volume_a" {
  availability_zone = "us-east-1a"
  size              = 50
  tags = {
    Name = "ebs-volume-us-east-1a"
  }
}

resource "aws_ebs_volume" "volume_b" {
  availability_zone = "us-east-1b"
  size              = 50
  tags = {
    Name = "ebs-volume-us-east-1b"
  }
}

# Attach EBS Volumes to Instances
resource "aws_volume_attachment" "attach_a" {
  device_name = "/dev/sdh"
  volume_id   = aws_ebs_volume.volume_a.id
  instance_id = aws_instance.instance_a.id
}

resource "aws_volume_attachment" "attach_b" {
  device_name = "/dev/sdh"
  volume_id   = aws_ebs_volume.volume_b.id
  instance_id = aws_instance.instance_b.id
}
