  tags = {
    Name = "efs-sg"
  }
}

# EFS File System
resource "aws_efs_file_system" "shared_efs" {
  creation_token = "shared-efs"
  encrypted      = true
  tags = {
    Name = "shared-efs"
  }
}

# EFS Mount Targets
resource "aws_efs_mount_target" "mount_target_1" {
  file_system_id  = aws_efs_file_system.shared_efs.id
  subnet_id       = aws_subnet.private_1.id
  security_groups = [aws_security_group.efs_sg.id]
}

resource "aws_efs_mount_target" "mount_target_2" {
  file_system_id  = aws_efs_file_system.shared_efs.id
  subnet_id       = aws_subnet.private_2.id
  security_groups = [aws_security_group.efs_sg.id]
}

# Latest Amazon Linux 2 AMI
data "aws_ami" "amazon_linux" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }
}

# EC2 Instance 1
resource "aws_instance" "ec2_instance_1" {
  ami                    = data.aws_ami.amazon_linux.id
  instance_type          = "t3.medium"
  subnet_id              = aws_subnet.private_1.id
  vpc_security_group_ids = [aws_security_group.ec2_sg.id]
  iam_instance_profile   = aws_iam_instance_profile.ec2_profile.name
  key_name               = "your-key-pair-name" # Replace with your key pair name
  user_data              = <<-EOF
                              #!/bin/bash
                              sudo yum update -y
                              sudo yum install -y amazon-efs-utils
                              sudo mkdir -p /mnt/efs
                              sudo mount -t efs ${aws_efs_file_system.shared_efs.dns_name}:/ /mnt/efs
                              echo "${aws_efs_file_system.shared_efs.dns_name}:/ /mnt/efs nfs4 nfsvers=4.1,rsize=1048576,wsize=1048576,hard,timeo=600,retrans=2,noresvport" | sudo tee -a /etc/fstab
                              sudo chown -R ec2-user:ec2-user /mnt/efs
                              EOF
  tags = {
    Name = "ec2-instance-1"
  }
}

# EC2 Instance 2
resource "aws_instance" "ec2_instance_2" {
  ami                    = data.aws_ami.amazon_linux.id
  instance_type          = "t3.medium"
  subnet_id              = aws_subnet.private_2.id
  vpc_security_group_ids = [aws_security_group.ec2_sg.id]
  iam_instance_profile   = aws_iam_instance_profile.ec2_profile.name
  key_name               = "your-key-pair-name" # Replace with your key pair name
  user_data              = <<-EOF
                              #!/bin/bash
                              sudo yum update -y
                              sudo yum install -y amazon-efs-utils
                              sudo mkdir -p /mnt/efs
                              sudo mount -t efs ${aws_efs_file_system.shared_efs.dns_name}:/ /mnt/efs
                              echo "${aws_efs_file_system.shared_efs.dns_name}:/ /mnt/efs nfs4 nfsvers=4.1,rsize=1048576,wsize=1048576,hard,timeo=600,retrans=2,noresvport" | sudo tee -a /etc/fstab
                              sudo chown -R ec2-user:ec2-user /mnt/efs
                              EOF
  tags = {
    Name = "ec2-instance-2"
  }
}

# IAM Role and Instance Profile for EC2
resource "aws_iam_role" "ec2_role" {
  name = "ec2_efs_role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "ec2_ssm_policy" {
  role       = aws_iam_role.ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSSMManagedInstanceCore"
}

resource "aws_iam_instance_profile" "ec2_profile" {
  name = "ec2_efs_profile"
  role = aws_iam_role.ec2_role.name
}
```

