# Using AWS DynamoDB with Global Secondary Index (GSI) to reduce database calls
resource "aws_dynamodb_table" "optimized_table" {
  name           = "OptimizedDataTable"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "id"

  attribute {
    name = "id"
    type = "S"
  }

  # Global Secondary Index (GSI) to enable querying by alternative attributes
  global_secondary_index {
    name            = "QueryIndex"
    hash_key        = "category"
    projection_type = "INCLUDE"
    non_key_attributes = ["timestamp"]
    range_key        = "sort_key"
  }

  # Local Secondary Index (LSI) for range queries on the same partition
  local_secondary_index {
    name            = "LSIIndex"
    range_key       = "timestamp"
    projection_type = "ALL"
  }

  # Enable point-in-time recovery (PITR) for backup purposes
  point_in_time_recovery {
    enabled = true
  }

  tags = {
    Name        = "OptimizedDataTable"
    Environment = "Production"
  }
}

# Using AWS ElastiCache Redis for caching frequently accessed data
resource "aws_elasticache_cluster" "redis_cache" {
  cluster_id           = "optimized-data-cache"
  engine               = "redis"
  node_type            = "cache.t3.micro"
  num_cache_nodes      = 1
  parameter_group_name = "default.redis7"
  engine_version       = "7.0"
  port                 = 6379

  tags = {
    Name        = "OptimizedDataCache"
    Environment = "Production"
  }
}

# Using AWS Lambda with DynamoDB Streams to process data in real-time
resource "aws_lambda_function" "dynamodb_stream_processor" {
  function_name = "dynamodb-stream-processor"
  role          = aws_iam_role.lambda_exec.arn
  handler       = "index.handler"
  runtime       = "nodejs18.x"
  filename      = "lambda_function.zip"

  environment {
    variables = {
      TABLE_NAME = aws_dynamodb_table.optimized_table.name
    }
  }

  depends_on = [aws_iam_role_policy_attachment.lambda_dynamodb]
}

# IAM Role for Lambda to interact with DynamoDB
resource "aws_iam_role" "lambda_exec" {
  name = "lambda_dynamodb_exec_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_dynamodb" {
  role       = aws_iam_role.lambda_exec.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonDynamoDBFullAccess"
}

# DynamoDB Stream for Lambda to process changes
resource "aws_dynamodb_table" "optimized_table_stream" {
  name           = "OptimizedDataTableStream"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "id"
  stream_enabled = true
  stream_view_type = "NEW_AND_OLD_IMAGES"

  attribute {
    name = "id"
    type = "S"
  }

  tags = {
    Name        = "OptimizedDataTableStream"
    Environment = "Production"
  }
}

# AWS Lambda Permission to access DynamoDB Stream
resource "aws_lambda_permission" "allow_dynamodb_stream" {
  statement_id  = "AllowExecutionFromDynamoDB"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.dynamodb_stream_processor.function_name
  principal     = "dynamodb.amazonaws.com"
  source_arn    = aws_dynamodb_table.optimized_table_stream.stream_arn
}

