provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create an IAM policy for Redis authentication
resource "aws_iam_policy" "redis_auth_policy" {
  name        = "RedisAuthPolicy"
  description = "Policy for authenticating with Redis using IAM"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = [
          "elasticache:Authenticate",
          "elasticache:DescribeCacheClusters"
        ]
        Resource = "*"
      }
    ]
  })
}

# Create an IAM user for Redis authentication
resource "aws_iam_user" "redis_auth_user" {
  name = "redis-auth-user"
}

# Attach the policy to the IAM user
resource "aws_iam_user_policy_attachment" "redis_auth_attachment" {
  user       = aws_iam_user.redis_auth_user.name
  policy_arn = aws_iam_policy.redis_auth_policy.arn
}

# Generate access keys for the IAM user
resource "aws_iam_access_key" "redis_auth_key" {
  user = aws_iam_user.redis_auth_user.name
}

# Create an ElastiCache Redis cluster
resource "aws_elasticache_cluster" "redis_cluster" {
  cluster_id           = "redis-cluster"
  engine               = "redis"
  node_type            = "cache.t3.micro"
  num_cache_nodes      = 1
  parameter_group_name = "default.redis7"
  engine_version       = "7.0"
  port                 = 6379
  skip_final_snapshot  = true
}

# Output the Redis endpoint and authentication details
output "redis_endpoint" {
  value = aws_elasticache_cluster.redis_cluster.cache_nodes[0].address
}

output "redis_port" {
  value = aws_elasticache_cluster.redis_cluster.port
}

output "redis_auth_user" {
  value     = aws_iam_user.redis_auth_user.name
  sensitive = true
}

output "redis_auth_password" {
  value     = aws_iam_access_key.redis_auth_key.secret
  sensitive = true
}

# Note: To authenticate with Redis using IAM, you need to configure Redis to use IAM authentication.
# This typically involves setting up Redis Auth Tokens and associating them with IAM users.
# The following is an example of how you might configure Redis to use IAM authentication.
# This part is not automated by Terraform and must be done manually or via Redis CLI.

# Example Redis CLI commands to enable IAM authentication (run on Redis server):
# 1. Create a Redis Auth Token:
# redis-cli --raw --eval /path/to/iam-auth-token-script.sh
# 2. Configure Redis to use IAM authentication (in redis.conf or via CLI):
# auth-required yes
# requirepass <your-generated-password>
# iam-auth-token <your-generated-token>

