provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# IAM Policy for Elasticache authentication
resource "aws_iam_policy" "elasticache_auth_policy" {
  name        = "ElastiCacheAuthPolicy"
  description = "Policy to allow authentication with ElastiCache"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "elasticache:Authenticate",
          "elasticache:DescribeCacheClusters",
          "elasticache:GetCacheClusterAuditEvents"
        ]
        Resource = "*"
      }
    ]
  })
}

# IAM User for Elasticache authentication
resource "aws_iam_user" "elasticache_user" {
  name = "elasticache-auth-user"
}

# Attach the policy to the IAM user
resource "aws_iam_user_policy_attachment" "elasticache_user_policy_attachment" {
  user       = aws_iam_user.elasticache_user.name
  policy_arn = aws_iam_policy.elasticache_auth_policy.arn
}

# Generate and output the access key for the IAM user
resource "aws_iam_access_key" "elasticache_user_access_key" {
  user = aws_iam_user.elasticache_user.name
}

output "elasticache_user_access_key_id" {
  value     = aws_iam_access_key.elasticache_user_access_key.id
  sensitive = true
}

output "elasticache_user_secret_access_key" {
  value     = aws_iam_access_key.elasticache_user_access_key.secret
  sensitive = true
}

# Optional: Generate a user policy document for ElastiCache authentication
resource "aws_elasticache_parameter_group" "auth_param_group" {
  name        = "auth-param-group"
  description = "Parameter group for ElastiCache authentication"

  family      = "redis6"

  dynamic "parameter" {
    for_each = {
      "auth_enabled" = 1,
      "requirepass"  = "your_redis_password_here" # Replace with your Redis password
    }
    content {
      name  = parameter.key
      value = parameter.value
    }
  }
}

