terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_dynamodb_table" "dax_cluster" {
  name           = "dax-cluster"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "id"

  attribute {
    name = "id"
    type = "S"
  }

  server_side_encryption {
    enabled     = true
  }

  point_in_time_recovery {
    enabled = true
  }
}

resource "aws_dax_cluster" "main" {
  cluster_name    = "dax-cluster"
  node_type       = "dax.r4.large"
  replication_factor = 1
  iam_role_arn    = aws_iam_role.dax_role.arn

  parameter_group_name = aws_dax_parameter_group.main.name
  security_group_ids   = [aws_security_group.dax_sg.id]
  subnet_group_name    = aws_dax_subnet_group.main.name
}

resource "aws_dax_parameter_group" "main" {
  name      = "dax-parameter-group"
  family    = "dax1"

  parameter {
    name  = "cluster_enabled"
    value = "true"
  }
}

resource "aws_dax_subnet_group" "main" {
  name       = "dax-subnet-group"
  subnet_ids = [aws_subnet.dax_subnet_1.id, aws_subnet.dax_subnet_2.id] # Replace with your subnet IDs

  maintenance_window = "sun:05:00-sun:09:00"
}

resource "aws_subnet" "dax_subnet_1" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "dax-subnet-1"
  }
}

resource "aws_subnet" "dax_subnet_2" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "dax-subnet-2"
  }
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "dax-vpc"
  }
}

resource "aws_security_group" "dax_sg" {
  name        = "dax-sg"
  description = "Allow DAX traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 8111
    to_port     = 8111
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "dax-sg"
  }
}

resource "aws_iam_role" "dax_role" {
  name = "dax-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dax.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "dax_policy" {
  role       = aws_iam_role.dax_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonDynamoDBFullAccess"
}

