resource "aws_msk_cluster" "example" {
  cluster_name           = "my-msk-cluster"
  kafka_version          = "3.4.0" # Check for the latest supported version
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.m5.large" # Adjust based on your needs
    volume_size     = 100              # Adjust based on your needs
    storage_info {
      ebs_storage_info {
        volume_type = "gp3"
      }
    }
