      "subnet-12345678", # Replace with your subnet IDs
      "subnet-87654321", # Replace with your subnet IDs
      "subnet-abcdef01"  # Replace with your subnet IDs
    ]
    security_groups = [
      "sg-12345678" # Replace with your security group IDs
    ]
  }

  configuration_info {
    arn      = "arn:aws:kafka:us-east-1:123456789012:cluster/kafka-configuration/ExampleConfig-12345678901234567890" # Replace with your configuration ARN
    revision = 1
  }

  encryption_info {
    encryption_in_transit {
      client_broker = "TLS_PLAINTEXT" # Change to "TLS" for production
    }
  }

  tags = {
    Environment = "Production"
  }
}

resource "aws_security_group" "msk_sg" {
  name        = "msk-cluster-sg"
  description = "Security group for MSK cluster"
