extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# S3 Bucket for MSK cluster logs
resource "aws_s3_bucket" "msk_logs_bucket" {
  bucket = "msk-cluster-logs-${random_id.bucket_suffix.hex}"
  force_destroy = true

  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

# IAM Role for MSK cluster
resource "aws_iam_role" "msk_cluster_role" {
  name = "msk-cluster-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "msk.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for S3 access
resource "aws_iam_policy" "msk_s3_logging_policy" {
  name        = "msk-s3-logging-policy"
  description = "Policy for MSK cluster to write logs to S3"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:ListBucket"
        ],
        Resource = [
          aws_s3_bucket.msk_logs_bucket.arn,
          "${aws_s3_bucket.msk_logs_bucket.arn}/*"
        ]
      }
    ]
  })
}

# Attach policy to role
resource "aws_iam_role_policy_attachment" "msk_s3_logging_attachment" {
  role       = aws_iam_role.msk_cluster_role.name
  policy_arn = aws_iam_policy.msk_s3_logging_policy.arn
}

# MSK Cluster
resource "aws_msk_cluster" "example" {
  name            = "msk-cluster-example"
  kafka_version   = "3.4.0" # Use latest stable version as needed
  cluster_type    = "PROD"

  broker_node_group_info {
    client_subnets = ["subnet-12345678", "subnet-87654321"] # Replace with your subnets
    instance_type  = "kafka.m5.large"
    security_groups = [aws_security_group.msk_cluster_sg.id]
    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  configuration_info {
    arn      = "arn:aws:msk:us-east-1:123456789012:cluster/kafka-2-8-1" # Replace with your config ARN
    revision = 1
  }

  encryption_info {
    encryption_in_transit {
      client_broker_encryption_in_transit = "TLS"
    }
    encryption_at_rest {
      kms_key_arn = aws_kms_key.msk_encryption_key.arn
    }
  }

  logging_info {
    broker_logs {
      s3 {
        bucket = aws_s3_bucket.msk_logs_bucket.bucket
        prefix = "kafka-logs"
      }
      log_type = "STDOUT"
    }
    consumer_logs {
      s3 {
        bucket = aws_s3_bucket.msk_logs_bucket.bucket
        prefix = "consumer-logs"
      }
      log_type = "STDOUT"
    }
    topic_logs {
      s3 {
        bucket = aws_s3_bucket.msk_logs_bucket.bucket
        prefix = "topic-logs"
      }
      log_type = "STDOUT"
    }
  }

  tags = {
    Environment = "Production"
  }
}

# KMS Key for encryption
resource "aws_kms_key" "msk_encryption_key" {
  description             = "KMS key for MSK cluster encryption"
  deletion_window_in_days = 30
}

# Security Group for MSK cluster
resource "aws_security_group" "msk_cluster_sg" {
  name        = "msk-cluster-sg"
  description = "Security group for MSK cluster"
  vpc_id      = "vpc-12345678" # Replace with your VPC ID

  ingress {
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict as needed
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Outputs
output "msk_cluster_arn" {
  value = aws_msk_cluster.example.arn
}

output "s3_bucket_name" {
  value = aws_s3_bucket.msk_logs_bucket.bucket
}

