  name        = "msk-cluster-encryption-example"
  destination = "extended_s3" # MSK doesn't directly use Firehose, but this is a placeholder for demonstration

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_s3_role.arn
    bucket_arn = aws_s3_bucket.msks3bucket.arn
    prefix     = "msk-data/"
