provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_msk_cluster" "kafka_cluster" {
  cluster_name           = "kafka-cluster-with-exporters"
  kafka_version          = "3.4.0" # Use a supported version
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type        = "kafka.m5.large"
    client_subnets      = ["subnet-12345678", "subnet-87654321"] # Replace with your subnet IDs
    security_groups      = ["sg-12345678"] # Replace with your security group ID
    imds_support        = "ENABLED"
    storage_info {
      ebs_storage_info {
        volume_size = 100
        volume_type = "gp3"
      }
    }
  }

  configuration_info {
    arn      = "arn:aws:kafka:${var.region}:${data.aws_caller_identity.current.account_id}:cluster/kafka/cluster-policy/basic" # Replace with your configuration ARN
    name     = "kafka-configuration"
  }

  encryption_info {
    encryption_in_transit {
      client_broker = "TLS_PLAINTEXT" # Change to "TLS_PLAINTEXT", "TLS_PLAINTEXT_WITH_AUTHENTICATION", or "TLS_PLAINTEXT_WITH_MUTUAL_AUTHENTICATION" as needed
    }
    encryption_in_transit_client_broker = "TLS_PLAINTEXT"
  }

  tags = {
    Environment = "dev"
    Terraform   = "true"
  }

  # Enable JMX Exporter
  kafka_exporter {
    jmx_exporter {
      enabled_in_broker = true
    }
  }

  # Enable Node Exporter
  kafka_exporter {
    node_exporter {
      enabled_in_broker = true
    }
  }

  # Optional: Configure logging
  logging_info {
    broker_log_topic_enabled_in_cluster = true
    topic_policy_arn                      = "arn:aws:kafka:${var.region}:${data.aws_caller_identity.current.account_id}:cluster/kafka/cluster-policy/basic"
    log_retention_in_days                = 7
  }
}

data "aws_caller_identity" "current" {}

# Output the cluster ARN for reference
output "kafka_cluster_arn" {
  value = aws_msk_cluster.kafka_cluster.arn
}

# Output the broker information
output "broker_info" {
  value = aws_msk_cluster.kafka_cluster.broker_node_group_info[0].brokers
}

