```hcl
terraform {
  required_providers {
    google = {
      source  = "hashicorp/google"
      version = "~> 4.0"
    }
  }
}

provider "google" {
  project = var.project_id
  region  = "us-east1"
}

variable "project_id" {
  description = "The GCP project ID"
  type        = string
}

variable "cluster_name" {
  description = "The name of the MSK cluster"
  type        = string
  default     = "msk-cluster"
}

variable "num_partitions" {
  description = "The number of partitions per topic"
  type        = number
  default     = 3
}

variable "replication_factor" {
  description = "The replication factor for the topics"
  type        = number
  default     = 3
}

resource "google_pubsub_topic" "msk_topic" {
  name = "${var.cluster_name}-topic"
}

resource "google_pubsub_subscription" "msk_subscription" {
  name  = "${var.cluster_name}-subscription"
  topic = google_pubsub_topic.msk_topic.name
}

resource "google_cloud_run_service" "msk_connector" {
  name     = "${var.cluster_name}-connector"
  location = "us-east1"

  template {
    spec {
      containers {
        image = "gcr.io/cloud-connector/kafka-connector:latest"
        env {
          name  = "KAFKA_BOOTSTRAP_SERVERS"
          value = "your-msk-broker-address:9092" # Replace with your MSK broker address
        }
        env {
          name  = "KAFKA_TOPIC"
          value = google_pubsub_topic.msk_topic.name
        }
        env {
          name  = "KAFKA_PARTITIONS"
          value = var.num_partitions
        }
        env {
          name  = "KAFKA_REPLICATION_FACTOR"
          value = var.replication_factor
        }
      }
    }
  }
}

resource "google_kafka_topic" "msk_topic_resource" {
  name     = "${var.cluster_name}-topic"
  cluster  = google_kafka_cluster.msk_cluster.name
  partition_count = var.num_partitions
  replication_factor = var.replication_factor
}

resource "google_kafka_cluster" "msk_cluster" {
  name     = var.cluster_name
  location = "us-east1-a"

  config {
    kafka_config_rules {
      jmx_port = 9997
      num_partitions = var.num_partitions
      replication_factor = var.replication_factor
    }
  }

  kafka_config_rules {
    jmx_port = 9997
  }

  retention_ms = 604800000 # 7 days in milliseconds
  num_partitions = var.num_partitions
  replication_factor = var.replication_factor
}

resource "google_kafka_broker" "msk_broker" {
  cluster = google_kafka_cluster.msk_cluster.name
  location = "us-east1-a"
  count = 3 # Example count, adjust based on your replication factor
}

output "msk_broker_address" {
  value = google_kafka_broker.msk_broker[*].address
}

output "msk_topic_name" {
  value = google_kafka_topic.msk_topic_resource.name
}
```

