terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_msk_cluster" "serverless_msk" {
  cluster_name           = "serverless-msk-cluster"
  kafka_version          = "3.4.0" # Specify your desired Kafka version
  number_of_broker_nodes = 3       # Fixed number of broker nodes (serverless MSK doesn't support dynamic scaling like provisioned MSK)

  serverless {
    application_type = "SINGLE_INSTANCE" # Serverless MSK is single-instance by default
    broker_node_group_info {
      client_authentication = "NONE" # Change as needed (PLAINTEXT, IAM, etc.)
      storage_info {
        ebs_storage_info {
          volume_size = 100 # Size in GB (minimum 100GB for serverless MSK)
        }
      }
    }
  }

  encryption_info {
    encryption_in_transit {
      client_broker = "TLS"
    }
    encryption_in_rest {
      kms_keys = []
      # Uncomment and add KMS key ARN if you want encryption at rest
      # kms_keys = [aws_kms_key.example.arn]
    }
  }

  tags = {
    Environment = "Production"
    Terraform   = "true"
  }
}

# Optional: KMS Key for encryption at rest (uncomment if needed)
