terraform {
  required_providers {
    google = {
      source  = "hashicorp/google"
      version = "~> 4.0"
    }
  }
}

provider "google" {
  project = var.project_id
  region  = "us-east1"
}

resource "google_pubsub_topic" "msk_events" {
  name = "msk-events-topic"
}

resource "google_cloudkms_crypto_key" "msk_key" {
  name            = "msk-encryption-key"
  key_ring_id     = google_kms_key_ring.msks.key_ring_id
  purpose         = "ENCRYPT_DECRYPT"
  rotation_period = "100000s" # Never rotate
}

resource "google_kms_key_ring" "msks" {
  name     = "msks-keyring"
  location = "us-east1"
}

resource "google_cloudkms_crypto_key_iam_binding" "msk_key_iam" {
  crypto_key_id = google_cloudkms_crypto_key.msks.id
  role          = "roles/cloudkms.cryptoKeyEncrypterDecrypter"
  members       = ["serviceAccount:${google_service_account.msks.email}"]
}

resource "google_service_account" "msks" {
  account_id   = "msks-service-account"
  display_name = "MSK Service Account"
}

resource "google_project_iam_member" "msks_pubsub" {
  project = var.project_id
  role    = "roles/pubsub.publisher"
  member  = "serviceAccount:${google_service_account.msks.email}"
}

resource "google_project_iam_member" "msks_kms" {
  project = var.project_id
  role    = "roles/cloudkms.cryptoKeyEncrypterDecrypter"
  member  = "serviceAccount:${google_service_account.msks.email}"
}

resource "google_cloudkms_crypto_key_iam_binding" "msks_kms" {
  crypto_key_id = google_cloudkms_crypto_key.msks.id
  role          = "roles/cloudkms.cryptoKeyEncrypterDecrypter"
  members       = ["serviceAccount:${google_service_account.msks.email}"]
}

resource "google_pubsub_subscription" "msk_events_sub" {
  name  = "msk-events-sub"
  topic = google_pubsub_topic.msks_events.name
  ack_deadline_seconds = 300
}

resource "google_msk_cluster" "msk_cluster" {
  name         = "msk-cluster"
  kafka_version = "2.8.1" # Check for latest supported version
  config {
    kafka {
      version = "2.8.1"
      logging {
        broker_log_segment_bytes = 1073741824
        broker_log_segment_ms    = 600000
        controller_log_segment_bytes = 1073741824
        controller_log_segment_ms    = 600000
        log_retention_hours = 168
      }
      authorization {
        type = "CLIENT_CERTIFICATE"
      }
    }
  }
  node_config {
    machine_type = "n2-standard-4"
    disk_size_gb = 100
    disk_type    = "PERSISTENT"
    disk_iops    = 300
  }
  broker_config {
    software_version = "2.8.1"
    zone             = "us-east1-b"
  }
  encryption_config {
    encryption_at_rest_config {
      kms_key_name = google_cloudkms_crypto_key.msks.id
    }
  }
  retention_policy {
    hours = 168
  }
  broker_filter {
    zone = "us-east1-b"
  }
  broker_filter {
    zone = "us-east1-c"
  }
  broker_filter {
    zone = "us-east1-d"
  }
  depends_on = [
    google_cloudkms_crypto_key.msks,
    google_service_account.msks,
    google_project_iam_member.msks_pubsub,
    google_project_iam_member.msks_kms
  ]
}

variable "project_id" {
  description = "The GCP project ID"
  type        = string
}

