  kafka_version = "2.8.1" # Check for latest supported version
  config {
    kafka {
      version = "2.8.1"
      logging {
        broker_log_segment_bytes = 1073741824
        broker_log_segment_ms    = 600000
        controller_log_segment_bytes = 1073741824
        controller_log_segment_ms    = 600000
        log_retention_hours = 168
      }
      authorization {
        type = "CLIENT_CERTIFICATE"
      }
    }
  }
  node_config {
    machine_type = "n2-standard-4"
    disk_size_gb = 100
    disk_type    = "PERSISTENT"
    disk_iops    = 300
  }
  broker_config {
    software_version = "2.8.1"
    zone             = "us-east1-b"
  }
  encryption_config {
    encryption_at_rest_config {
      kms_key_name = google_cloudkms_crypto_key.msks.id
    }
  }
  retention_policy {
    hours = 168
  }
  broker_filter {
    zone = "us-east1-b"
  }
  broker_filter {
    zone = "us-east1-c"
  }
  broker_filter {
    zone = "us-east1-d"
  }
  depends_on = [
    google_cloudkms_crypto_key.msks,
    google_service_account.msks,
    google_project_iam_member.msks_pubsub,
    google_project_iam_member.msks_kms
  ]
}

