}

# IAM Role for Firehose S3 Delivery
resource "aws_iam_role" "firehose_s3_role" {
  name = "firehose-s3-delivery-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Effect = "Allow",
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "firehose_s3_policy" {
  role       = aws_iam_role.firehose_s3_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3FullAccess"
}

# MSK Cluster
resource "aws_msk_cluster" "msk_cluster" {
  cluster_name           = "msk-cluster"
  kafka_version          = "3.4.0" # Check for latest supported version
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    client_subnets  = ["subnet-12345678", "subnet-87654321", "subnet-abcdef12"] # Replace with your subnets
    security_groups = [aws_security_group.msk_sg.id]
  }

  configuration_info {
    arn      = data.aws_msk_configuration.msk_config.arn
    revision = data.aws_msk_configuration.msk_config.latest_revision
  }

  encryption_info {
    encryption_in_transit {
      client_broker_encryption_in_transit = "TLS"
    }
    encryption_at_rest {
      kms_keys = [aws_kms_key.msk_key.arn]
    }
  }

  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_log_group.name
      }
    }
  }

  tags = {
    Environment = "production"
  }
}

# KMS Key for MSK Encryption at Rest
resource "aws_kms_key" "msk_key" {
  description             = "KMS Key for MSK Encryption at Rest"
  deletion_window_in_days = 30
  policy                  = data.aws_iam_policy_document.kms_policy.json
}

data "aws_iam_policy_document" "kms_policy" {
  statement {
    sid    = "Enable IAM User Permissions"
    effect = "Allow"
    principals {
      type        = "AWS"
      identifiers = ["arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"]
    }
    actions   = ["kms:*"]
    resources = ["*"]
  }
}

# Security Group for MSK
resource "aws_security_group" "msk_sg" {
  name        = "msk-security-group"
  description = "Security group for MSK cluster"

  ingress {
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict to your VPC CIDR in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Open Monitoring Configuration
resource "aws_msk_configuration" "msk_config" {
  name          = "msk-configuration"
  kafka_versions = ["3.4.0"]
  configuration = filebase64("configs/kafka-server.properties") # Ensure this file exists with your Kafka config
}

# CloudWatch Alarm for MSK Broker Health
resource "aws_cloudwatch_metric_alarm" "msk_broker_health" {
  alarm_name          = "msk-broker-health-alarm"
  comparison_operator = "GreaterThanThreshold"
  evaluation_periods  = "1"
  metric_name         = "BrokerHealthy"
  namespace           = "AWS/MSK"
  period              = "60"
  statistic           = "Average"
  threshold           = "0"
  alarm_description   = "Alarm when MSK broker health drops below expected"
  alarm_actions       = [aws_sns_topic.msk_alerts.arn]

  dimensions = {
    ClusterArn = aws_msk_cluster.msk_cluster.arn
  }
}

# SNS Topic for Alerts
resource "aws_sns_topic" "msk_alerts" {
  name = "msk-alerts-topic"
}

# Data Sources
data "aws_caller_identity" "current" {}
data "aws_msk_configuration" "msk_config" {
  latest = true
}
```

