      aws_subnet.msk_subnet_3.id
    ]
    instance_type   = "kafka.m5.large"
    security_groups = [aws_security_group.msk_sg.id]
    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  configuration_info {
    arn      = data.aws_msk_configuration.msk_config.arn
    revision = data.aws_msk_configuration.msk_config.latest_revision
  }

  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk_key.arn
  }

  tags = {
    Environment = "dev"
  }
}

# Get default MSK configuration
data "aws_msk_configuration" "msk_config" {
  name = "latest"
}

# Create KMS Key for MSK
resource "aws_kms_key" "msk_key" {
  description             = "KMS key for MSK encryption"
  deletion_window_in_days = 30
  enable_key_rotation     = true
}

# Create MSK Connect Custom Plugin
resource "aws_mskconnect_custom_plugin" "debezium_plugin" {
  name = "debezium-custom-plugin"
  content_type = "ZIP"
  location {
    s3 {
      bucket_arn = aws_s3_bucket.debezium_plugin_bucket.arn
      file_key   = "debezium.zip"
    }
  }
}

# Create S3 Bucket for Custom Plugin
resource "aws_s3_bucket" "debezium_plugin_bucket" {
  bucket = "debezium-plugin-bucket-${random_id.bucket_suffix.hex}"
}

resource "random_id" "bucket_suffix" {
  byte_length = 4
}

# Upload the debezium.zip to S3
resource "aws_s3_bucket_object" "debezium_plugin" {
  bucket = aws_s3_bucket.debezium_plugin_bucket.id
  key    = "debezium.zip"
  source = "path/to/your/debezium.zip" # Replace with actual path to your debezium.zip file
}

# Create MSK Connect Worker
resource "aws_mskconnect_worker" "debezium_worker" {
  name = "debezium-worker"
  worker_group {
    worker_group_info {
      broker_arns = [aws_msk_cluster.msk_cluster.arn]
      security_groups = [aws_security_group.msk_sg.id]
      service_execution_role_arn = aws_iam_role.msk_connect_role.arn
    }
    log_delivery {
      cloudwatch_logs {
        cloudwatch_logs_role_arn = aws_iam_role.msk_connect_logs_role.arn
        log_delivery_configuration_name = "debezium-log-delivery"
      }
    }
  }
}

# Create MSK Connect Connector
resource "aws_mskconnect_connector" "debezium_connector" {
  name = "debezium-connector"
  kafka_cluster_client_authentication {
    authentication_type = "NONE"
  }
  kafka_cluster {
    apache_kafka_cluster {
      bootstrap_servers = aws_msk_cluster.msk_cluster.bootstrap_brokers_sasl_iam
      vpc {
        security_groups = [aws_security_group.msk_sg.id]
      }
    }
  }
  connector_configuration = {
    "connector.class" = "io.debezium.connector.mysql.MySqlConnector"
    "tasks.max" = "1"
    "database.hostname" = "your-database-host"
    "database.port" = "3306"
    "database.user" = "your-database-user"
    "database.password" = "your-database-password"
    "database.server.id" = "123"
    "database.server.name" = "your-database-server"
    "database.include.list" = "your-database-name"
  }
  custom_plugin {
    id = aws_mskconnect_custom_plugin.debezium_plugin.id
  }
  mskconnect_worker {
    id = aws_mskconnect_worker.debezium_worker.id
  }
}

# IAM Role for MSK Connect
resource "aws_iam_role" "msk_connect_role" {
  name = "msk-connect-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "mskconnect.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "msk_connect_s3_access" {
  role       = aws_iam_role.msk_connect_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3ReadOnlyAccess"
}

resource "aws_iam_role_policy_attachment" "msk_connect_cloudwatch" {
  role       = aws_iam_role.msk_connect_role.name
  policy_arn = "arn:aws:iam::aws:policy/CloudWatchLogsFullAccess"
}

# IAM Role for MSK Connect Logs
resource "aws_iam_role" "msk_connect_logs_role" {
  name = "msk-connect-logs-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "logs.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "msk_connect_logs_policy" {
  role       = aws_iam_role.msk_connect_logs_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSMSKConnectLogsDeliveryRolePolicy"
}
