terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# S3 Bucket for MSK Connect plugin
resource "aws_s3_bucket" "msk_connect_plugin" {
  bucket = "msk-connect-plugin-bucket-${random_id.bucket_suffix.hex}"
}

resource "random_id" "bucket_suffix" {
  byte_length = 4
}

# IAM Role for MSK Connect
resource "aws_iam_role" "msk_connect_role" {
  name = "msk-connect-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kafka.connect.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for MSK Connect
resource "aws_iam_policy" "msk_connect_policy" {
  name        = "msk-connect-policy"
  description = "Policy for MSK Connect"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.msk_connect_plugin.arn,
          "${aws_s3_bucket.msk_connect_plugin.arn}/*"
        ]
      },
      {
        Effect   = "Allow"
        Action   = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents",
          "logs:DescribeLogStreams"
        ]
        Resource = "*"
      },
      {
        Effect   = "Allow"
        Action   = [
          "firehose:*"
        ]
        Resource = "*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "msk_connect_attach" {
  role       = aws_iam_role.msk_connect_role.name
  policy_arn = aws_iam_policy.msk_connect_policy.arn
}

# Upload custom plugin to S3
resource "aws_s3_object" "debezium_plugin" {
  bucket = aws_s3_bucket.msk_connect_plugin.bucket
  key    = "debezium.zip"
  source = "path/to/local/debezium.zip" # Update this path
  etag   = filemd5("path/to/local/debezium.zip") # Update this path
}

# CloudWatch Log Group for MSK
resource "aws_cloudwatch_log_group" "msk_log_group" {
  name              = "/aws/kafka/cluster/${aws_msk_cluster.msk_cluster.cluster_name}"
  retention_in_days = 7
}

# Kinesis Firehose Delivery Stream
resource "aws_kinesisfirehose_delivery_stream" "msk_firehose" {
  name        = "msk-to-firehose-stream"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_s3.arn
    bucket_arn = aws_s3_bucket.firehose_bucket.arn
    prefix     = "msk-data/"
    buffering_hints {
      size_in_mb   = 5
      interval_in_seconds = 300
    }
  }
}

resource "aws_s3_bucket" "firehose_bucket" {
  bucket = "msk-firehose-bucket-${random_id.firehose_bucket_suffix.hex}"
}

resource "random_id" "firehose_bucket_suffix" {
  byte_length = 4
}

resource "aws_iam_role" "firehose_s3" {
  name = "firehose-s3-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose_s3_policy" {
  name = "firehose-s3-policy"
  role = aws_iam_role.firehose_s3.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.firehose_bucket.arn,
          "${aws_s3_bucket.firehose_bucket.arn}/*"
        ]
      }
    ]
  })
}

# MSK Cluster
resource "aws_msk_cluster" "msk_cluster" {
  cluster_name           = "my-msk-cluster"
  kafka_version          = "3.4.0"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.t3.2xlarge"
    client_subnets  = ["subnet-12345678", "subnet-87654321"] # Replace with your subnets
    security_groups = [aws_security_group.msk_sg.id]
  }

  configuration_info {
    arn      = data.aws_msk_configuration.msk_config.arn
    revision = data.aws_msk_configuration.msk_config.revision
  }

  encryption_info {
    encryption_in_transit {
      client_broker = "TLS"
    }
    encryption_at_rest {
      kms_key_arn = aws_kms_key.msk_key.arn
    }
  }

  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_log_group.name
      }
    }
    consumer_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_log_group.name
      }
    }
    controller_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_log_group.name
      }
    }
    offline_logs {
      s3 {
        bucket_mappings = [
          {
            log_directory = "msk-offline-logs"
            s3_bucket_arn = aws_s3_bucket.msk_logs_bucket.arn
          }
        ]
      }
    }
  }

  open_monitoring {
    prometheus {
      jmx_exporter {
        enabled_in_broker = true
      }
    }
  }
}

resource "aws_security_group" "msk_sg" {
  name        = "msk-sg"
  description = "Security group for MSK cluster"

  ingress {
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_kms_key" "msk_key" {
  description             = "KMS key for MSK encryption at rest"
  deletion_window_in_days = 30
}

resource "aws_kms_alias" "msk_key_alias" {
  name          = "alias/msk-key"
  target_key_id = aws_kms_key.msk_key.key_id
}

resource "aws_s3_bucket" "msk_logs_bucket" {
  bucket = "msk-logs-bucket-${random_id.logs_bucket_suffix.hex}"
}

resource "random_id" "logs_bucket_suffix" {
  byte_length = 4
}

# Data Source for MSK Configuration
data "aws_msk_configuration" "msk_config" {
  arn = "arn:aws:kafka:${var.region}:aws:cluster/client-v3.4.0" # Update version if needed
}

# MSK Connect Custom Plugin
resource "aws_mskconnect_custom_plugin" "debezium_plugin" {
  name           = "debezium-custom-plugin"
  content        = filebase64("path/to/local/debezium.zip") # Update this path
  location {
    s3 {
      bucket_arn = aws_s3_bucket.msk_connect_plugin.arn
      file_key   = "debezium.zip"
    }
  }
}

# MSK Connect Connector
resource "aws_mskconnect_connector" "debezium_connector" {
  name           = "debezium-connector"
  kafka_cluster {
    kafka_cluster_arn = aws_msk_cluster.msk_cluster.arn
    vpc {
      security_groups = [aws_security_group.msk_sg.id]
      subnets         = ["subnet-12345678", "subnet-87654321"] # Replace with your subnets
    }
  }
  kafka_cluster_client_authentication {
    authentication_type = "NONE"
  }
  kafka_cluster_encryption_in_transit {
    encryption_type = "TLS"
  }
  kafka_cluster_ssl_configuration {
    authentication_type = "TLS"
  }
  connector_configuration = {
    "connector.class" = "io.debezium.connector.mysql.MySqlConnector"
    "tasks.max"       = "1"
    "database.hostname" = "your-database-host" # Replace with your database host
    "database.port"    = "3306"
    "database.user"    = "your-database-user" # Replace with your database user
    "database.password" = "your-database-password" # Replace with your database password
    "database.server.id" = "1"
    "database.server.name" = "debezium-database"
    "database.include.list" = "your-database-name" # Replace with your database name
    "transforms" = "unwrap"
    "transforms.unwrap.type" = "io.debezium.transforms.ExtractNewRecordState"
  }
  plugin_configuration = {
    "CustomPluginConfiguration" = jsonencode({
      "S3BucketArn" = aws_s3_bucket.msk_connect_plugin.arn,
      "S3KeyPrefix" = "plugins/debezium"
    })
  }
  capacity = {
    auto_scale = {
      min_worker_count = 2
      max_worker_count = 4
    }
  }
  log_delivery {
    cloudwatch_logs {
      enabled   = true
      log_group = aws_cloudwatch_log_group.msk_log_group.name
    }
    s3 {
      enabled = true
      bucket_arn = aws_s3_bucket.msk_connect_plugin.arn
      prefix     = "connect-logs"
    }
    firehose {
      enabled = true
      delivery_stream_arn = aws_kinesisfirehose_delivery_stream.msk_firehose.arn
    }
  }
  service_execution_role_arn = aws_iam_role.msk_connect_role.arn
}
