provider "google" {
  project = var.project_id
  region  = var.region
}

variable "project_id" {
  description = "The GCP project ID"
  type        = string
}

variable "region" {
  description = "The GCP region where the cluster will be created"
  type        = string
  default     = "us-central1"
}

variable "zones" {
  description = "The GCP zones where the cluster will be deployed"
  type        = list(string)
  default     = ["us-central1-a", "us-central1-b", "us-central1-c"]
}

resource "google_sql_database_instance" "mysql_cluster" {
  name             = "mysql-cluster-${random_id.suffix.hex}"
  database_version = "MYSQL_8_0"
  region           = var.region

  settings {
    tier = "db-custom-1-3840" # 1 vCPU, 3840 GB RAM (adjust as needed for 100GB per zone)

    backup_configuration {
      enabled    = true
      binary_log_enabled = true
      start_time = "03:00"
    }

    ip_configuration {
      ipv4_enabled    = true
      authorized_networks {
        name  = "allowed_network"
        value = "0.0.0.0/0" # Replace with your network restrictions
      }
    }

    replication_configuration {
      replica_name = "replica-${random_id.suffix.hex}"
    }
  }

  deletion_protection = false
}

resource "google_sql_database" "mysql_database" {
  name     = "main_database"
  instance = google_sql_database_instance.mysql_cluster.name
}

resource "random_id" "suffix" {
  byte_length = 4
}

# Cloud SQL Proxy for external connections (optional)
resource "google_compute_instance" "mysql_proxy" {
  count = 1
  name         = "mysql-proxy-${random_id.suffix.hex}"
  machine_type = "e2-medium"
  zone         = var.zones[count.index % length(var.zones)]

  boot_disk {
    initialize_params {
      image = "cos-cloud/cos-stable"
      size  = 10
    }
  }

  network_interface {
    network = "default"
    access_config {
      # Ephemeral public IP
    }
  }

  metadata_startup_script = <<-EOT
    #!/bin/bash
    curl -sS https://dl.google.com/cloudsql/cloud_sql_proxy.linux.amd64 \n      -o /usr/local/bin/cloud_sql_proxy
    chmod +x /usr/local/bin/cloud_sql_proxy
    sudo apt-get install -y google-cloud-sql-proxy
    sudo systemctl enable cloud_sql_proxy
    sudo systemctl start cloud_sql_proxy
    EOT

  metadata = {
    gce-cloud-sql-instances = "${google_sql_database_instance.mysql_cluster.name}=tcp:3306"
  }
}

# Cloud SQL Instance Flags (optional)
resource "google_sql_database_instance" "mysql_flags" {
  name             = google_sql_database_instance.mysql_cluster.name
  database_version = google_sql_database_instance.mysql_cluster.database_version
  region           = google_sql_database_instance.mysql_cluster.region

  settings {
    tier = google_sql_database_instance.mysql_cluster.settings.tier

    ip_configuration {
      ipv4_enabled    = google_sql_database_instance.mysql_cluster.settings.ip_configuration.ipv4_enabled
      authorized_networks = google_sql_database_instance.mysql_cluster.settings.ip_configuration.authorized_networks
    }

    backup_configuration {
      enabled    = google_sql_database_instance.mysql_cluster.settings.backup_configuration.enabled
      binary_log_enabled = google_sql_database_instance.mysql_cluster.settings.backup_configuration.binary_log_enabled
      start_time = google_sql_database_instance.mysql_cluster.settings.backup_configuration.start_time
    }

    replication_configuration {
      replica_name = google_sql_database_instance.mysql_cluster.settings.replication_configuration.replica_name
    }

    # Add flags for 100GB per zone (adjust as needed)
    mysql_5_7_settings {
      innodb_buffer_pool_size = "70080M" # ~70GB per zone (adjust based on actual zone count)
    }
  }
}

