provider "aws" {
  region = "us-east-1"
}

resource "aws_db_instance" "mysql_cluster" {
  allocated_storage      = 100
  engine                 = "mysql"
  engine_version         = "8.0"
  instance_class         = "db.m5.large"
  db_name                = "mydatabase"
  username               = "admin"
  password               = "your_secure_password_here" # Change this to a secure password or use AWS Secrets Manager
  skip_final_snapshot    = true
  multi_az               = true
  storage_encrypted      = true
  backup_retention_period = 7
  copy_tags_to_snapshot  = true
  parameter_group_name   = "default.mysql8.0"
  vpc_security_group_ids = [aws_security_group.mysql_cluster_sg.id]
  db_subnet_group_name   = aws_db_subnet_group.mysql_cluster.name
  publicly_accessible    = false
  storage_type           = "gp2"
  tags = {
    Name = "mysql-cluster"
  }
}

resource "aws_security_group" "mysql_cluster_sg" {
  name        = "mysql-cluster-sg"
  description = "Security group for MySQL cluster"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Adjust this CIDR block as per your VPC requirements
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "mysql-cluster-sg"
  }
}

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "main-vpc"
  }
}

resource "aws_subnet" "mysql_cluster_subnets" {
  count                   = 3
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.${count.index}.0/24"
  availability_zone       = element(["us-east-1a", "us-east-1b", "us-east-1c"], count.index)
  map_public_ip_on_launch = false
  tags = {
    Name = "mysql-cluster-subnet-${count.index}"
  }
}

resource "aws_db_subnet_group" "mysql_cluster" {
  name       = "mysql-cluster-subnet-group"
  subnet_ids = aws_subnet.mysql_cluster_subnets[*].id
  tags = {
    Name = "mysql-cluster-subnet-group"
  }
}

