    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_dynamodb_table" "example_table" {
  name           = "ExampleTable"
  billing_mode   = "PAY_PER_REQUEST" # or "PROVISIONED" with `read_capacity` and `write_capacity`
  hash_key       = "id"

  attribute {
    name = "id"
    type = "S" # String type
  }

  # Optional: Add additional attributes if composite key is needed
  # range_key = "sort_key"
  #
  # attribute {
  #   name = "sort_key"
  #   type = "N" # Number type (or "S", "B", etc.)
  # }

  # Optional: Enable global secondary indexes if needed
  # global_secondary_index {
  #   name            = "ExampleGSI"
  #   hash_key        = "gsi_id"
  #   range_key       = "gsi_sort_key"
  #   projection_type = "INCLUDE" # or "KEYS_ONLY", "ALL"
  #
  #   attribute {
  #     name = "gsi_id"
  #     type = "S"
  #   }
  #
  #   attribute {
  #     name = "gsi_sort_key"
  #     type = "N"
  #   }
  # }

  # Optional: Enable stream for DynamoDB Streams
  stream_enabled   = false
  stream_view_type = "NEW_AND_OLD_IMAGES" # Options: NEW_IMAGE, OLD_IMAGE, NEW_AND_OLD_IMAGES

  # Optional: Enable point-in-time recovery
  point_in_time_recovery {
    enabled = false
  }

  tags = {
    Environment = "dev" # Change as needed
    Terraform   = "true"
  }
}
```

