resource "aws_dax_cluster" "example" {
  cluster_name    = "example-dax-cluster"
  description     = "DAX cluster for caching DynamoDB"
  node_type       = "dax.r4.large" # Adjust node type based on your needs
  replication_group_id = aws_dax_replication_group.example.id
  parameter_group_name = aws_dax_parameter_group.example.name
  iam_role_arn     = aws_iam_role.dax_role.arn
  tags = {
    Name = "example-dax-cluster"
  }
}

resource "aws_dax_replication_group" "example" {
  replication_group_id = "example-dax-replication-group"
  node_type           = "dax.r4.large"
  description         = "DAX replication group for caching DynamoDB"
  multi_az            = true
  parameter_group_name = aws_dax_parameter_group.example.name
  tags = {
    Name = "example-dax-replication-group"
  }
}

resource "aws_dax_parameter_group" "example" {
  name      = "example-dax-parameter-group"
  family    = "dax6"
  description = "DAX parameter group for caching DynamoDB"
  parameters = {
    "cluster_enabled" = "true"
    "engine_version"  = "6.2"
    "max_shards"      = "10"
    "min_shards"      = "1"
    "shard_count"     = "1"
  }
}

resource "aws_iam_role" "dax_role" {
  name = "dax-cluster-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dax.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "dax_amazon_dax_policy" {
  role       = aws_iam_role.dax_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonDaxFullAccess"
}

