resource "aws_dynamodb_table" "point_in_time_recovery" {
  name           = "my-dynamodb-table"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "id"

  attribute {
    name = "id"
    type = "S"
  }

  point_in_time_recovery_specification {
    point_in_time_recovery_enabled = true
  }

  # Optional: Enable encryption at rest
  server_side_encryption {
    enabled     = true
    kms_key_arn = "arn:aws:kms:REGION:ACCOUNT_ID:key/KEY_ID" # Replace with your KMS key ARN
  }

  # Optional: Enable backup
  backup {
    point_in_time_recovery_spec {
      continuous_backups = true
    }
  }
}

