# Configure a custom Time to Live (TTL) for CloudFront cache using AWS example
# This example sets a TTL for both default and origin responses

resource "aws_cloudfront_cache_policy" "custom_ttl_policy" {
  name        = "custom-ttl-policy-${var.environment}"
  default_ttl = 3600 # 1 hour default TTL
  max_ttl     = 86400 # 24 hours maximum TTL
  min_ttl     = 600  # 10 minutes minimum TTL

  parameters_in_cache_key {
    enable_accept_ranges = true
    query_strings {
      cache_key_specification = "all"
    }
    cookies_config {
      cookie_behavior = "none"
    }
  }
}

resource "aws_cloudfront_distribution" "example" {
  origin {
    domain_name = aws_s3_bucket.example.bucket_regional_domain_name
    origin_id   = "S3-${aws_s3_bucket.example.bucket}"

    s3_origin_config {
      origin_access_identity = aws_cloudfront_origin_access_identity.example.cloudfront_access_identity_path
    }
  }

  enabled             = true
  is_ipv6_enabled     = true
  default_root_object = "index.html"

  aliases = ["${var.domain_name}"]

  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "S3-${aws_s3_bucket.example.bucket}"

    forwarded_values {
      query_string = true
      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "redirect-to-https"
    cache_policy_id        = aws_cloudfront_cache_policy.custom_ttl_policy.id
    min_ttl                = 600
    default_ttl            = 3600
    max_ttl                = 86400
  }

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }
}

