provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "main-vpc"
  }
}

# Create Internet Gateway
resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.main.id
  tags = {
    Name = "main-igw"
  }
}

# Create Subnet
resource "aws_subnet" "public" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a" # Change to your preferred AZ
  tags = {
    Name = "public-subnet"
  }
}

# Create Network ACL
resource "aws_network_acl" "public_nacl" {
  vpc_id = aws_vpc.main.id
  subnet_ids = [aws_subnet.public.id]

  # Inbound rules
  dynamic "entry" {
    for_each = [
      {
        rule_no    = 100
        protocol   = "6" # TCP
        rule_action = "allow"
        egress     = false
        cidr_block = "0.0.0.0/0"
        from_port  = 80
        to_port    = 80
      },
      {
        rule_no    = 110
        protocol   = "6" # TCP
        rule_action = "allow"
        egress     = false
        cidr_block = "0.0.0.0/0"
        from_port  = 443
        to_port    = 443
      },
      {
        rule_no    = 120
        protocol   = "6" # TCP
        rule_action = "allow"
        egress     = false
        cidr_block = "0.0.0.0/0"
        from_port  = 22
        to_port    = 22
      },
      {
        rule_no    = 1000
        protocol   = "-1" # All protocols
        rule_action = "allow"
        egress     = false
        cidr_block = aws_vpc.main.cidr_block
        from_port  = 0
        to_port    = 0
      }
    ]

    content {
      rule_no    = entry.value.rule_no
      protocol   = entry.value.protocol
      rule_action = entry.value.rule_action
      egress     = entry.value.egress
      cidr_block = entry.value.cidr_block
      from_port  = lookup(entry.value, "from_port", 0)
      to_port    = lookup(entry.value, "to_port", 0)
    }
  }

  # Outbound rules
  dynamic "entry" {
    for_each = [
      {
        rule_no    = 100
        protocol   = "-1" # All protocols
        rule_action = "allow"
        egress     = true
        cidr_block = "0.0.0.0/0"
        from_port  = 0
        to_port    = 0
      }
    ]

    content {
      rule_no    = entry.value.rule_no
      protocol   = entry.value.protocol
      rule_action = entry.value.rule_action
      egress     = entry.value.egress
      cidr_block = entry.value.cidr_block
      from_port  = lookup(entry.value, "from_port", 0)
      to_port    = lookup(entry.value, "to_port", 0)
    }
  }

  tags = {
    Name = "public-nacl"
  }
}

# Associate Network ACL with Subnet
resource "aws_vpc_network_acl_association" "public_nacl_association" {
  network_acl_id = aws_network_acl.public_nacl.id
  subnet_id      = aws_subnet.public.id
}

