provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create a VPC for the Neptune cluster
resource "aws_vpc" "neptune_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "Neptune-VPC"
  }
}

# Create an Internet Gateway for the VPC
resource "aws_internet_gateway" "neptune_igw" {
  vpc_id = aws_vpc.neptune_vpc.id
  tags = {
    Name = "Neptune-IGW"
  }
}

# Create a Route Table for the VPC
resource "aws_route_table" "neptune_route_table" {
  vpc_id = aws_vpc.neptune_vpc.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.neptune_igw.id
  }
  tags = {
    Name = "Neptune-Route-Table"
  }
}

# Create a Neptune Subnet Group
resource "aws_neptune_subnet_group" "neptune_subnet_group" {
  name        = "neptune-subnet-group"
  subnet_ids  = [
    aws_subnet.neptune_subnet_1.id,
    aws_subnet.neptune_subnet_2.id
  ]
  subnet_azs  = ["us-east-1a", "us-east-1b"] # Adjust AZs as needed
  tags = {
    Name = "Neptune-Subnet-Group"
  }
}

# Create two example subnets for the Neptune cluster
resource "aws_subnet" "neptune_subnet_1" {
  vpc_id            = aws_vpc.neptune_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "Neptune-Subnet-1"
  }
}

resource "aws_subnet" "neptune_subnet_2" {
  vpc_id            = aws_vpc.neptune_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "Neptune-Subnet-2"
  }
}

# Associate the subnets with the route table
resource "aws_route_table_association" "neptune_subnet_association_1" {
  subnet_id      = aws_subnet.neptune_subnet_1.id
  route_table_id = aws_route_table.neptune_route_table.id
}

resource "aws_route_table_association" "neptune_subnet_association_2" {
  subnet_id      = aws_subnet.neptune_subnet_2.id
  route_table_id = aws_route_table.neptune_route_table.id
}

# Enable public IP assignment for the subnets
resource "aws_eip" "neptune_eip_1" {
  domain = "vpc"
  tags = {
    Name = "Neptune-EIP-1"
  }
}

resource "aws_eip" "neptune_eip_2" {
  domain = "vpc"
  tags = {
    Name = "Neptune-EIP-2"
  }
}

resource "aws_nat_gateway" "neptune_nat_gw" {
  allocation_id = aws_eip.neptune_eip_1.id
  subnet_id     = aws_subnet.neptune_subnet_1.id
  tags = {
    Name = "Neptune-NAT-Gateway"
  }
}

resource "aws_route" "neptune_nat_route" {
  route_table_id         = aws_route_table.neptune_route_table.id
  destination_cidr_block = "0.0.0.0/0"
  nat_gateway_id         = aws_nat_gateway.neptune_nat_gw.id
}

# Output the Neptune Subnet Group ID
output "neptune_subnet_group_id" {
  value = aws_neptune_subnet_group.neptune_subnet_group.id
}

