  vpc_id      = "vpc-12345678" # Replace with your VPC ID

  # Allow inbound traffic only from the specified subnets on port 8182 (Neptune default)
  ingress {
    description = "Neptune inbound from example subnets"
    from_port   = 8182
    to_port     = 8182
    protocol    = "tcp"
    cidr_blocks = [
      "subnet-12345678", # Replace with first example subnet ID
      "subnet-87654321"  # Replace with second example subnet ID
    ]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "neptune-restricted-access-sg"
  }
}

# Create the Neptune cluster with the custom parameter group and security group
resource "aws_neptune_cluster" "basic_cluster" {
  cluster_identifier      = "neptune-basic-cluster"
  engine                  = "neptune"
  engine_version          = "8.0" # Adjust based on your Neptune version
  instance_type           = "db.r5.large" # Adjust based on your needs
  preferred_maintenance_window = "sun:05:00-sun:09:00"
  skip_final_snapshot     = true # Set to false if you want final snapshots

  # Apply the custom parameter group
  parameter_group_name = aws_neptune_parameter_group.custom_param_group.name

  # Apply the security group
  vpc_security_group_ids = [aws_security_group.neptune_sg.id]

  # Configure subnet group (replace with your actual subnet IDs)
  subnet_group_name = aws_neptune_subnet_group.neptune_subnet_group.name

  # Enable public access (optional, adjust based on your requirements)
  enable_http_endpoint = true

  tags = {
    Name = "neptune-basic-cluster"
  }
}

# Create a Neptune subnet group for the specified subnets
resource "aws_neptune_subnet_group" "neptune_subnet_group" {
  name       = "neptune-subnet-group"
  subnet_ids = [
    "subnet-12345678", # Replace with first example subnet ID
    "subnet-87654321"  # Replace with second example subnet ID
  ]

  tags = {
    Name = "neptune-subnet-group"
  }
}
