provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create IAM role for Chime Voice Connector
resource "aws_iam_role" "chime_voice_connector_role" {
  name = "chime-voice-connector-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "chime.amazonaws.com"
        }
      }
    ]
  })
}

# Attach necessary IAM policies to the role
resource "aws_iam_role_policy_attachment" "chime_voice_connector_attachment" {
  role       = aws_iam_role.chime_voice_connector_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonChimeVoiceConnectorServiceRolePolicy"
}

# Create first Chime Voice Connector with encryption
resource "aws_chime_voice_connector" "primary_connector" {
  name        = "primary-voice-connector"
  description = "Primary voice connector with encryption"
  media_encryption_settings {
    media_encryption = "ENABLED"
  }
  region = "us-east-1"
  role_arn = aws_iam_role.chime_voice_connector_role.arn
}

# Create second Chime Voice Connector with encryption
resource "aws_chime_voice_connector" "secondary_connector" {
  name        = "secondary-voice-connector"
  description = "Secondary voice connector with encryption"
  media_encryption_settings {
    media_encryption = "ENABLED"
  }
  region = "us-east-1"
  role_arn = aws_iam_role.chime_voice_connector_role.arn
}

# Create Chime Voice Connector Group with prioritized connectors
resource "aws_chime_voice_connector_group" "connector_group" {
  name        = "voice-connector-group"
  description = "Group containing primary and secondary voice connectors"

  voice_connector_arns = [
    aws_chime_voice_connector.primary_connector.arn,
    aws_chime_voice_connector.secondary_connector.arn
  ]

  priority {
    voice_connector_arn = aws_chime_voice_connector.primary_connector.arn
    priority            = 1 # Higher priority (lower number)
  }

  priority {
    voice_connector_arn = aws_chime_voice_connector.secondary_connector.arn
    priority            = 2 # Lower priority (higher number)
  }
}

