terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_chime_voice_connector" "chime_vc" {
  name = "my-chime-voice-connector"

  media_encryption_settings {
    media_encryption_type = "SRTP_AES_256_GCM"
  }

  logging_settings {
    media_metrics_logging_enabled = true
    media_metrics_logging_s3_bucket_arn = aws_s3_bucket.chime_logs.arn
  }

  tags = {
    Name        = "chime-voice-connector"
    Environment = "production"
  }
}

resource "aws_s3_bucket" "chime_logs" {
  bucket = "chime-media-metrics-logs-${random_id.bucket_suffix.hex}"
  force_destroy = true

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }

  versioning {
    enabled = true
  }

  tags = {
    Name        = "chime-media-metrics-logs"
    Environment = "production"
  }
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

resource "aws_s3_bucket_policy" "chime_logs_policy" {
  bucket = aws_s3_bucket.chime_logs.id
  policy = data.aws_iam_policy_document.chime_logs_policy.json
}

data "aws_iam_policy_document" "chime_logs_policy" {
  statement {
    actions   = ["s3:PutObject"]
    resources = ["${aws_s3_bucket.chime_logs.arn}/*"]

    principals {
      type        = "Service"
      identifiers = ["chime.amazonaws.com"]
    }
  }
}

