provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create an SNS topic for notifications
resource "aws_sns_topic" "voice_connector_notifications" {
  name = "voice-connector-notifications"
}

# Create an IAM policy for Chime Voice Connector
resource "aws_iam_policy" "voice_connector_policy" {
  name        = "VoiceConnectorPolicy"
  description = "Policy for Chime Voice Connector"

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:ListBucket"
        ],
        Resource = [
          "arn:aws:s3:::aws-chime-voice-connector-*",
          "arn:aws:s3:::aws-chime-voice-connector-*/*"
        ]
      },
      {
        Effect = "Allow",
        Action = [
          "sns:Publish"
        ],
        Resource = aws_sns_topic.voice_connector_notifications.arn
      }
    ]
  })
}

# Create an IAM role for Chime Voice Connector
resource "aws_iam_role" "voice_connector_role" {
  name = "VoiceConnectorRole"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Effect = "Allow",
        Principal = {
          Service = "chime.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "voice_connector_policy_attachment" {
  role       = aws_iam_role.voice_connector_role.name
  policy_arn = aws_iam_policy.voice_connector_policy.arn
}

# Create a Chime Voice Connector with encryption
resource "aws_chime_voice_connector" "example" {
  name        = "example-voice-connector"
  description = "Voice Connector with encryption and streaming configuration"

  media_storage_s3_bucket_arn = "arn:aws:s3:::aws-chime-voice-connector-${var.region}-${data.aws_caller_identity.current.account_id}"

  # Enable encryption
  encryption_configuration {
    kms_key_arn = aws_kms_key.chime_voice_connector_key.arn
  }

  # Configure streaming
  streaming_configuration {
    retention_period_hours = 5
    sns_topic_arn         = aws_sns_topic.voice_connector_notifications.arn
    kinesis_stream_arn    = "" # Disabled by leaving empty
  }
}

# Create a KMS key for encryption
resource "aws_kms_key" "chime_voice_connector_key" {
  description             = "KMS key for Chime Voice Connector encryption"
  deletion_window_in_days = 30
  enable_key_rotation     = true
}

# Allow Chime to use the KMS key
resource "aws_kms_alias" "chime_voice_connector_key_alias" {
  name          = "alias/chime-voice-connector-key"
  target_key_id = aws_kms_key.chime_voice_connector_key.key_id
}

resource "aws_kms_grant" "chime_voice_connector_grant" {
  name              = "chime-voice-connector-grant"
  grantee_principal = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:role/VoiceConnectorRole"
  operations        = ["Decrypt", "GenerateDataKey"]
  key_id            = aws_kms_key.chime_voice_connector_key.key_id
}

# Retrieve current AWS account ID
data "aws_caller_identity" "current" {}

