provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create an IAM role for the Chime Voice Connector
resource "aws_iam_role" "chime_vc_role" {
  name = "chime-voice-connector-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "chime.amazonaws.com"
        }
      }
    ]
  })
}

# Attach necessary policies to the IAM role
resource "aws_iam_role_policy_attachment" "chime_vc_policy" {
  role       = aws_iam_role.chime_vc_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonChimeVoiceConnectorServicePolicy"
}

# Create a Kinesis Data Stream for media streaming
resource "aws_kinesis_stream" "chime_media_stream" {
  name             = "chime-media-stream"
  shard_count      = 1 # Adjust based on expected throughput
  stream_mode_details {
    type = "PROVISIONED"
  }
}

# Create an IAM policy for Kinesis access
resource "aws_iam_policy" "kinesis_access_policy" {
  name        = "chime-kinesis-access-policy"
  description = "Policy for Chime Voice Connector to write to Kinesis"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = [
          "kinesis:PutRecord",
          "kinesis:PutRecords",
          "kinesis:DescribeStream"
        ]
        Resource = aws_kinesis_stream.chime_media_stream.arn
      }
    ]
  })
}

# Attach the Kinesis policy to the IAM role
