terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create VPC
resource "aws_vpc" "redshift_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "Redshift-VPC"
  }
}

# Create first subnet
resource "aws_subnet" "redshift_subnet_1" {
  vpc_id                  = aws_vpc.redshift_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = true
  tags = {
    Name = "Redshift-Subnet-1"
  }
}

# Create second subnet
resource "aws_subnet" "redshift_subnet_2" {
  vpc_id                  = aws_vpc.redshift_vpc.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-east-1b"
  map_public_ip_on_launch = true
  tags = {
    Name = "Redshift-Subnet-2"
  }
}

# Create Redshift subnet group
resource "aws_redshift_subnet_group" "redshift_subnet_group" {
  name       = "redshift-subnet-group"
  subnet_ids = [aws_subnet.redshift_subnet_1.id, aws_subnet.redshift_subnet_2.id]
  tags = {
    Name = "Redshift-Subnet-Group"
  }
}

# Create Redshift cluster
resource "aws_redshift_cluster" "example_cluster" {
  cluster_identifier      = "example-redshift-cluster"
  database_name           = "dev"
  master_username         = "admin"
  master_password         = "YourSecurePassword123!" # Change this to a secure password
  node_type               = "dc2.large"
  cluster_type            = "single-node"
  publicly_accessible     = true
  skip_final_snapshot     = true
  vpc_security_group_ids  = [aws_security_group.redshift_sg.id] # Add security group if needed
  subnet_group_name       = aws_redshift_subnet_group.redshift_subnet_group.name
  tags = {
    Name = "Example-Redshift-Cluster"
  }
}

# Create security group for Redshift (optional but recommended)
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-security-group"
  description = "Allow inbound traffic to Redshift"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict this in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "Redshift-Security-Group"
  }
}

# Create Redshift cluster endpoint
resource "aws_redshift_endpoint" "example_endpoint" {
  cluster_identifier = aws_redshift_cluster.example_cluster.cluster_identifier
  endpoint_type      = "DATAWAREHOUSE"
  subnet_group_name  = aws_redshift_subnet_group.redshift_subnet_group.name
}

