extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# VPC and Subnets (assuming these already exist, adjust as needed)
data "aws_vpc" "default" {
  default = true
}

data "aws_subnets" "selected" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
  filter {
    name   = "availability-zone"
    values = ["us-east-1a", "us-east-1b"] # Replace with your preferred AZs
  }
}

# IAM Role for Redshift (if not already created)
resource "aws_iam_role" "redshift_role" {
  name = "redshift-cluster-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "redshift.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "redshift_s3_access" {
  role       = aws_iam_role.redshift_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3ReadOnlyAccess"
}

# Security Group for Redshift (restrictive by default)
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-cluster-sg"
  description = "Allow Redshift access from specified subnets"
  vpc_id      = data.aws_vpc.default.id

  # Allow Redshift internal communication (default port 5439)
  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    self        = true
  }

  # Allow SSH (optional, for maintenance)
  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Adjust based on your VPC CIDR
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Redshift Cluster
resource "aws_redshift_cluster" "example" {
  cluster_identifier = "example-cluster"
  database_name      = "devdb"
  master_username    = "admin"
  master_password    = "YourSecurePassword123!" # Change to a secure password
  node_type          = "dc2.large"
  cluster_type       = "single-node" # Change to "multi-node" for larger clusters

  # Network configuration
  vpc_security_group_ids = [aws_security_group.redshift_sg.id]
  subnet_ids             = data.aws_subnets.selected.ids

  # IAM role for Redshift
  iam_roles = [aws_iam_role.redshift_role.arn]

  # Publicly accessible (adjust if you want private access)
  publicly_accessible = true

  # Encryption
  encrypted = true

  # Maintenance window (adjust as needed)
  maintenance_window = "sun:03:00-sun:05:00"

  # Skip final snapshot (for demo purposes; remove in production)
  skip_final_snapshot = true
}

# Output the cluster endpoint
output "redshift_cluster_endpoint" {
  value = aws_redshift_cluster.example.endpoint
}

