provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# IAM Role for Redshift to publish to SNS
resource "aws_iam_role" "redshift_sns_role" {
  name = "redshift-sns-publish-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "redshift.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "redshift_sns_policy" {
  role       = aws_iam_role.redshift_sns_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSNSFullAccess"
}

# SNS Topic for Redshift events
resource "aws_sns_topic" "redshift_events" {
  name = "redshift-cluster-events"
}

# Redshift Cluster
resource "aws_redshift_cluster" "example" {
  cluster_identifier = "example-cluster"
  database_name      = "dev"
  master_username    = "admin"
  master_password    = "YourSecurePassword123!" # Change this to a secure password or use AWS Secrets Manager
  node_type          = "dc2.large"
  cluster_type       = "single-node"

  # Enable logging for cluster events
  logging {
    enable_logging = true
    log_port       = 5439
    search_log_path = "/var/log/redshift/"
  }

  # IAM role for Redshift to publish to SNS
  iam_roles = [aws_iam_role.redshift_sns_role.arn]
}

# Redshift Event Subscription to SNS
resource "aws_redshift_event_subscription" "sns_subscription" {
  name          = "redshift-sns-subscription"
  event_types   = ["cluster-create", "cluster-delete", "cluster-modify", "cluster-failover", "cluster-resize"]
  notification_topic_arn = aws_sns_topic.redshift_events.arn
  s3_notification_configuration {
    log_delivery_configuration {
      log_type = "CLUSTER_LOG"
      s3_cfn_role_arn = aws_iam_role.redshift_sns_role.arn
    }
  }
}

