  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create a Redshift parameter group
resource "aws_redshift_parameter_group" "example_param_group" {
  name   = "example-param-group"
  family = "redshift-1.0" # Adjust family based on your Redshift version

  parameter {
    name  = "wlm_json_configuration"
    value = '{"query_concurrency": 5}'
  }

  parameter {
    name  = "enable_user_activity_logging"
    value = "true"
  }

  parameter {
    name  = "workload_management_timeout"
    value = "30"
  }
}

# Create a Redshift cluster with the parameter group
resource "aws_redshift_cluster" "example_cluster" {
  cluster_identifier      = "example-redshift-cluster"
  database_name           = "exampledb"
  master_username         = "admin"
  master_password         = "SecurePassword123!" # Change to a secure password
  node_type               = "dc2.large"
  cluster_type            = "single-node"
  skip_final_snapshot     = true # Set to false to create a final snapshot

  # Apply the parameter group
  parameter_group_name = aws_redshift_parameter_group.example_param_group.name

  # Enable notifications for parameter group changes
  notification {
    event_categories = ["parameter-group-modify"]
    sns_topic_arn    = aws_sns_topic.redshift_notifications.arn
  }

  # Enable notifications for cluster events
  notification {
    event_categories = [
      "cluster-create",
      "cluster-modify",
      "cluster-delete",
      "cluster-restart",
      "cluster-resize",
      "cluster-reboot",
      "cluster-maintenance",
      "cluster-failover",
      "cluster-snapshot-create",
      "cluster-snapshot-delete",
      "cluster-snapshot-restore",
      "cluster-snapshot-copy",
      "cluster-snapshot-modify",
      "cluster-snapshot-drop"
    ]
    sns_topic_arn = aws_sns_topic.redshift_notifications.arn
  }

  # Optional: Configure VPC settings
  vpc_security_group_ids = [aws_security_group.redshift_sg.id]
  publicly_accessible     = false
}

# Create an SNS topic for Redshift notifications
resource "aws_sns_topic" "redshift_notifications" {
  name = "redshift-cluster-notifications"
}

# Create a security group for Redshift
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-sg"
  description = "Security group for Redshift cluster"
  vpc_id      = "vpc-12345678" # Replace with your VPC ID

  ingress {
    from_port   = 5439 # Redshift port
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Replace with your allowed CIDR block
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Optional: Create a subscription for the SNS topic (e.g., email)
resource "aws_sns_topic_subscription" "email_subscription" {
  topic_arn = aws_sns_topic.redshift_notifications.arn
  protocol  = "email"
  endpoint  = "your-email@example.com" # Replace with your email
}

