  family = "redshift-1.0" # Adjust family based on your Redshift version

  parameter {
    name  = "wlm_json_configuration"
    value = '{"query_concurrency": 5}'
  }

  parameter {
    name  = "enable_user_activity_logging"
    value = "1"
  }
}

# Create an SNS topic for Redshift event notifications
resource "aws_sns_topic" "redshift_events_topic" {
  name = "redshift-events-topic"
}

# Create a Redshift event subscription to the SNS topic
resource "aws_redshift_event_subscription" "param_group_subscription" {
  name            = "redshift-param-group-subscription"
  event_categories = ["parameter-group-modify"]
  sns_topic_arn   = aws_sns_topic.redshift_events_topic.arn
  source_ids      = [aws_redshift_parameter_group.example_param_group.name]
}

# Create a Redshift cluster
resource "aws_redshift_cluster" "example_cluster" {
  cluster_identifier = "example-redshift-cluster"
  database_name      = "devdb"
  master_username    = "admin"
  master_password    = "YourSecurePassword123!" # Change to a secure password
  node_type          = "dc2.large"
  cluster_type       = "single-node"
  skip_final_snapshot = true # Set to false to create snapshots

  # Attach the parameter group
  parameter_group_name = aws_redshift_parameter_group.example_param_group.name

  # Optional: Configure public access if needed
  publicly_accessible = false

  # Optional: Configure maintenance window
  maintenance_window = "sun:02:00-sun:04:00"

  # Optional: Configure encryption
  encrypted = true
}

