  region = "us-east-1" # Change to your preferred region
}

resource "aws_s3_bucket" "website_images" {
  bucket = "your-unique-bucket-name-for-images" # Replace with your unique bucket name
  tags = {
    Name        = "WebsiteImagesBucket"
    Environment = "Production"
  }
}

resource "aws_s3_bucket_public_access_block" "website_images" {
  bucket = aws_s3_bucket.website_images.id

  block_public_acls       = false
  block_public_policy     = false
  ignore_public_acls      = false
  restrict_public_buckets = false
}

resource "aws_s3_bucket_policy" "website_images" {
  bucket = aws_s3_bucket.website_images.id
  policy = data.aws_iam_policy_document.website_images_policy.json
}

data "aws_iam_policy_document" "website_images_policy" {
  statement {
    actions   = ["s3:GetObject"]
    resources = ["${aws_s3_bucket.website_images.arn}/*"]

    principals {
      type        = "*"
      identifiers = ["*"]
    }
  }
}

resource "aws_cloudfront_distribution" "website_images" {
  origin {
    domain_name = aws_s3_bucket.website_images.bucket_regional_domain_name
    origin_id   = aws_s3_bucket.website_images.bucket

    s3_origin_config {
      origin_access_identity = aws_cloudfront_origin_access_identity.website_images.cloudfront_access_identity_path
    }
  }

  enabled             = true
  is_ipv6_enabled     = true
  default_root_object = "index.html"

  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = aws_s3_bucket.website_images.bucket

    forwarded_values {
      query_string = false

      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "redirect-to-https"
    min_ttl                = 0
    default_ttl            = 3600
    max_ttl                = 86400
  }

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }
}

resource "aws_cloudfront_origin_access_identity" "website_images" {
  comment = "Access identity for website images bucket"
}

resource "aws_s3_bucket_website_configuration" "website_images" {
  bucket = aws_s3_bucket.website_images.id

  index_document {
    suffix = "index.html"
  }

  error_document {
    key = "error.html"
  }
}

output "cloudfront_domain_name" {
  value = aws_cloudfront_distribution.website_images.domain_name
}

output "s3_bucket_name" {
  value = aws_s3_bucket.website_images.bucket
}
