terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create the main S3 bucket
resource "aws_s3_bucket" "main_bucket" {
  bucket = "mybucket"
}

# Create the analytics export bucket
resource "aws_s3_bucket" "analytics_export_bucket" {
  bucket = "mybucket-analytics-export-${random_id.bucket_suffix.hex}" # Using random suffix to avoid naming conflicts
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

# Enable server access logging for the main bucket (optional but recommended for analytics)
resource "aws_s3_bucket_server_side_encryption_configuration" "main_bucket_encryption" {
  bucket = aws_s3_bucket.main_bucket.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# Enable bucket analytics configuration
resource "aws_s3_bucket_analytics_configuration" "main_bucket_analytics" {
  bucket = aws_s3_bucket.main_bucket.id

  name = "main-bucket-analytics"

  filter {
    prefix = "" # Applies to entire bucket
  }

  storage_class = "STANDARD"

  data_export {
    destination {
      s3_bucket_destination {
        bucket_arn = aws_s3_bucket.analytics_export_bucket.arn
        role_arn   = aws_iam_role.s3_analytics_role.arn
      }
    }

    output_schema_version = "1.0"
    metrics = [
      "NumberOfObjects",
      "Size",
      "StorageClassAnalysis",
      "RequestCount",
      "InitiatedRequests",
      "TransitionedObjects",
      "TotalStorageClassSwitches"
    ]
  }
}

# IAM role for S3 analytics to write to the export bucket
resource "aws_iam_role" "s3_analytics_role" {
  name = "s3-analytics-role-${random_id.bucket_suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "s3.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "s3_analytics_policy" {
  name = "s3-analytics-policy-${random_id.bucket_suffix.hex}"
  role = aws_iam_role.s3_analytics_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetBucketAnalyticsConfiguration",
          "s3:PutBucketAnalyticsConfiguration",
          "s3:GetBucketRequestMetricsConfiguration",
          "s3:PutBucketRequestMetricsConfiguration",
          "s3:GetBucketInventoryConfiguration",
          "s3:PutBucketInventoryConfiguration",
          "s3:GetBucketObjectLockConfiguration",
          "s3:PutBucketObjectLockConfiguration",
          "s3:GetBucketVersioning",
          "s3:PutBucketVersioning",
          "s3:GetBucketTagging",
          "s3:PutBucketTagging",
          "s3:GetBucketPolicyStatus",
          "s3:GetBucketPublicAccessBlock",
          "s3:GetBucketLogging",
          "s3:PutBucketLogging",
          "s3:GetBucketOwnershipControls",
          "s3:PutBucketOwnershipControls"
        ]
        Resource = [
          aws_s3_bucket.main_bucket.arn,
          aws_s3_bucket.analytics_export_bucket.arn
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          "${aws_s3_bucket.analytics_export_bucket.arn}/*"
        ]
      }
    ]
  })
}

# Enable bucket versioning (optional but recommended for analytics)
resource "aws_s3_bucket_versioning" "main_bucket_versioning" {
  bucket = aws_s3_bucket.main_bucket.id

  versioning_configuration {
    status = "Enabled"
  }
}

# Enable bucket logging (optional but recommended for analytics)
resource "aws_s3_bucket_logging" "main_bucket_logging" {
  bucket = aws_s3_bucket.main_bucket.id

  target_bucket = aws_s3_bucket.analytics_export_bucket.id
  target_prefix = "logs/"
}

