terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create the primary S3 bucket for storing objects
resource "aws_s3_bucket" "primary_bucket" {
  bucket = "my-primary-bucket-${random_id.bucket_suffix.hex}" # Unique bucket name
  force_destroy = true # Set to false in production if you want to retain objects

  versioning {
    enabled = true
  }

  tags = {
    Name        = "Primary S3 Bucket"
    Environment = "Terraform Managed"
  }
}

# Create a random suffix for the bucket name to ensure uniqueness
resource "random_id" "bucket_suffix" {
  byte_length = 4
}

# Create a secondary S3 bucket for storing inventory reports
resource "aws_s3_bucket" "inventory_bucket" {
  bucket = "my-inventory-bucket-${random_id.bucket_suffix.hex}" # Unique bucket name
  force_destroy = true # Set to false in production if you want to retain objects

  tags = {
    Name        = "Inventory Reports Bucket"
    Environment = "Terraform Managed"
  }
}

# Enable server-side encryption on both buckets
resource "aws_s3_bucket_server_side_encryption_configuration" "primary_bucket_encryption" {
  bucket = aws_s3_bucket.primary_bucket.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "inventory_bucket_encryption" {
  bucket = aws_s3_bucket.inventory_bucket.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# Configure bucket policy for inventory report generation
resource "aws_s3_bucket_public_access_block" "primary_bucket_public_access" {
  bucket = aws_s3_bucket.primary_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

resource "aws_s3_bucket_public_access_block" "inventory_bucket_public_access" {
  bucket = aws_s3_bucket.inventory_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Create an IAM role for the S3 Inventory service
resource "aws_iam_role" "inventory_role" {
  name = "s3-inventory-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "s3.amazonaws.com"
        }
      }
    ]
  })
}

# Attach S3 Inventory policy to the role
resource "aws_iam_role_policy" "inventory_policy" {
  name = "s3-inventory-policy"
  role = aws_iam_role.inventory_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "s3:GetBucketLocation",
          "s3:ListBucket",
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:GetObjectVersionAcl",
          "s3:GetObjectVersionTagging"
        ],
        Resource = [
          aws_s3_bucket.primary_bucket.arn,
          "${aws_s3_bucket.primary_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow",
        Action = [
          "s3:PutObject"
        ],
        Resource = [
          "${aws_s3_bucket.inventory_bucket.arn}/*"
        ]
      }
    ]
  })
}

# Create the S3 Inventory configuration
resource "aws_s3_bucket_inventory_configuration" "inventory_config" {
  bucket = aws_s3_bucket.primary_bucket.id
  destination {
    s3_bucket {
      account_id = data.aws_caller_identity.current.account_id
      bucket     = aws_s3_bucket.inventory_bucket.bucket
      prefix     = "inventory-reports/"
      format     = "CSV"
    }
  }
  filter {
    prefix = "" # Inventory all objects in the bucket
  }
  included_object_versions = "All"
  is_enabled               = true
  schedule {
    frequency = "Weekly"
  }
  optional_fields = [
    "Size",
    "LastModifiedDate",
    "StorageClass",
    "ETag",
    "IsMultipartUploaded",
    "ReplicationStatus"
  ]
}

# Get the current AWS account ID
data "aws_caller_identity" "current" {}

