provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create an S3 bucket
resource "aws_s3_bucket" "payment_bucket" {
  bucket = "payment-data-bucket-${random_id.bucket_suffix.hex}" # Unique bucket name with random suffix
  tags = {
    Name        = "PaymentDataBucket"
    Environment = "Production"
  }
}

# Generate a random suffix for the bucket name to ensure uniqueness
resource "random_id" "bucket_suffix" {
  byte_length = 4
}

# Enable versioning on the S3 bucket
resource "aws_s3_bucket_versioning" "payment_bucket_versioning" {
  bucket = aws_s3_bucket.payment_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

# Enable server-side encryption with SSE-S3
resource "aws_s3_bucket_server_side_encryption_configuration" "payment_bucket_encryption" {
  bucket = aws_s3_bucket.payment_bucket.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# Block public access to the S3 bucket
resource "aws_s3_bucket_public_access_block" "payment_bucket_public_access" {
  bucket = aws_s3_bucket.payment_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Example payment configuration resource (JSON file stored in S3)
resource "aws_s3_object" "payment_config" {
  bucket = aws_s3_bucket.payment_bucket.id
  key    = "config/payment_config.json"
  source = "${path.module}/payment_config.json" # Ensure this file exists in the same directory
  etag   = filemd5("${path.module}/payment_config.json")

  # Example JSON content if file doesn't exist (uncomment and modify as needed)
  # content = <<EOF
  # {
  #   "payment_processor": "stripe",
  #   "api_key": "sk_test_1234567890",
  #   "webhook_url": "https://example.com/webhook",
  #   "max_retries": 3,
  #   "timeout_seconds": 30
  # }
  # EOF
}

# Optional: Bucket policy to restrict access to specific IAM roles/users
resource "aws_s3_bucket_policy" "payment_bucket_policy" {
  bucket = aws_s3_bucket.payment_bucket.id
  policy = data.aws_iam_policy_document.payment_bucket_policy_document.json
}

data "aws_iam_policy_document" "payment_bucket_policy_document" {
  statement {
    actions   = ["s3:GetObject", "s3:PutObject"]
    resources = ["${aws_s3_bucket.payment_bucket.arn}/*"]

    principals {
      type        = "AWS"
      identifiers = ["arn:aws:iam::123456789012:role/PaymentProcessingRole"] # Replace with your IAM role ARN
    }
  }
}

