terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_s3_bucket" "owner_pays_bucket" {
  bucket = "my-unique-bucket-name-${random_id.bucket_suffix.hex}" # Replace with your desired bucket name or use a variable
  force_destroy = true # WARNING: This will delete all objects in the bucket when destroyed

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }

  versioning {
    enabled = true
  }

  tags = {
    Name        = "OwnerPaysBucket"
    Environment = "Production"
  }
}

resource "random_id" "bucket_suffix" {
  byte_length = 4
}

# Enable bucket owner pays for requests (S3 bucket requester pays)
resource "aws_s3_bucket_public_access_block" "bucket_public_access" {
  bucket = aws_s3_bucket.owner_pays_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Optional: Add bucket policy to enforce requester pays
resource "aws_s3_bucket_policy" "requester_pays_policy" {
  bucket = aws_s3_bucket.owner_pays_bucket.id
  policy = data.aws_iam_policy_document.requester_pays_policy.json
}

data "aws_iam_policy_document" "requester_pays_policy" {
  statement {
    actions   = ["s3:GetObject"]
    resources = ["${aws_s3_bucket.owner_pays_bucket.arn}/*"]

    principals {
      type        = "*"
      identifiers = ["*"]
    }

    condition {
      test     = "Bool"
      variable = "s3:x-amz-request-payer"
      values   = ["Requester"]
    }
  }
}

