  bucket = "my-unique-log-bucket-name-${random_id.log_suffix.hex}" # Replace with your desired bucket name or use a random suffix
  tags = {
    Name        = "Log S3 Bucket"
    Environment = "Dev"
  }
}

# Create a random suffix for the log bucket
