provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# S3 Bucket to store student submissions and autograder results
resource "aws_s3_bucket" "student_submissions" {
  bucket = "cs-class-autograder-submissions-${random_id.bucket_suffix.hex}"
  force_destroy = true

  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }
}

resource "random_id" "bucket_suffix" {
  byte_length = 4
}

# IAM Role for CodeBuild to interact with S3
resource "aws_iam_role" "codebuild_role" {
  name = "cs-class-autograder-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for CodeBuild to access S3
resource "aws_iam_policy" "codebuild_s3_policy" {
  name        = "cs-class-autograder-s3-policy"
  description = "Policy for CodeBuild to access S3 bucket"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:ListBucket"
        ],
        Resource = [
          aws_s3_bucket.student_submissions.arn,
          "${aws_s3_bucket.student_submissions.arn}/*"
        ]
      },
      {
        Effect = "Allow",
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ],
        Resource = "*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "codebuild_s3_attachment" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = aws_iam_policy.codebuild_s3_policy.arn
}

# CodeBuild Project to run the autograder
resource "aws_codebuild_project" "autograder" {
  name          = "cs-class-autograder"
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = "60"

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/amazonlinux2-x86_64-standard:4.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "SUBMISSION_BUCKET"
      value = aws_s3_bucket.student_submissions.bucket
    }

    environment_variable {
      name  = "OUTPUT_BUCKET"
      value = aws_s3_bucket.student_submissions.bucket
    }

    environment_variable {
      name  = "GITHUB_REPO"
      value = "your-student-repo-url" # Replace with actual GitHub repo URL
    }
  }

  source {
    type      = "GITHUB"
    location  = "your-student-repo-url" # Replace with actual GitHub repo URL
    git_clone_depth = 1
  }

  source_version = "main" # Replace with the branch/tag/commit you want to build

  cache {
    type     = "LOCAL"
    modes    = ["LOCAL_DOCKER_LAYER_CACHE", "LOCAL_SOURCE_CACHE"]
  }
}

# S3 Bucket Notification to trigger CodeBuild when new submissions are uploaded
resource "aws_s3_bucket_notification" "codebuild_trigger" {
  bucket = aws_s3_bucket.student_submissions.id

  lambda_function {
    lambda_function_arn = aws_lambda_function.codebuild_trigger.arn
    events              = ["s3:ObjectCreated:*"]
    filter_suffix       = ".zip" # Assuming submissions are uploaded as .zip files
  }
}

# Lambda Function to trigger CodeBuild
resource "aws_lambda_function" "codebuild_trigger" {
  function_name = "trigger-autograder-codebuild"
  runtime       = "python3.9"
  handler       = "index.lambda_handler"
  role          = aws_iam_role.lambda_role.arn
  s3_bucket     = aws_s3_bucket.student_submissions.bucket
  s3_key        = "lambda/trigger_codebuild.zip" # Upload your Lambda function code here

  environment {
    variables = {
      CODEBUILD_PROJECT = aws_codebuild_project.autograder.name
    }
  }
}

resource "aws_iam_role" "lambda_role" {
  name = "cs-class-autograder-lambda-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

resource "aws_iam_role_policy" "lambda_s3_access" {
  name = "cs-class-autograder-lambda-s3-policy"
  role = aws_iam_role.lambda_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "s3:GetObject"
        ],
        Resource = [
          aws_s3_bucket.student_submissions.arn,
          "${aws_s3_bucket.student_submissions.arn}/*"
        ]
      },
      {
        Effect = "Allow",
        Action = [
          "codebuild:StartBuild"
        ],
        Resource = [
          aws_codebuild_project.autograder.arn
        ]
      }
    ]
  })
}

# Example buildspec file for CodeBuild (can be customized)
resource "aws_s3_object" "buildspec_file" {
  bucket = aws_s3_bucket.student_submissions.bucket
  key    = "buildspec.yml"
  source = "buildspec.yml" # You need to create this file locally and upload it
  etag   = filemd5("buildspec.yml")
}

