terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# VPC for isolated autograder environment
resource "aws_vpc" "autograder_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "autograder-vpc"
  }
}

# Private subnets for CodeBuild
resource "aws_subnet" "private_subnet_1" {
  vpc_id            = aws_vpc.autograder_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "autograder-private-subnet-1"
  }
}

resource "aws_subnet" "private_subnet_2" {
  vpc_id            = aws_vpc.autograder_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "autograder-private-subnet-2"
  }
}

# Internet Gateway (not attached to VPC, but needed for NAT)
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.autograder_vpc.id
  tags = {
    Name = "autograder-igw"
  }
}

# NAT Gateway for CodeBuild to access GitHub
resource "aws_eip" "nat_eip" {
  domain = "vpc"
}

resource "aws_nat_gateway" "nat_gw" {
  allocation_id = aws_eip.nat_eip.id
  subnet_id     = aws_subnet.private_subnet_1.id
  tags = {
    Name = "autograder-nat-gw"
  }
}

# Route tables
resource "aws_route_table" "private_route_table" {
  vpc_id = aws_vpc.autograder_vpc.id

  route {
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.nat_gw.id
  }

  tags = {
    Name = "autograder-private-route-table"
  }
}

resource "aws_route_table_association" "private_association_1" {
  subnet_id      = aws_subnet.private_subnet_1.id
  route_table_id = aws_route_table.private_route_table.id
}

resource "aws_route_table_association" "private_association_2" {
  subnet_id      = aws_subnet.private_subnet_2.id
  route_table_id = aws_route_table.private_route_table.id
}

# Security Group for CodeBuild (no outbound internet access)
resource "aws_security_group" "codebuild_sg" {
  name        = "autograder-codebuild-sg"
  description = "Allow CodeBuild to communicate within VPC"
  vpc_id      = aws_vpc.autograder_vpc.id

  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    self        = true
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["10.0.0.0/16"] # Only allow internal communication
  }

  tags = {
    Name = "autograder-codebuild-sg"
  }
}

# Security Group for GitHub access (only from NAT)
resource "aws_security_group" "github_access_sg" {
  name        = "autograder-github-access-sg"
  description = "Allow GitHub access via NAT"
  vpc_id      = aws_vpc.autograder_vpc.id

  egress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = [aws_eip.nat_eip.public_ip]
  }

  tags = {
    Name = "autograder-github-access-sg"
  }
}

# IAM Role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "autograder-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for CodeBuild
resource "aws_iam_policy" "codebuild_policy" {
  name        = "autograder-codebuild-policy"
  description = "Policy for CodeBuild to access GitHub and S3"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ],
        Resource = "*"
      },
      {
        Effect = "Allow",
        Action = [
          "s3:GetObject",
          "s3:PutObject"
        ],
        Resource = [
          "arn:aws:s3:::autograder-results-*",
          "arn:aws:s3:::autograder-inputs-*"
        ]
      },
      {
        Effect = "Allow",
        Action = [
          "ecr:GetAuthorizationToken",
          "ecr:BatchCheckLayerAvailability",
          "ecr:GetDownloadUrlForLayer",
          "ecr:BatchGetImage"
        ],
        Resource = "*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "codebuild_policy_attach" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = aws_iam_policy.codebuild_policy.arn
}

# CodeBuild Project
resource "aws_codebuild_project" "autograder" {
  name          = "autograder-project"
  description   = "Autograder for CS class"
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = "60"

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:6.0"
    type                        = "LINUX_CONTAINER"
    privileged_mode             = true
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "GITHUB_REPO"
      value = "your-students-repo-url" # Replace with actual GitHub repo URL
    }

    environment_variable {
      name  = "OUTPUT_BUCKET"
      value = aws_s3_bucket.autograder_results.bucket
    }

    environment_variable {
      name  = "INPUT_BUCKET"
      value = aws_s3_bucket.autograder_inputs.bucket
    }

    # Configure environment to use NAT for GitHub access
    environment_variable {
      name  = "HTTP_PROXY"
      value = "http://${aws_eip.nat_eip.public_ip}:8080"
    }
  }

  source {
    type      = "GITHUB"
    location  = "https://github.com/your-org/your-repo.git" # Replace with actual repo
    git_clone_depth = 1
  }

  network_config {
    enable_network_isolation = true
    vpc_config {
      subnets         = [aws_subnet.private_subnet_1.id, aws_subnet.private_subnet_2.id]
      security_groups = [aws_security_group.codebuild_sg.id]
      aws_vpc_config {
        vpc_id = aws_vpc.autograder_vpc.id
      }
    }
  }

  tags = {
    Name = "autograder-project"
  }
}

# S3 Buckets for storing inputs and results
resource "aws_s3_bucket" "autograder_inputs" {
  bucket = "autograder-inputs-${random_id.bucket_suffix.hex}"
  force_destroy = true
}

resource "aws_s3_bucket" "autograder_results" {
  bucket = "autograder-results-${random_id.bucket_suffix.hex}"
  force_destroy = true
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

# CloudWatch Log Group for CodeBuild
resource "aws_cloudwatch_log_group" "autograder_logs" {
  name              = "/aws/codebuild/autograder-project"
  retention_in_days = 7
}

# Buildspec file (stored in S3 and referenced by CodeBuild)
resource "aws_s3_bucket_object" "buildspec" {
  bucket = aws_s3_bucket.autograder_inputs.bucket
  key    = "buildspec.yml"
  source = <<EOF
version: 0.2
phases:
  install:
    runtime-versions:
      python: 3.8
    commands:
      - echo "Installing dependencies..."
      - pip install pytest
  pre_build:
    commands:
      - echo "Downloading student code..."
      - aws s3 cp s3://${aws_s3_bucket.autograder_inputs.bucket}/student-code.zip /tmp/student-code.zip
      - unzip /tmp/student-code.zip -d /tmp/student-code
  build:
    commands:
      - echo "Running tests..."
      - cd /tmp/student-code
      - python -m pytest --maxfail=1 --disable-warnings
  post_build:
    commands:
      - echo "Storing results..."
      - aws s3 cp /tmp/student-code/test-results.json s3://${aws_s3_bucket.autograder_results.bucket}/results/
EOF
}

# IAM Policy for S3 access
resource "aws_iam_policy" "s3_access_policy" {
  name        = "autograder-s3-access-policy"
  description = "Policy for CodeBuild to access S3 buckets"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:ListBucket"
        ],
        Resource = [
          aws_s3_bucket.autograder_inputs.arn,
          "${aws_s3_bucket.autograder_inputs.arn}/*",
          aws_s3_bucket.autograder_results.arn,
          "${aws_s3_bucket.autograder_results.arn}/*"
        ]
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "s3_access_attach" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = aws_iam_policy.s3_access_policy.arn
}

