      - aws s3 cp s3://${aws_s3_bucket.autograder_inputs.bucket}/student-code.zip /tmp/student-code.zip
      - unzip /tmp/student-code.zip -d /tmp/student-code
  build:
    commands:
      - echo "Running tests..."
      - cd /tmp/student-code
      - python -m pytest --maxfail=1 --disable-warnings
  post_build:
    commands:
      - echo "Storing results..."
      - aws s3 cp /tmp/student-code/test-results.json s3://${aws_s3_bucket.autograder_results.bucket}/results/
EOF
}

