  description = "Policy for CodeBuild to access S3 buckets"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:ListBucket"
        ],
        Resource = [
          aws_s3_bucket.autograder_inputs.arn,
          "${aws_s3_bucket.autograder_inputs.arn}/*",
