# VPC for isolated autograder environment
resource "aws_vpc" "autograder_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "autograder-vpc"
  }
}

# Private subnet for CodeBuild
resource "aws_subnet" "autograder_subnet" {
  vpc_id            = aws_vpc.autograder_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "autograder-subnet"
  }
}

# Security group to restrict internet access
resource "aws_security_group" "autograder_sg" {
  name        = "autograder-security-group"
  description = "Restrict autograder to internal communication only"
  vpc_id      = aws_vpc.autograder_vpc.id

  # Allow internal communication within VPC
  ingress {
    from_port   = 0
    to_port     = 65535
    protocol    = "tcp"
    self        = true
  }

  # Allow SSH from bastion host (if needed)
  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Restrict to VPC CIDR
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["10.0.0.0/16"] # Only allow internal traffic
  }

  tags = {
    Name = "autograder-sg"
  }
}

# S3 Bucket for storing student submissions and results
resource "aws_s3_bucket" "autograder_bucket" {
  bucket = "autograder-${random_id.bucket_suffix.hex}"
  force_destroy = true

  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }

  tags = {
    Name = "autograder-bucket"
  }
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

# IAM Role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "autograder-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for CodeBuild
resource "aws_iam_policy" "codebuild_policy" {
  name        = "autograder-codebuild-policy"
  description = "Policy for autograder CodeBuild"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:ListBucket"
        ],
        Resource = [
          aws_s3_bucket.autograder_bucket.arn,
          "${aws_s3_bucket.autograder_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow",
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ],
        Resource = "*"
      },
      {
        Effect = "Allow",
        Action = [
          "ec2:CreateNetworkInterface",
          "ec2:DescribeDhcpOptions",
          "ec2:DescribeNetworkInterfaces",
          "ec2:DeleteNetworkInterface",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeVpcs"
        ],
        Resource = "*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "codebuild_policy_attach" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = aws_iam_policy.codebuild_policy.arn
}

# CodeBuild Project for autograder
resource "aws_codebuild_project" "autograder_project" {
  name          = "autograder-project"
  description   = "Autograder for CS class"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image          = "aws/codebuild/standard:6.0"
    type           = "LINUX_CONTAINER"
    privileged_mode = true

    environment_variable {
      name  = "BUCKET_NAME"
      value = aws_s3_bucket.autograder_bucket.bucket
    }

    environment_variable {
      name  = "SUBNET_ID"
      value = aws_subnet.autograder_subnet.id
    }

    environment_variable {
      name  = "SECURITY_GROUP_ID"
      value = aws_security_group.autograder_sg.id
    }
  }

  source {
    type = "GITHUB"
    location = "https://github.com/your-org/your-repo.git"
  }

  cache {
    type     = "LOCAL"
    modes    = ["LOCAL_DOCKER_LAYER_CACHE", "LOCAL_SOURCE_CACHE"]
  }

  vpc_config {
    vpc_id             = aws_vpc.autograder_vpc.id
    subnets            = [aws_subnet.autograder_subnet.id]
    security_group_ids = [aws_security_group.autograder_sg.id]
  }

  tags = {
    Name = "autograder-project"
  }
}

# CloudWatch Log Group for CodeBuild
resource "aws_cloudwatch_log_group" "autograder_logs" {
  name              = "/aws/codebuild/autograder-project"
  retention_in_days = 7
}

# Example buildspec file (can be stored in S3 or GitHub)
resource "aws_s3_bucket_object" "buildspec" {
  bucket = aws_s3_bucket.autograder_bucket.bucket
  key    = "buildspec.yml"
  source = <<-EOT
version: 0.2
phases:
  install:
    runtime-versions:
      python: 3.8
    commands:
      - echo "Installing dependencies..."
      - pip install pytest
  pre_build:
    commands:
      - echo "Downloading student submission..."
      - aws s3 cp s3://${aws_s3_bucket.autograder_bucket.bucket}/student-submission.zip .
  build:
    commands:
      - echo "Running tests..."
      - unzip student-submission.zip
      - cd student-submission
      - python3 -m pytest --maxfail=1 --disable-warnings
  post_build:
    commands:
      - echo "Uploading results..."
      - aws s3 cp results.json s3://${aws_s3_bucket.autograder_bucket.bucket}/results/
EOT
}

