  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "codebuild-vpc"
  }
}

# Create VPC subnet
resource "aws_subnet" "private" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.0.0/24"
  availability_zone = "us-east-1a" # Change to your preferred AZ
  tags = {
    Name = "codebuild-private-subnet"
  }
}

# Create Security Group with no ingress/egress
resource "aws_security_group" "private" {
  name        = "codebuild-private-sg"
  description = "Security group with no ingress/egress"
  vpc_id      = aws_vpc.main.id

  tags = {
    Name = "codebuild-private-sg"
  }
}

# Create CodeBuild project
resource "aws_codebuild_project" "codebuild_project" {
  name          = "students-codebuild-project"
  description   = "CodeBuild project for students' code"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "S3"
    location = aws_s3_bucket.codebuild_output.bucket
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/alpine:latest"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode             = true
  }

  source {
    type      = "GITHUB"
    location  = "https://github.com/source-location"
    git_clone_depth = 1
  }

  vpc_config {
    vpc_id             = aws_vpc.main.id
    subnets            = [aws_subnet.private.id]
    security_group_ids = [aws_security_group.private.id]
  }
}

# IAM Role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for CodeBuild
resource "aws_iam_role_policy_attachment" "codebuild_policy" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSCodeBuildAdminAccess"
}

# IAM Policy for S3 access
resource "aws_iam_role_policy" "s3_access_policy" {
  name = "codebuild-s3-access-policy"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:GetBucketVersioning"
        ],
        Resource = [
          aws_s3_bucket.codebuild_output.arn,
          "${aws_s3_bucket.codebuild_output.arn}/*"
        ]
      }
    ]
  })
}
