terraform {
  required_version = ">= 1.0.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 4.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Create an S3 bucket to store cat pictures
resource "aws_s3_bucket" "cat_pictures" {
  bucket = "cat-pictures-${random_id.bucket_suffix.hex}"
}

resource "random_id" "bucket_suffix" {
  byte_length = 4
}

# Enable versioning on the bucket
resource "aws_s3_bucket_versioning" "cat_pictures_versioning" {
  bucket = aws_s3_bucket.cat_pictures.id
  versioning_configuration {
    status = "Enabled"
  }
}

# Create a Lambda function to handle cat picture uploads and retrieval
resource "aws_lambda_function" "cat_picture_handler" {
  filename      = "lambda_function.zip"
  function_name = "catPictureHandler"
  role          = aws_iam_role.lambda_exec.arn
  handler       = "index.handler"
  runtime       = "nodejs18.x"
  s3_bucket     = aws_s3_bucket.cat_pictures.bucket
  s3_key        = "lambda_function.zip"
  environment {
    variables = {
      BUCKET_NAME = aws_s3_bucket.cat_pictures.id
    }
  }
}

# IAM Role for Lambda
