**Note:** You'll need to create a Lambda function named `index.js` with the following content to handle the upload and random cat picture requests:

```javascript
const AWS = require('aws-sdk');
const s3 = new AWS.S3();
const crypto = require('crypto');

exports.handler = async (event) => {
  let response;

  if (event.resource === '/upload' && event.httpMethod === 'POST') {
    // Handle file upload
    const bucketName = process.env.BUCKET_NAME;
    const file = event.body;

    if (!file) {
      return {
        statusCode: 400,
        body: JSON.stringify({ message: 'No file uploaded' }),
      };
    }

    const fileName = `cat_picture_${Date.now()}.jpg`;
    const params = {
      Bucket: bucketName,
      Key: fileName,
      Body: file,
      ContentType: 'image/jpeg',
    };

    try {
      await s3.upload(params).promise();
      response = {
        statusCode: 200,
        body: JSON.stringify({ message: 'File uploaded successfully', fileName }),
      };
    } catch (err) {
      response = {
        statusCode: 500,
        body: JSON.stringify({ message: 'Error uploading file', error: err }),
      };
    }
  } else if (event.resource === '/random' && event.httpMethod === 'GET') {
    // Handle random cat picture retrieval
    const bucketName = process.env.BUCKET_NAME;

    try {
      const listParams = {
        Bucket: bucketName,
      };

      const data = await s3.listObjectsV2(listParams).promise();
      const randomIndex = Math.floor(Math.random() * data.Contents.length);
      const randomObject = data.Contents[randomIndex];
      const getParams = {
        Bucket: bucketName,
        Key: randomObject.Key,
      };

      const url = s3.getSignedUrl('getObject', getParams, { expires: 60 * 15 });
      response = {
        statusCode: 200,
        body: JSON.stringify({ url: url }),
      };
    } catch (err) {
      response = {
        statusCode: 500,
        body: JSON.stringify({ message: 'Error retrieving random cat picture', error: err }),
      };
    }
  } else {
    response = {
      statusCode: 404,
      body: JSON.stringify({ message: 'Not Found' }),
    };
  }

  return response;
};
```

Zip this file into `lambda_function.zip` and place it in the same directory as your Terraform configuration.

