terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# S3 Bucket to store cat pictures
resource "aws_s3_bucket" "cat_pictures" {
  bucket = "cat-pictures-bucket-${random_id.bucket_suffix.hex}"
}

resource "random_id" "bucket_suffix" {
  byte_length = 4
}

resource "aws_s3_bucket_public_access_block" "cat_pictures" {
  bucket = aws_s3_bucket.cat_pictures.id

  block_public_acls       = false
  block_public_policy     = false
  ignore_public_acls      = false
  restrict_public_buckets = false
}

resource "aws_s3_bucket_policy" "cat_pictures" {
  bucket = aws_s3_bucket.cat_pictures.id
  policy = data.aws_iam_policy_document.s3_bucket_policy.json
}

data "aws_iam_policy_document" "s3_bucket_policy" {
  statement {
    actions   = ["s3:*"]
    resources = [aws_s3_bucket.cat_pictures.arn]

    principals {
      type        = "*"
      identifiers = ["*"]
    }
  }
}

# DynamoDB table to track uploaded cat pictures
resource "aws_dynamodb_table" "cat_pictures_metadata" {
  name           = "CatPicturesMetadata"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "picture_id"

  attribute {
    name = "picture_id"
    type = "S"
  }
}

# Lambda function to handle uploads and serve random cat pictures
resource "aws_lambda_function" "cat_pictures_handler" {
  filename      = "lambda_function.zip"
  function_name = "CatPicturesHandler"
  role          = aws_iam_role.lambda_exec.arn
  handler       = "index.handler"
  runtime       = "nodejs18.x"
  timeout       = 30

  environment {
    variables = {
      BUCKET_NAME = aws_s3_bucket.cat_pictures.bucket
      TABLE_NAME = aws_dynamodb_table.cat_pictures_metadata.name
    }
  }
}

# IAM Role for Lambda
resource "aws_iam_role" "lambda_exec" {
  name = "lambda_exec"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_exec.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

resource "aws_iam_role_policy" "lambda_s3_dynamodb_access" {
  name = "lambda_s3_dynamodb_access"
  role = aws_iam_role.lambda_exec.id

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:ListBucket"
        ],
        Resource = [
          aws_s3_bucket.cat_pictures.arn,
          "${aws_s3_bucket.cat_pictures.arn}/*"
        ]
      },
      {
        Effect = "Allow",
        Action = [
          "dynamodb:PutItem",
          "dynamodb:GetItem",
          "dynamodb:Scan"
        ],
        Resource = aws_dynamodb_table.cat_pictures_metadata.arn
      }
    ]
  })
}

# Lambda permission for API Gateway
resource "aws_lambda_permission" "apigw_lambda" {
  statement_id  = "AllowExecutionFromAPIGateway"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.cat_pictures_handler.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_api_gateway_rest_api.cat_pictures.execution_arn}/*/*"
}

# API Gateway REST API
resource "aws_api_gateway_rest_api" "cat_pictures" {
  name        = "CatPicturesAPI"
  description = "API for uploading and retrieving cat pictures"
}

# Resources for API Gateway
resource "aws_api_gateway_resource" "upload_picture" {
  rest_api_id = aws_api_gateway_rest_api.cat_pictures.id
  parent_id   = aws_api_gateway_rest_api.cat_pictures.root_resource_id
  path_part   = "upload"
}

resource "aws_api_gateway_resource" "random_picture" {
  rest_api_id = aws_api_gateway_rest_api.cat_pictures.id
  parent_id   = aws_api_gateway_rest_api.cat_pictures.root_resource_id
  path_part   = "random"
}

# API Gateway methods
resource "aws_api_gateway_method" "upload_picture_post" {
  rest_api_id   = aws_api_gateway_rest_api.cat_pictures.id
  resource_id   = aws_api_gateway_resource.upload_picture.id
  http_method   = "POST"
  authorization = "NONE"
}

resource "aws_api_gateway_method" "random_picture_get" {
  rest_api_id   = aws_api_gateway_rest_api.cat_pictures.id
  resource_id   = aws_api_gateway_resource.random_picture.id
  http_method   = "GET"
  authorization = "NONE"
}

# API Gateway integration with Lambda
resource "aws_api_gateway_integration" "upload_picture_integration" {
  rest_api_id = aws_api_gateway_rest_api.cat_pictures.id
  resource_id = aws_api_gateway_resource.upload_picture.id
  http_method = aws_api_gateway_method.upload_picture_post.http_method

  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = aws_lambda_function.cat_pictures_handler.invoke_arn
}

resource "aws_api_gateway_integration" "random_picture_integration" {
  rest_api_id = aws_api_gateway_rest_api.cat_pictures.id
  resource_id = aws_api_gateway_resource.random_picture.id
  http_method = aws_api_gateway_method.random_picture_get.http_method

  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = aws_lambda_function.cat_pictures_handler.invoke_arn
}

# API Gateway deployment
resource "aws_api_gateway_deployment" "cat_pictures_deployment" {
  depends_on = [
    aws_api_gateway_integration.upload_picture_integration,
    aws_api_gateway_integration.random_picture_integration,
  ]

  rest_api_id = aws_api_gateway_rest_api.cat_pictures.id
  stage_name   = "prod"
}

# Output the API Gateway URL
output "api_gateway_url" {
  value = "${aws_api_gateway_deployment.cat_pictures_deployment.invoke_url}"
}
