terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# S3 Bucket for cat pictures
resource "aws_s3_bucket" "cat_pictures_bucket" {
  bucket = "caas-cat-pictures-bucket-${random_id.bucket_suffix.hex}"
}

resource "random_id" "bucket_suffix" {
  byte_length = 4
}

resource "aws_s3_bucket_public_access_block" "cat_pictures_bucket" {
  bucket = aws_s3_bucket.cat_pictures_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# DynamoDB Table for cat names
resource "aws_dynamodb_table" "cats_table" {
  name           = "caas-cats-table"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "name"

  attribute {
    name = "name"
    type = "S"
  }
}

# Lambda Function for GET method
resource "aws_lambda_function" "caas_get_lambda" {
  function_name = "caas-get-cat"
  runtime       = "python3.9"
  handler       = "lambda_function.lambda_handler"
  role          = aws_iam_role.lambda_exec.arn

  s3_bucket = aws_s3_bucket.lambda_code_bucket.name
  s3_key    = "caas-get-cat.zip"

  environment {
    variables = {
      CATS_TABLE = aws_dynamodb_table.cats_table.name
      CAT_PICTURES_BUCKET = aws_s3_bucket.cat_pictures_bucket.bucket
    }
  }
}

# Lambda Function for PUT method
resource "aws_lambda_function" "caas_put_lambda" {
  function_name = "caas-put-cat"
  runtime       = "python3.9"
  handler       = "lambda_function.lambda_handler"
  role          = aws_iam_role.lambda_exec.arn

  s3_bucket = aws_s3_bucket.lambda_code_bucket.name
  s3_key    = "caas-put-cat.zip"

  environment {
    variables = {
      CATS_TABLE = aws_dynamodb_table.cats_table.name
      CAT_PICTURES_BUCKET = aws_s3_bucket.cat_pictures_bucket.bucket
    }
  }
}

# S3 Bucket for Lambda code
resource "aws_s3_bucket" "lambda_code_bucket" {
  bucket = "caas-lambda-code-bucket-${random_id.lambda_bucket_suffix.hex}"
}

resource "random_id" "lambda_bucket_suffix" {
  byte_length = 4
}

resource "aws_s3_bucket_public_access_block" "lambda_code_bucket" {
  bucket = aws_s3_bucket.lambda_code_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# IAM Role for Lambda Execution
resource "aws_iam_role" "lambda_exec" {
  name = "caas-lambda-exec-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_exec.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

resource "aws_iam_role_policy" "lambda_dynamodb_access" {
  name = "caas-lambda-dynamodb-access"
  role = aws_iam_role.lambda_exec.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "dynamodb:GetItem",
          "dynamodb:PutItem",
          "dynamodb:UpdateItem",
          "dynamodb:DeleteItem",
          "dynamodb:Query"
        ],
        Resource = aws_dynamodb_table.cats_table.arn
      },
      {
        Effect = "Allow",
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:DeleteObject"
        ],
        Resource = [
          "${aws_s3_bucket.cat_pictures_bucket.arn}/*"
        ]
      }
    ]
  })
}

# API Gateway
resource "aws_apigatewayv2_api" "caas_api" {
  name          = "caas"
  protocol_type = "HTTP"
}

resource "aws_apigatewayv2_integration" "caas_get_integration" {
  api_id             = aws_apigatewayv2_api.caas_api.id
  integration_type   = "AWS_PROXY"
  integration_uri    = aws_lambda_function.caas_get_lambda.invoke_arn
  integration_method = "POST"
}

resource "aws_apigatewayv2_route" "caas_get_route" {
  api_id    = aws_apigatewayv2_api.caas_api.id
  route_key = "GET /caas_cat/cat"
  target    = "integrations/${aws_apigatewayv2_integration.caas_get_integration.id}"
}

resource "aws_apigatewayv2_integration" "caas_put_integration" {
  api_id             = aws_apigatewayv2_api.caas_api.id
  integration_type   = "AWS_PROXY"
  integration_uri    = aws_lambda_function.caas_put_lambda.invoke_arn
  integration_method = "POST"
}

resource "aws_apigatewayv2_route" "caas_put_route" {
  api_id    = aws_apigatewayv2_api.caas_api.id
  route_key = "PUT /caas_cat/cat"
  target    = "integrations/${aws_apigatewayv2_integration.caas_put_integration.id}"
}

resource "aws_lambda_permission" "apigw_caas_get_lambda" {
  statement_id  = "AllowExecutionFromAPIGateway"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.caas_get_lambda.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_apigatewayv2_api.caas_api.execution_arn}/*/*"
}

resource "aws_lambda_permission" "apigw_caas_put_lambda" {
  statement_id  = "AllowExecutionFromAPIGateway"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.caas_put_lambda.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_apigatewayv2_api.caas_api.execution_arn}/*/*"
}

# Outputs
output "api_gateway_url" {
  value = aws_apigatewayv2_api.caas_api.api_endpoint
}

output "dynamodb_table_name" {
  value = aws_dynamodb_table.cats_table.name
}

output "s3_bucket_name" {
  value = aws_s3_bucket.cat_pictures_bucket.bucket
}
