}

# IAM Role for EC2 to allow AWS Backup access
resource "aws_iam_role" "ec2_backup_role" {
  name = "ec2-backup-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Effect = "Allow",
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "ec2_backup_attachment" {
  role       = aws_iam_role.ec2_backup_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSBackupReadOnlyAccess"
}

# IAM Instance Profile for EC2
resource "aws_iam_instance_profile" "ec2_backup_profile" {
  name = "ec2-backup-profile"
  role = aws_iam_role.ec2_backup_role.name
}

# Security Group for EC2
resource "aws_security_group" "ec2_sg" {
  name        = "ec2-backup-sg"
  description = "Allow SSH and HTTP traffic"

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict this in production
  }

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict this in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# EC2 Instance
resource "aws_instance" "backup_instance" {
  ami           = "ami-0c55b159cbfafe1f0" # Amazon Linux 2 (us-east-1)
  instance_type = "t2.micro"
  key_name      = "your-key-pair" # Replace with your key pair name
  security_groups = [aws_security_group.ec2_sg.name]
  iam_instance_profile = aws_iam_instance_profile.ec2_backup_profile.name
  tags = {
    Name = "Backup-Protected-EC2"
  }
}

# AWS Backup Plan
resource "aws_backup_plan" "daily_backup_plan" {
  name = "daily-ec2-backup-plan"

  rule {
    rule_name         = "daily-backup-rule"
    target_vault_name = aws_backup_vault.backup_vault.name
    schedule          = "cron(0 0 * * ? *)" # Midnight UTC
    start_window      = 60
    delete_after      = 7 # Delete backups after 7 days
    lifecycle {
      copy_actions {
        destination_backup_vault_arn = aws_backup_vault.backup_vault.arn
      }
    }
  }
}

# AWS Backup Vault
resource "aws_backup_vault" "backup_vault" {
  name = "ec2-backup-vault"
}

# AWS Backup Selection for EC2 Instance
resource "aws_backup_selection" "ec2_backup_selection" {
  iam_role_arn = aws_backup_plan.daily_backup_plan.arn
  name         = "ec2-backup-selection"

  resources = [
    aws_instance.backup_instance.arn
  ]

  plan_id = aws_backup_plan.daily_backup_plan.arn
}

# AWS Backup Plan Assignment
resource "aws_backup_plan" "daily_backup_plan" {
  name = "daily-ec2-backup-plan"

  rule {
    rule_name         = "daily-backup-rule"
    target_vault_name = aws_backup_vault.backup_vault.name
    schedule          = "cron(0 0 * * ? *)"
    start_window      = 60
    delete_after      = 7
    lifecycle {
      copy_actions {
        destination_backup_vault_arn = aws_backup_vault.backup_vault.arn
      }
    }
  }
}

resource "aws_backup_plan_assignment" "ec2_backup_assignment" {
  plan_id   = aws_backup_plan.daily_backup_plan.arn
  iam_role_arn = aws_iam_role.ec2_backup_role.arn
  resources = [
    aws_instance.backup_instance.arn
  ]
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

data "aws_ami" "amzn2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["*ubuntu-noble-24.04-amd64-server-*"]
  }
}

resource "aws_instance" "cloud_desktop" {
  instance_type = "t2.micro"
  ami = data.aws_ami.amzn2.id
}

resource "aws_backup_plan" "cloud_desktop_backup" {
  name = "cloud_desktop_backup_plan"
  rule {
    rule_name         = "cloud_desktop_backup_rule" # required, not specified
    target_vault_name = aws_backup_vault.valut.name # required, not specified
    schedule          = "cron(0 0 * * ? *)"
  }

  advanced_backup_setting {
    backup_options = {
      WindowsVSS = "enabled"
    }
    resource_type = "EC2"
  }
}

resource "aws_backup_vault" "valut" {
  name = "cloud_desktop_backup_valut"
}

resource "aws_backup_selection" "backup_ec2" {
  iam_role_arn = aws_iam_role.backup.arn

  name    = "backup_ec2"
  plan_id = aws_backup_plan.cloud_desktop_backup.id

  resources = [
    aws_instance.cloud_desktop.arn,
  ]
}

data "aws_iam_policy_document" "backup_assume_role" {
  statement {
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["backup.amazonaws.com"]
    }

    actions = ["sts:AssumeRole"]
  }
}

resource "aws_iam_role" "backup" {
  name               = "backup"
  assume_role_policy = data.aws_iam_policy_document.backup_assume_role.json
}

resource "aws_iam_role_policy_attachment" "backup" {
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
  role       = aws_iam_role.backup.name
}

