    target_vault_name = aws_backup_vault.ec2_backup_vault.name
    schedule_expression = "cron(0 0 * * ? *)" # Midnight UTC
    start_window_minutes = 60
    completion_window_minutes = 120
    delete_after = 7 # Delete backups after 7 days (optional)
  }
}

# Create a backup selection for the EC2 instance
