    target_vault_name = aws_backup_vault.ec2_backup_vault.name
    schedule_expression = "cron(0 0 * * ? *)"
    start_window_minutes = 60
    completion_window_minutes = 120
    delete_after = 7
    copy_action {
      destination_backup_vault_arn = aws_backup_vault.ec2_backup_vault.arn
      lifecycle {
        delete_after = 7
      }
    }
  }

  depends_on = [
    aws_backup_selection.ec2_backup_selection_updated
  ]
}

# Assign the updated backup selection to the backup plan
