resource "aws_cloudwatch_event_rule" "daily_schedule" {
  name                = "daily-code-execution"
  description         = "Triggers a job daily at 7 UTC"
  schedule_expression = "cron(0 7 * * ? *)" # Runs at 7:00 UTC every day
}

resource "aws_cloudwatch_event_target" "eventbridge_target" {
  rule      = aws_cloudwatch_event_rule.daily_schedule.name
  target_id = "invoke-lambda-function"
  arn       = aws_lambda_function.code_executor.arn
}

resource "aws_lambda_function" "code_executor" {
  function_name = "daily-code-executor"
  runtime       = "python3.9" # Adjust runtime as needed
  handler       = "lambda_function.lambda_handler"
  role          = aws_iam_role.lambda_exec.arn

  filename      = "lambda_function.zip" # Replace with your Lambda deployment package
  source_code_hash = filebase64sha256("lambda_function.zip") # Required for updates

  environment {
    variables = {
      # Add environment variables if needed
    }
  }
}

