  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.daily_cron.arn
}

resource "aws_lambda_function" "lambda_func" {
  filename      = "./supplement/lambda_func.zip"
  function_name = "daily-lambda-function"
  role          = aws_iam_role.lambda_exec.arn
  handler       = "index.handler" # Adjust based on your Lambda function's entry point
  runtime       = "nodejs18.x"    # Adjust runtime as needed (e.g., python3.9, java11)
  depends_on    = [aws_iam_role_policy_attachment.lambda_basic_execution]
}

resource "aws_iam_role" "lambda_exec" {
  name = "lambda_exec_role"

  assume_role_policy = jsonencode({
