    sampled_requests_enabled   = true
  }

  rule {
    name     = "AWS-AWSManagedRulesCommonRuleSet"
    priority = 0

    override_action {
      none {}
    }

    statement {
      managed_rule_group_statement {
        vendor_name = "AWS"
        name        = "AWSManagedRulesCommonRuleSet"
      }
    }

    visibility_config {
      cloudwatch_metrics_enabled = true
      metric_name                = "AWS-AWSManagedRulesCommonRuleSet"
      sampled_requests_enabled   = true
    }
  }
}

resource "aws_wafv2_web_acl_association" "video_streaming_waf_association" {
  resource_arn = aws_cloudfront_distribution.video_streaming_updated.arn
  web_acl_arn  = aws_wafv2_web_acl.video_streaming_waf.arn
}

# Variables
variable "domain_name" {
  description = "The domain name for the video streaming site"
  type        = string
}

# Outputs
output "cloudfront_domain_name" {
