extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# VPC for the video streaming infrastructure
resource "aws_vpc" "streaming_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "streaming-vpc"
  }
}

# Internet Gateway
resource "aws_internet_gateway" "streaming_igw" {
  vpc_id = aws_vpc.streaming_vpc.id
  tags = {
    Name = "streaming-igw"
  }
}

# Public Subnet for Load Balancer
resource "aws_subnet" "public_subnet" {
  vpc_id                  = aws_vpc.streaming_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = true
  tags = {
    Name = "public-subnet"
  }
}

# Route Table for Public Subnet
resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.streaming_vpc.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.streaming_igw.id
  }
  tags = {
    Name = "public-rt"
  }
}

# Associate Route Table with Public Subnet
resource "aws_route_table_association" "public_rta" {
  subnet_id      = aws_subnet.public_subnet.id
  route_table_id = aws_route_table.public_rt.id
}

# Security Group for Load Balancer
resource "aws_security_group" "lb_sg" {
  name        = "streaming-lb-sg"
  description = "Allow HTTP/HTTPS traffic to the load balancer"
  vpc_id      = aws_vpc.streaming_vpc.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "streaming-lb-sg"
  }
}

# Security Group for Application Servers
resource "aws_security_group" "app_sg" {
  name        = "streaming-app-sg"
  description = "Allow traffic from load balancer"
  vpc_id      = aws_vpc.streaming_vpc.id

  ingress {
    from_port       = 8080
    to_port         = 8080
    protocol        = "tcp"
    security_groups = [aws_security_group.lb_sg.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "streaming-app-sg"
  }
}

# Launch Template for Application Servers
resource "aws_launch_template" "app_launch_template" {
  name_prefix   = "streaming-app-template"
  image_id      = "ami-0c55b159cbfafe1f0" # Amazon Linux 2 AMI (us-east-1)
  instance_type = "t3.medium"
  key_name      = "your-key-pair" # Replace with your key pair name

  network_interfaces {
    associate_public_ip_address = false
    security_groups             = [aws_security_group.app_sg.id]
  }

  user_data = base64encode(<<-EOF
              #!/bin/bash
              yum update -y
              yum install -y httpd
              systemctl start httpd
              systemctl enable httpd
              echo "Video Streaming Server" > /var/www/html/index.html
              EOF
  )

  tag_specifications {
    resource_type = "instance"
    tags = {
      Name = "streaming-app-server"
    }
  }
}

# Auto Scaling Group for Application Servers
resource "aws_autoscaling_group" "app_asg" {
  desired_capacity    = 2
  max_size            = 4
  min_size            = 2
  vpc_zone_identifier = [aws_subnet.public_subnet.id]

  launch_template {
    id      = aws_launch_template.app_launch_template.id
    version = "$Latest"
  }

  tag {
    key                 = "Name"
    value               = "streaming-app-server"
    propagate_at_launch = true
  }
}

# Application Load Balancer
resource "aws_lb" "streaming_lb" {
  name               = "streaming-lb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.lb_sg.id]
  subnets            = [aws_subnet.public_subnet.id]

  enable_deletion_protection = false

  tags = {
    Name = "streaming-lb"
  }
}

# Target Group for Load Balancer
resource "aws_lb_target_group" "app_tg" {
  name        = "streaming-app-tg"
  port        = 8080
  protocol    = "HTTP"
  vpc_id      = aws_vpc.streaming_vpc.id
  target_type = "instance"

  health_check {
    path                = "/"
