    healthy_threshold   = 2
    unhealthy_threshold = 2
    matcher             = "200-299"
  }
}

resource "aws_lb_listener" "app_listener" {
  load_balancer_arn = aws_lb.app_lb.arn
  port              = 80
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.app_tg.arn
  }
}

resource "aws_instance" "ubuntu_instance" {
  ami           = "ami-0c55b159cbfafe1f0" # Latest Ubuntu AMI in us-east-1
  instance_type = "t2.micro"
  subnet_id     = module.vpc.public_subnets[0]
  vpc_security_group_ids = [aws_security_group.app_sg.id]

  tags = {
    Name = "ubuntu-instance"
  }
}

resource "aws_lb_target_group_attachment" "instance_attachment" {
  target_group_arn = aws_lb_target_group.app_tg.arn
  target_id        = aws_instance.ubuntu_instance.id
  port             = 80
}

resource "aws_route53_zone" "domain_zone" {
  name = "test-video-stream.com"
}

resource "aws_route53_record" "lb_record" {
  zone_id = aws_route53_zone.domain_zone.zone_id
  name    = "lb.test-video-stream.com"
  type    = "A"

  alias {
    name                   = aws_lb.app_lb.dns_name
    zone_id                = aws_lb.app_lb.zone_id
    evaluate_target_health = true
  }
}

resource "aws_route53_record" "domain_record" {
  zone_id = aws_route53_zone.domain_zone.zone_id
  name    = "test-video-stream.com"
  type    = "A"

  alias {
    name                   = aws_lb.app_lb.dns_name
    zone_id                = aws_lb.app_lb.zone_id
    evaluate_target_health = true
  }
}

resource "aws_route53_record" "domain_record_ipv6" {
  zone_id = aws_route53_zone.domain_zone.zone_id
  name    = "test-video-stream.com"
  type    = "AAAA"

  alias {
    name                   = aws_lb.app_lb.dns_name
    zone_id                = aws_lb.app_lb.zone_id
    evaluate_target_health = true
  }
}
