  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.${count.index}.0/24"
  availability_zone = element(data.aws_availability_zones.available.names, count.index)
  tags = {
    Name = "public-subnet-${count.index}"
  }
}

# Create Route Table for Public Subnets
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.gw.id
  }
  tags = {
    Name = "public-route-table"
  }
}

# Associate Route Table with Public Subnets
resource "aws_route_table_association" "public" {
  count          = 2
  subnet_id      = aws_subnet.public[count.index].id
  route_table_id = aws_route_table.public.id
}

# Create Security Group for Database Access
resource "aws_security_group" "db_sg" {
  name        = "postgres-db-sg"
  description = "Allow PostgreSQL access"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "PostgreSQL access"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Restrict to VPC CIDR or adjust as needed
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "postgres-db-sg"
  }
}

# Create RDS Subnet Group
resource "aws_db_subnet_group" "postgres" {
  name       = "postgres-subnet-group"
  subnet_ids = aws_subnet.public[*].id # Use public subnets for RDS (adjust if needed)
  tags = {
    Name = "postgres-subnet-group"
  }
}

# Create PostgreSQL Database Instance
resource "aws_db_instance" "postgres" {
  allocated_storage    = 5 # 5GB storage
  engine               = "postgres"
  engine_version       = "17.1"
  instance_class       = "db.t3.micro" # Adjust based on your needs
  db_name              = "mydatabase"
  username             = "adminuser"
  password             = "your-secure-password" # Use AWS Secrets Manager or environment variables in production
  skip_final_snapshot  = true
  vpc_security_group_ids = [aws_security_group.db_sg.id]
  db_subnet_group_name = aws_db_subnet_group.postgres.name
  publicly_accessible  = false # Ensure it's not publicly accessible
  storage_encrypted     = true # Enable encryption
  tags = {
    Name = "postgres-db-instance"
  }
}

# Data source for availability zones
data "aws_availability_zones" "available" {
  state = "available"
}

