    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-security-group"
  }
}

# Create Custom Parameter Group for PostgreSQL
resource "aws_db_parameter_group" "postgres_param_group" {
  name        = "postgres-param-group"
  family      = "postgres15"
  description = "Custom PostgreSQL parameter group for version 15"

  parameter {
    name  = "log_min_duration_statement"
    value = "1000"
  }

  parameter {
    name  = "max_connections"
    value = "200"
  }

  parameter {
    name  = "shared_buffers"
    value = "4GB"
  }

  tags = {
    Name = "postgres-param-group"
  }
}

# Create RDS PostgreSQL Instance
