```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create a VPC if not already existing (assuming VPC details are provided elsewhere)
# resource "aws_vpc" "main" {
#   cidr_block           = "10.0.0.0/16"
#   enable_dns_support   = true
#   enable_dns_hostnames = true
#   tags = {
#     Name = "main-vpc"
#   }
# }

# Create a KMS key for encryption
resource "aws_kms_key" "rds_key" {
  description             = "KMS key for RDS PostgreSQL encryption"
  deletion_window_in_days = 30
  enable_key_rotation     = true
  policy                  = data.aws_iam_policy_document.kms_policy.json
}

data "aws_iam_policy_document" "kms_policy" {
  statement {
    sid    = "Enable IAM User Permissions"
    effect = "Allow"
    principals {
      type        = "AWS"
      identifiers = ["arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"]
    }
    actions   = ["kms:*"]
    resources = ["*"]
  }
}

data "aws_caller_identity" "current" {}

# Create a customer managed KMS key alias
resource "aws_kms_alias" "rds_key_alias" {
  name          = "alias/rds-postgresql-key"
  target_key_id = aws_kms_key.rds_key.key_id
}

# Create a subnet group for RDS
resource "aws_db_subnet_group" "postgresql_subnet_group" {
  name       = "postgresql-subnet-group"
  subnet_ids = ["subnet-12345678", "subnet-87654321"] # Replace with your subnet IDs
  tags = {
    Name = "PostgreSQL Subnet Group"
  }
}

# Create a security group for PostgreSQL
resource "aws_security_group" "postgresql_sg" {
  name        = "postgresql-security-group"
  description = "Allow PostgreSQL access"
  vpc_id      = "vpc-12345678" # Replace with your VPC ID

  ingress {
    description = "PostgreSQL access"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Replace with your VPC CIDR or restrict further
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "PostgreSQL Security Group"
  }
}

# Create a PostgreSQL parameter group
resource "aws_db_parameter_group" "postgresql_param_group" {
  name        = "postgresql-custom-param-group"
  family      = "postgres13" # Change to your PostgreSQL version
  description = "Custom PostgreSQL parameter group"

  parameter {
    name  = "log_min_duration_statement"
    value = "1000"
  }

  parameter {
    name  = "shared_preload_libraries"
    value = "pg_stat_statements"
  }

  tags = {
    Name = "PostgreSQL Custom Parameter Group"
  }
}

# Create the RDS PostgreSQL instance
resource "aws_db_instance" "postgresql" {
  allocated_storage      = 100 # Adjust as needed
  engine                 = "postgres"
  engine_version         = "13.4" # Change to your PostgreSQL version
  instance_class         = "db.m5.large" # Adjust as needed
  db_name                = "mydatabase" # Change to your database name
  username               = "admin" # Change to your admin username
  password               = "your-secure-password" # Change to a secure password
  parameter_group_name   = aws_db_parameter_group.postgresql_param_group.name
  skip_final_snapshot    = false
  final_snapshot_identifier = "pgsnapshot" # As per your request
  db_subnet_group_name   = aws_db_subnet_group.postgresql_subnet_group.name
  vpc_security_group_ids = [aws_security_group.postgresql_sg.id]
  multi_az               = true # For high availability
  storage_encrypted      = true
  kms_key_id             = aws_kms_key.rds_key.arn
  publicly_accessible    = false
  backup_retention_period = 7 # Adjust as needed
  tags = {
    Name = "PostgreSQL RDS Instance"
  }
}

# Output the RDS endpoint
output "postgresql_endpoint" {
  value = aws_db_instance.postgresql.endpoint
}
