  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "airbyte-vpc"
  }
}

# Public Subnet Configuration (replace with your specific subnets)
resource "aws_subnet" "airbyte_public_subnets" {
  count             = 2 # Adjust number of subnets as needed
