  cidr_block        = "10.0.${count.index}.0/24"
  availability_zone = "us-east-1${count.index + 1}" # us-east-1a, us-east-1b
  map_public_ip_on_launch = true

  tags = {
    Name = "airbyte-public-subnet-${count.index + 1}"
  }
}

# Internet Gateway
