terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# VPC and Subnet Configuration (assuming these exist; adjust as needed)
data "aws_vpc" "default" {
  default = true
}

data "aws_subnets" "public" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
  filter {
    name   = "map-public-ip-on-launch"
    values = ["true"]
  }
}

# RDS PostgreSQL 15 Instance
resource "aws_db_instance" "airbyte_postgres" {
  allocated_storage    = 5
  engine               = "postgres"
  engine_version       = "15.4" # Latest stable PostgreSQL 15 version
  instance_class       = "db.t3.micro"
  db_name              = "airbyte_test"
  username             = "airbyte_user"
  password             = "SecurePassword123!" # Change to a secure password or use AWS Secrets Manager
  publicly_accessible  = false # Set to true if public access is required (not recommended for production)
  skip_final_snapshot  = true # Disable for production to retain snapshots
  storage_encrypted    = true
  storage_type         = "gp2"
  backup_retention_period = 7 # Days to retain automated backups
  multi_az             = false # Set to true for production HA
  db_subnet_group_name = aws_db_subnet_group.airbyte_subnet_group.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]

  # Managed settings (low maintenance)
  auto_minor_version_upgrade = true
  copy_tags_to_snapshot     = true
  deletion_protection       = false # Disable for testing; enable in production
  performance_insights_enabled = true
  monitoring_interval      = "300" # 5-minute monitoring interval
}

# DB Subnet Group (attach to public subnets)
resource "aws_db_subnet_group" "airbyte_subnet_group" {
  name       = "airbyte-postgres-subnet-group"
  subnet_ids = data.aws_subnets.public.ids
  tags = {
    Name = "Airbyte PostgreSQL Subnet Group"
  }
}

# Security Group for RDS (restrict access to Airbyte connector IPs)
resource "aws_security_group" "rds_sg" {
  name        = "airbyte-rds-sg"
  description = "Allow Airbyte connector access to PostgreSQL"
  vpc_id      = data.aws_vpc.default.id

  # Allow PostgreSQL from Airbyte connector (adjust CIDR as needed)
  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/8"] # Replace with Airbyte connector subnet CIDR
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "Airbyte RDS Security Group"
  }
}

# Output the RDS endpoint for connection
output "rds_endpoint" {
  value = aws_db_instance.airbyte_postgres.endpoint
}
```

