terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.5"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "random_password" "db_password" {
  length           = 16
  special          = true
  override_special = "!#$%&*()-_=+[]{}<>:?"
}

resource "aws_security_group" "rds_public_access" {
  name        = "rds-public-access-sg"
  description = "Allow public access to RDS MySQL instance"
  vpc_id      = "vpc-12345678" # Replace with your VPC ID or use aws_vpc.default

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # WARNING: This allows public access. Restrict as needed.
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "RDS Public Access SG"
  }
}

resource "aws_db_instance" "mysql" {
  allocated_storage    = 20
  engine               = "mysql"
  engine_version       = "8.0"
  instance_class       = "db.t3.micro"
  db_name              = "mydatabase"
  username             = "admin"
  password             = random_password.db_password.result
  parameter_group_name = "default.mysql8.0"
  skip_final_snapshot  = true
  publicly_accessible  = true # WARNING: This enables public access. Restrict as needed.
  vpc_security_group_ids = [aws_security_group.rds_public_access.id]
  db_subnet_group_name = "default-vpc-12345678" # Replace with your subnet group name or use aws_db_subnet_group.default

  tags = {
    Name = "MySQL-RDS-Instance"
  }
}

output "db_endpoint" {
  value = aws_db_instance.mysql.endpoint
}

output "db_password" {
  value     = random_password.db_password.result
  sensitive = true
}

