terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
  required_version = ">= 1.0.0"
}

provider "aws" {
  region = "us-east-1"
}

# VPC Configuration
resource "aws_vpc" "aurora_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "Aurora-MySQL-VPC"
  }
}

# Public Subnets
resource "aws_subnet" "public_subnets" {
  count                   = 2
  vpc_id                  = aws_vpc.aurora_vpc.id
  cidr_block              = "10.0.${count.index}.0/24"
  availability_zone       = element(["us-east-1a", "us-east-1b"], count.index)
  map_public_ip_on_launch = true
  tags = {
    Name = "Public-Subnet-${count.index}"
  }
}

# Private Subnets
resource "aws_subnet" "private_subnets" {
  count                   = 2
  vpc_id                  = aws_vpc.aurora_vpc.id
  cidr_block              = "10.0.${count.index + 2}.0/24"
  availability_zone       = element(["us-east-1a", "us-east-1b"], count.index)
  tags = {
    Name = "Private-Subnet-${count.index}"
  }
}

# Internet Gateway
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.aurora_vpc.id
  tags = {
    Name = "Aurora-MySQL-IGW"
  }
}

# Route Table for Public Subnets
resource "aws_route_table" "public_route_table" {
  vpc_id = aws_vpc.aurora_vpc.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }
  tags = {
    Name = "Public-Route-Table"
  }
}

# Route Table Association for Public Subnets
resource "aws_route_table_association" "public_association" {
  count          = 2
  subnet_id      = aws_subnet.public_subnets[count.index].id
  route_table_id = aws_route_table.public_route_table.id
}

# Security Group for RDS
resource "aws_security_group" "rds_sg" {
  name        = "Aurora-MySQL-SG"
  description = "Allow MySQL traffic"
  vpc_id      = aws_vpc.aurora_vpc.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "Aurora-MySQL-Security-Group"
  }
}

# Security Group for Proxy
resource "aws_security_group" "proxy_sg" {
  name        = "Aurora-MySQL-Proxy-SG"
  description = "Allow proxy traffic"
  vpc_id      = aws_vpc.aurora_vpc.id

  ingress {
    from_port   = 6432
    to_port     = 6432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "Aurora-MySQL-Proxy-Security-Group"
  }
}

# IAM Role for Secrets Manager
resource "aws_iam_role" "rds_secrets_role" {
  name = "Aurora-MySQL-Secrets-Role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "secretsmanager.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for Secrets Manager
resource "aws_iam_policy" "rds_secrets_policy" {
  name        = "Aurora-MySQL-Secrets-Policy"
  description = "Allow Secrets Manager to manage RDS secrets"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "rds:DescribeDBInstances",
          "rds:AddTagsToResource",
          "rds:RemoveTagsFromResource"
        ],
        Resource = "*"
      }
    ]
  })
}

# Attach IAM Policy to Role
resource "aws_iam_role_policy_attachment" "rds_secrets_attachment" {
  role       = aws_iam_role.rds_secrets_role.name
  policy_arn = aws_iam_policy.rds_secrets_policy.arn
}

# Aurora MySQL Cluster
resource "aws_db_cluster" "aurora_mysql" {
  cluster_identifier      = "aurora-mysql-cluster"
  engine                  = "aurora-mysql"
  engine_mode             = "provisioned"
  database_name           = "mydatabase"
  master_username         = "admin"
  master_password         = random_password.db_password.result
  backup_retention_period = 7
  preferred_backup_window = "07:00-09:00"
  skip_final_snapshot     = true
  vpc_security_group_ids  = [aws_security_group.rds_sg.id]
  db_subnet_group_name    = aws_db_subnet_group.private_subnet_group.name

  tags = {
    Name = "Aurora-MySQL-Cluster"
  }
}

# Aurora MySQL Instance
resource "aws_db_instance" "aurora_mysql" {
  identifier             = "aurora-mysql-instance"
  engine                 = aws_db_cluster.aurora_mysql.engine
  engine_version         = aws_db_cluster.aurora_mysql.engine_version
  db_cluster_identifier  = aws_db_cluster.aurora_mysql.id
  instance_class         = "db.r5.large"
  db_subnet_group_name   = aws_db_subnet_group.private_subnet_group.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  storage_type           = "gp2"
  allocated_storage      = 100
  max_allocated_storage  = 1000
  storage_encrypted      = true
  copy_tags_to_snapshot  = true
  skip_final_snapshot    = true
  publicly_accessible    = false
  multi_az               = true
  parameter_group_name   = "default.aurora-mysql5.7"
}

# DB Subnet Group
resource "aws_db_subnet_group" "private_subnet_group" {
  name       = "private-subnet-group"
  subnet_ids = aws_subnet.private_subnets[*].id
  tags = {
    Name = "Private-Subnet-Group"
  }
}

# Secrets Manager for RDS Credentials
resource "aws_secretsmanager_secret" "rds_credentials" {
  name        = "aurora-mysql-credentials"
  description = "Credentials for Aurora MySQL"
}

resource "aws_secretsmanager_secret_version" "rds_credentials_version" {
  secret_id     = aws_secretsmanager_secret.rds_credentials.id
  secret_string = jsonencode({
    username = aws_db_cluster.aurora_mysql.master_username
    password = aws_db_cluster.aurora_mysql.master_password
    engine   = aws_db_cluster.aurora_mysql.engine
    host     = aws_db_cluster.aurora_mysql.endpoint
  })
}

# Proxy Configuration (e.g., AWS RDS Proxy)
resource "aws_db_proxy" "aurora_proxy" {
  name                     = "aurora-mysql-proxy"
  engine_family            = "MYSQL"
  require_tls              = true
  vpc_subnet_ids           = aws_subnet.private_subnets[*].id
  vpc_security_group_ids   = [aws_security_group.proxy_sg.id]
  idle_client_timeout      = 1800
  max_connections          = 100
  role_arn                 = aws_iam_role.rds_proxy_role.arn
  secrets_provider {
    secret_arn     = aws_secretsmanager_secret.rds_credentials.arn
    secret_provider_type = "SECRETS_MANAGER"
    query_string_auth_enabled = false
  }
  tags = {
    Name = "Aurora-MySQL-Proxy"
  }
}

# IAM Role for RDS Proxy
resource "aws_iam_role" "rds_proxy_role" {
  name = "Aurora-MySQL-Proxy-Role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for RDS Proxy
resource "aws_iam_policy" "rds_proxy_policy" {
  name        = "Aurora-MySQL-Proxy-Policy"
  description = "Allow RDS Proxy to manage Aurora MySQL"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "secretsmanager:GetSecretValue",
          "secretsmanager:DescribeSecret"
        ],
        Resource = aws_secretsmanager_secret.rds_credentials.arn
      },
      {
        Effect = "Allow",
        Action = [
          "rds-db:connect"
        ],
        Resource = aws_db_cluster.aurora_mysql.arn
      }
    ]
  })
}

# Attach IAM Policy to Proxy Role
resource "aws_iam_role_policy_attachment" "rds_proxy_attachment" {
  role       = aws_iam_role.rds_proxy_role.name
  policy_arn = aws_iam_policy.rds_proxy_policy.arn
}

# Random Password for RDS
resource "random_password" "db_password" {
  length           = 16
  special          = true
  override_special = "!#$%&*()-_=+[]{}<>:?"
}
```

