```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
  required_version = ">= 1.0.0"
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# VPC Configuration
resource "aws_vpc" "aurora_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "aurora-vpc"
  }
}

# Public Subnets
resource "aws_subnet" "public_subnets" {
  count                   = 2
  vpc_id                  = aws_vpc.aurora_vpc.id
  cidr_block              = "10.0.${count.index}.0/24"
  availability_zone       = element(["us-east-1a", "us-east-1b"], count.index)
  map_public_ip_on_launch = true
  tags = {
    Name = "public-subnet-${count.index}"
  }
}

# Private Subnets
resource "aws_subnet" "private_subnets" {
  count             = 2
  vpc_id            = aws_vpc.aurora_vpc.id
  cidr_block        = "10.0.${count.index + 2}.0/24"
  availability_zone = element(["us-east-1a", "us-east-1b"], count.index)
  tags = {
    Name = "private-subnet-${count.index}"
  }
}

# Internet Gateway
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.aurora_vpc.id
  tags = {
    Name = "aurora-igw"
  }
}

# Route Table for Public Subnets
resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.aurora_vpc.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }
  tags = {
    Name = "public-rt"
  }
}

# Route Table Association for Public Subnets
resource "aws_route_table_association" "public_association" {
  count          = 2
  subnet_id      = aws_subnet.public_subnets[count.index].id
  route_table_id = aws_route_table.public_rt.id
}

# Security Group for RDS Proxy
resource "aws_security_group" "rds_proxy_sg" {
  name        = "rds-proxy-sg"
  description = "Allow inbound traffic to RDS Proxy"
  vpc_id      = aws_vpc.aurora_vpc.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-proxy-sg"
  }
}

# Security Group for RDS Cluster
resource "aws_security_group" "rds_sg" {
  name        = "rds-cluster-sg"
  description = "Allow inbound traffic to RDS Cluster"
  vpc_id      = aws_vpc.aurora_vpc.id

  ingress {
    from_port       = 3306
    to_port         = 3306
    protocol        = "tcp"
    security_groups = [aws_security_group.rds_proxy_sg.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-cluster-sg"
  }
}

# IAM Role for RDS Proxy
resource "aws_iam_role" "rds_proxy_role" {
  name = "rds-proxy-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for RDS Proxy
resource "aws_iam_policy" "rds_proxy_policy" {
  name        = "rds-proxy-policy"
  description = "Policy for RDS Proxy"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "secretsmanager:GetSecretValue",
          "secretsmanager:DescribeSecret",
          "secretsmanager:ListSecrets"
        ],
        Resource = "*"
      },
      {
        Effect = "Allow",
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents",
          "logs:DescribeLogStreams"
        ],
        Resource = "*"
      }
    ]
  })
}

# Attach IAM Policy to Role
resource "aws_iam_role_policy_attachment" "rds_proxy_attachment" {
  role       = aws_iam_role.rds_proxy_role.name
  policy_arn = aws_iam_policy.rds_proxy_policy.arn
}

# RDS Proxy
resource "aws_db_proxy" "rds_proxy" {
  name                     = "aurora-proxy"
  engine_family            = "MYSQL"
  role_arn                 = aws_iam_role.rds_proxy_role.arn
  require_tls              = true
  idle_client_timeout      = 1800
  debug_logging            = false
  vpc_security_group_ids   = [aws_security_group.rds_proxy_sg.id]
  vpc_subnet_ids           = aws_subnet.private_subnets[*].id
  secrets_provider {
    secret_arn = aws_secretsmanager_secret.rds_secret.arn
  }
  tags = {
    Name = "aurora-proxy"
  }
}

# Secrets Manager for RDS Credentials
resource "aws_secretsmanager_secret" "rds_secret" {
  name        = "aurora-mysql-secret"
  description = "Secret for Aurora MySQL credentials"
}

resource "aws_secretsmanager_secret_version" "rds_secret_version" {
  secret_id     = aws_secretsmanager_secret.rds_secret.id
  secret_string = jsonencode({
    username = "admin"
    password = "your_secure_password_here" # Change this to a secure password or use a random_password resource
  })
}

# Aurora MySQL Cluster
resource "aws_db_cluster" "aurora_mysql" {
  cluster_identifier      = "aurora-mysql-cluster"
  engine                  = "aurora-mysql"
  engine_mode             = "provisioned"
  database_name           = "mydatabase"
  master_username         = jsondecode(aws_secretsmanager_secret_version.rds_secret_version.secret_string)["username"]
  master_password         = jsondecode(aws_secretsmanager_secret_version.rds_secret_version.secret_string)["password"]
  backup_retention_period = 7
  preferred_backup_window = "07:00-09:00"
  skip_final_snapshot     = true
  vpc_security_group_ids  = [aws_security_group.rds_sg.id]
  db_subnet_group_name    = aws_db_subnet_group.aurora_subnet_group.name
  enable_http_endpoint    = false
  enable_https_endpoint   = true
  tags = {
    Name = "aurora-mysql-cluster"
  }
}

# Aurora MySQL Instance
resource "aws_db_instance" "aurora_mysql_instance" {
  identifier             = "aurora-mysql-instance"
  cluster_identifier     = aws_db_cluster.aurora_mysql.id
  engine                 = aws_db_cluster.aurora_mysql.engine
  engine_version         = aws_db_cluster.aurora_mysql.engine_version
  instance_class         = "db.r5.large"
  db_subnet_group_name   = aws_db_subnet_group.aurora_subnet_group.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  publicly_accessible    = false
  skip_final_snapshot    = true
  tags = {
    Name = "aurora-mysql-instance"
  }
}

# DB Subnet Group
resource "aws_db_subnet_group" "aurora_subnet_group" {
  name       = "aurora-subnet-group"
  subnet_ids = aws_subnet.private_subnets[*].id
  tags = {
    Name = "aurora-subnet-group"
  }
}
