    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.aurora_igw.id
  }
  tags = {
    Name = "aurora-public-rt"
  }
}

# Route Table Association for Public Subnets
resource "aws_route_table_association" "public_association" {
  count          = 2
  subnet_id      = aws_subnet.public_subnets[count.index].id
  route_table_id = aws_route_table.public_rt.id
}

# Security Group for RDS Proxy
resource "aws_security_group" "rds_proxy_sg" {
  name        = "rds-proxy-sg"
  description = "Allow connections to RDS Proxy"
  vpc_id      = aws_vpc.aurora_vpc.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-proxy-sg"
  }
}

# Security Group for RDS Cluster
resource "aws_security_group" "rds_cluster_sg" {
  name        = "rds-cluster-sg"
  description = "Allow connections to RDS Cluster"
  vpc_id      = aws_vpc.aurora_vpc.id

  ingress {
    from_port       = 3306
    to_port         = 3306
    protocol        = "tcp"
    security_groups = [aws_security_group.rds_proxy_sg.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-cluster-sg"
  }
}

# IAM Role for RDS Proxy
resource "aws_iam_role" "rds_proxy_role" {
  name = "rds-proxy-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for RDS Proxy
resource "aws_iam_role_policy" "rds_proxy_policy" {
  name = "rds-proxy-policy"
  role = aws_iam_role.rds_proxy_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "secretsmanager:GetSecretValue",
          "secretsmanager:DescribeSecret",
          "secretsmanager:ListSecrets"
        ],
        Resource = "*"
      }
    ]
  })
}

# Secrets Manager for RDS Credentials
resource "aws_secretsmanager_secret" "rds_secret" {
  name        = "aurora-mysql/credentials"
  description = "Credentials for Aurora MySQL"
}

resource "aws_secretsmanager_secret_version" "rds_secret_version" {
  secret_id     = aws_secretsmanager_secret.rds_secret.id
  secret_string = jsonencode({
    username = "admin"
    password = "SecurePassword123!"
  })
}

# RDS Proxy
resource "aws_rds_proxy" "aurora_proxy" {
  name                   = "aurora-mysql-proxy"
  engine_family          = "MYSQL"
  role_arn               = aws_iam_role.rds_proxy_role.arn
  require_tls            = true
  secrets_arn            = aws_secretsmanager_secret.rds_secret.arn
  vpc_subnet_ids         = aws_subnet.private_subnets[*].id
  security_group_ids     = [aws_security_group.rds_proxy_sg.id]
  endpoint_type          = "PRIVATE"
  idle_client_timeout    = 1800
  require_tls            = true
  debug_logging          = false
  enable_http_endpoint   = false
  tags = {
    Name = "aurora-mysql-proxy"
  }
}

# Aurora MySQL Cluster
resource "aws_db_cluster" "aurora_mysql" {
  cluster_identifier      = "aurora-mysql-cluster"
  engine                  = "aurora-mysql"
  engine_mode             = "provisioned"
  database_name           = "mydatabase"
  master_username         = jsondecode(aws_secretsmanager_secret_version.rds_secret_version.secret_string)["username"]
  master_password         = jsondecode(aws_secretsmanager_secret_version.rds_secret_version.secret_string)["password"]
  backup_retention_period = 5
  preferred_backup_window = "07:00-09:00"
  skip_final_snapshot     = true
  vpc_security_group_ids  = [aws_security_group.rds_cluster_sg.id]
  db_subnet_group_name    = aws_db_subnet_group.aurora_subnet_group.name
  enable_http_endpoint    = false
  storage_encrypted       = true
  tags = {
    Name = "aurora-mysql-cluster"
  }
}

# Aurora MySQL Subnet Group
resource "aws_db_subnet_group" "aurora_subnet_group" {
  name       = "aurora-subnet-group"
  subnet_ids = aws_subnet.private_subnets[*].id
  tags = {
    Name = "aurora-subnet-group"
  }
}

# Aurora MySQL Instance
resource "aws_db_instance" "aurora_mysql_instance" {
  identifier             = "aurora-mysql-instance"
  engine                 = "aurora-mysql"
  engine_version         = "8.0"
  db_cluster_identifier  = aws_db_cluster.aurora_mysql.id
  instance_class         = "db.r5.large"
  db_subnet_group_name   = aws_db_subnet_group.aurora_subnet_group.name
  vpc_security_group_ids = [aws_security_group.rds_cluster_sg.id]
  storage_type           = "gp2"
  storage_encrypted      = true
  backup_retention_period = 5
  skip_final_snapshot    = true
  tags = {
    Name = "aurora-mysql-instance"
  }
}

# Outputs
output "rds_proxy_endpoint" {
  value = aws_rds_proxy.aurora_proxy.endpoint
}

output "rds_cluster_endpoint" {
  value = aws_db_cluster.aurora_mysql.endpoint
}
