provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_lightsail_database" "managed_db" {
  name              = "my-managed-db"
  database_name     = "mydatabase"
  master_username   = "admin"
  master_password   = "SecurePassword123!" # Change to a strong password
  allocation        = "1 GB"               # Database storage allocation
  engine            = "mysql"              # Database engine (mysql, postgresql, etc.)
  engine_version    = "8.0"               # Engine version
  region            = "us-east-1"         # Must match provider region
  preferred_availability_zone = "us-east-1a"
  resource_name     = "my-managed-db-resource"
  parameter_group_name = "default.mysql8.0" # Default parameter group for MySQL 8.0
  public_access      = "no"                # Set to "yes" if public access is needed
  vpc_security_group_ids = [aws_lightsail_security_group.db_sg.id] # Optional: Attach to VPC security group
}

resource "aws_lightsail_security_group" "db_sg" {
  name        = "db-security-group"
  labels      = { Name = "db-sg" }
  description = "Security group for Lightsail managed database"
  region      = "us-east-1"

  ingress {
    protocol    = "tcp"
    port_range  = "3306" # MySQL default port (adjust for other engines)
    cidr_blocks = ["0.0.0.0/0"] # Restrict to specific IPs in production
  }

  egress {
    protocol    = "-1" # All protocols
    cidr_blocks = ["0.0.0.0/0"]
  }
}

output "db_endpoint" {
  value = aws_lightsail_database.managed_db.endpoint
}

output "db_resource_name" {
  value = aws_lightsail_database.managed_db.resource_name
}

