  name              = "postgres-db"
  database_name     = "postgres"
  master_username   = "admin" # Change to your preferred username
  master_password   = "YourSecurePassword123!" # Change to a secure password
  allocation        = "1GB" # Minimum allocation for Lightsail
  engine            = "postgres"
  engine_version    = "14" # Latest stable version as of 2023
  region            = "us-east-1" # Must match provider region
  preferred_backup_window = "00:00-01:00" # Backup window (24-hour window)
  auto_backup       = "true"
  preferred_availability_zone = "us-east-1a" # Change as needed
  db_instance_class = "db-small-1" # Small instance class

  # Enable immediate maintenance window changes
  maintenance_window = "now" # Forces immediate maintenance window change
  maintenance_window_utc = "now" # Forces immediate UTC maintenance window change

  tags = {
    Name = "PostgresDB"
    Environment = "Production" # Change as needed
  }
}

