provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create a Lightsail instance (compute service)
resource "aws_lightsail_instance" "compute_instance" {
  name              = "my-lightsail-compute"
  availability_zone = "us-east-1a"
  blueprint_id      = "ubuntu_22_04" # Change to your preferred blueprint
  bundle_id         = "nano_2_0"     # Change to your preferred bundle
  key_pair_name     = "your-key-pair" # Replace with your SSH key pair name

  # Optional: Configure networking
  network_interfaces {
    subnets = ["default"] # Use default subnet or specify your own
  }
}

# Create a Lightsail static IP (optional, if needed)
resource "aws_lightsail_static_ip" "static_ip" {
  name = "my-lightsail-static-ip"
}

# Attach the static IP to the instance (optional)
resource "aws_lightsail_static_ip_attachment" "static_ip_attachment" {
  static_ip_name = aws_lightsail_static_ip.static_ip.name
  instance_name  = aws_lightsail_instance.compute_instance.name
}

# Create a Lightsail storage (block storage)
resource "aws_lightsail_storage" "block_storage" {
  name          = "my-lightsail-block-storage"
  availability_zone = "us-east-1a"
  size_in_gb    = 10 # Adjust size as needed
}

# Attach the storage to the instance
resource "aws_lightsail_instance_attachment" "storage_attachment" {
  instance_name = aws_lightsail_instance.compute_instance.name
  storage_name  = aws_lightsail_storage.block_storage.name
  device_name   = "/dev/sdf" # Adjust device name if needed
}

# Output the instance's public IP (for testing/access)
