resource "aws_s3_bucket_policy" "allow_lightsail_access" {
  bucket = aws_s3_bucket.example.id
  policy = data.aws_iam_policy_document.lightsail_s3_access_policy.json
}

data "aws_iam_policy_document" "lightsail_s3_access_policy" {
  statement {
    actions   = ["s3:GetObject", "s3:PutObject", "s3:ListBucket"]
    resources = ["${aws_s3_bucket.example.arn}", "${aws_s3_bucket.example.arn}/*"]

    principals {
      type        = "*"
      identifiers = ["arn:aws:lightsail:${var.aws_region}:${data.aws_caller_identity.current.account_id}:resource/${aws_lightsail_instance.example.name}"]
    }
  }
}

