terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    aws_lightsail = {
      source  = "aws-lightsail/aws-lightsail"
      version = "~> 1.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

provider "aws_lightsail" {
  region = "us-east-1" # Must match AWS provider region
}

# Create a Lightsail Instance (Origin)
resource "aws_lightsail_instance" "origin_instance" {
  name              = "origin-server"
  availability_zone = "us-east-1a" # Change to your preferred AZ
  blueprint_id      = "ubuntu_22_04" # Ubuntu 22.04 LTS
  bundle_id         = "nano_2_0"      # Nano instance (adjust based on needs)

  key_pair_name = "origin-key-pair" # Replace with your existing key pair or create one

  # Configure instance for origin (e.g., web server)
  user_data = <<-EOF
              #!/bin/bash
              sudo apt update -y
              sudo apt install -y nginx
              sudo systemctl start nginx
              sudo systemctl enable nginx
              EOF

  tags = {
    Name = "Origin-Server"
    Role = "Origin"
  }
}

# Create a Lightsail Distribution (CDN)
resource "aws_lightsail_distribution" "cdn_distribution" {
  name = "origin-cdn"

  origin {
    domain_name = aws_lightsail_instance.origin_instance.public_ip_address
    origin_path = "/"
    custom_origin_config {
      http_port           = 80
      https_port          = 443
      origin_protocol_policy = "http-only"
      origin_ssl_protocols = ["TLSv1.2"]
    }
  }

  default_cache_behavior {
    target_origin_id = aws_lightsail_instance.origin_instance.name
    viewer_protocol_policy = "redirect-to-https"
    allowed_methods = ["GET", "HEAD"]
    cached_methods = ["GET", "HEAD"]
    forwarded_values {
      query_string = false
      cookies {
        forward = "none"
      }
    }
    min_ttl       = 0
    default_ttl   = 3600
    max_ttl       = 86400
  }

  enabled = true
  price_plan = "pay-as-you-go" # Adjust based on your needs

  tags = {
    Name = "Origin-CDN"
    Role = "Distribution"
  }
}

# Output the distribution domain name
output "cdn_domain_name" {
  value = aws_lightsail_distribution.cdn_distribution.distribution_domain_name
}

# Output the origin instance public IP
output "origin_instance_public_ip" {
  value = aws_lightsail_instance.origin_instance.public_ip_address
}

