terraform {
  required_version = ">= 1.0.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# S3 Bucket for Long-Term Data Storage with Versioning and Encryption
resource "aws_s3_bucket" "long_term_data" {
  bucket = "long-term-data-backup-${random_id.bucket_suffix.hex}" # Unique bucket name
  tags = {
    Name        = "LongTermDataBackup"
    Environment = "Production"
    Purpose     = "Long-term data storage and backup"
  }
}

# Random suffix to ensure bucket name uniqueness
resource "random_id" "bucket_suffix" {
  byte_length = 4
}

# Enable versioning for the bucket
resource "aws_s3_bucket_versioning" "versioning_enable" {
  bucket = aws_s3_bucket.long_term_data.id
  versioning_configuration {
    status = "Enabled"
  }
}

# Enable server-side encryption with SSE-S3
resource "aws_s3_bucket_server_side_encryption_configuration" "encryption" {
  bucket = aws_s3_bucket.long_term_data.id
  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# Block public access to the bucket
resource "aws_s3_bucket_public_access_block" "public_access_block" {
  bucket = aws_s3_bucket.long_term_data.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Enable default lifecycle rules for long-term storage (move to S3 Glacier after 30 days)
resource "aws_s3_bucket_lifecycle_configuration" "lifecycle_rule" {
  bucket = aws_s3_bucket.long_term_data.id

  rule {
    id     = "move-to-glacier-after-30-days"
    status = "Enabled"

    transition {
      days          = 30
      storage_class = "GLACIER"
    }

    expiration {
      days = 3650 # 10 years (optional: set to null to disable expiration)
    }
  }
}

# Enable S3 Object Lock for compliance and retention policies (optional)
resource "aws_s3_bucket_object_lock_configuration" "object_lock" {
  bucket = aws_s3_bucket.long_term_data.id

  rule {
    default_retention {
      mode = "GOVERNANCE"
      retain_until {
        days = 3650 # 10 years (adjust as needed)
      }
    }
  }
}

# IAM Policy for S3 Bucket Access (restrictive example)
resource "aws_iam_policy" "s3_bucket_policy" {
  name        = "s3-long-term-data-access"
  description = "Restrictive policy for long-term data bucket access"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:ListBucket",
          "s3:GetBucketLocation"
        ]
        Resource = aws_s3_bucket.long_term_data.arn
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:DeleteObject",
          "s3:RestoreObject"
        ]
        Resource = "${aws_s3_bucket.long_term_data.arn}/*"
        Condition = {
          StringEquals = {
            "aws:ResourceOwner" = "123456789012" # Replace with your AWS account ID
          }
        }
      }
    ]
  })
}

# Output the bucket name and ARN
output "s3_bucket_name" {
  value = aws_s3_bucket.long_term_data.bucket
}

output "s3_bucket_arn" {
  value = aws_s3_bucket.long_term_data.arn
}

