# Configure S3 Glacier storage class for the bucket
resource "aws_s3_bucket_versioning" "glacier_vault_versioning" {
  bucket = aws_s3_bucket.glacier_vault.id
  versioning_configuration {
    status = "Enabled"
  }
}

# Create S3 Lifecycle Configuration to transition objects to Glacier
resource "aws_s3_bucket_lifecycle_configuration" "glacier_transition" {
  bucket = aws_s3_bucket.glacier_vault.id

  rule {
    id     = "transition-to-glacier"
    status = "Enabled"

    transition {
      days          = 30 # Transition after 30 days
      storage_class = "GLACIER" # Transition to Glacier
    }

    transition {
      days          = 90 # Transition to Deep Archive after 90 days
      storage_class = "DEEP_ARCHIVE"
    }

    expiration {
      days = 3650 # Delete after 10 years (optional)
    }
  }
}

# AWS Data Lifecycle Manager (DLM) Configuration
resource "aws_dlm_lifecycle_policy" "glacier_policy" {
  description = "Policy to manage S3 lifecycle transitions to Glacier"

  policy_shape {
    copy_tags_to_replicas    = false
    name                     = "glacier-transition-policy"
    schedule                 = "cron(0 12 * * ? *)" # Daily at 12:00 UTC
    tags_to_copy             = []
    state                    = "ENABLED"
    state_message            = "Managed by Terraform"
    tags                     = {
      Environment = "Production"
    }
    versioning_configuration {
      status = "Enabled"
    }
  }

  resource_types = ["S3"]

  target_tags = {
    "LifecyclePolicy" = "glacier-transition-policy"
  }
}

# IAM Role for DLM (if not using default)
resource "aws_iam_role" "dlm_role" {
  name = "dlm-s3-glacier-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dlm.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "dlm_s3_full_access" {
  role       = aws_iam_role.dlm_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3FullAccess"
}

# Attach the DLM policy to the S3 bucket
resource "aws_s3_bucket_policy" "dlm_bucket_policy" {
  bucket = aws_s3_bucket.glacier_vault.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Principal = {
          AWS = aws_iam_role.dlm_role.arn
        },
        Action = [
          "s3:ListBucket",
          "s3:GetBucketVersioning"
        ],
        Resource = aws_s3_bucket.glacier_vault.arn
      },
      {
        Effect = "Allow",
        Principal = {
          AWS = aws_iam_role.dlm_role.arn
        },
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:DeleteObject",
          "s3:GetObjectVersion"
        ],
        Resource = "${aws_s3_bucket.glacier_vault.arn}/*"
      }
    ]
  })
}

