}

# IAM Policy Document for S3 Glacier Vault Access
data "aws_iam_policy_document" "glacier_vault_policy" {
  statement {
    actions = [
      "glacier:CreateVault",
      "glacier:DeleteVault",
      "glacier:GetVaultNotification",
      "glacier:PutVaultNotification",
      "glacier:DeleteVaultNotification",
      "glacier:ListVaults",
      "glacier:GetVaultLock",
      "glacier:InitiateJob",
      "glacier:AbortJob",
      "glacier:GetJobOutput",
      "glacier:GetVaultLock",
      "glacier:PutVaultLock",
      "glacier:DescribeVault",
      "glacier:ListJobs",
      "glacier:GetVault",
      "glacier:RetrieveArchive",
      "glacier:UploadArchive",
      "glacier:DeleteArchive",
      "glacier:InitiateMultipartUpload",
      "glacier:UploadMultipartPart",
      "glacier:CompleteMultipartUpload",
      "glacier:AbortMultipartUpload",
      "glacier:ListMultipartUploads",
      "glacier:GetMultipartUploadParts",
    ]
    resources = ["*"]
    principals {
      type        = "AWS"
      identifiers = ["arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"] # Replace with specific IAM roles/users if needed
    }
  }
}

