    rules {
      name  = "Retention"
      type  = "RetentionPeriod"
      value = "365" # 1 year retention period
    }
    rules {
      name  = "LegalHold"
      type  = "LegalHold"
      value = "true"
    }
  }
}

# Output the vault ARN for reference
output "glacier_vault_arn" {
  value = aws_glacier_vault.example.arn
}

