  internal           = true
  load_balancer_type = "network"
  subnets            = [aws_subnet.internal_lb_subnet.id]

  enable_deletion_protection = false

  tags = {
    Name = "internal-lb"
  }
}

resource "aws_lb_target_group" "internal_lb_tg" {
  name     = "internal-lb-tg"
  port     = 80
  protocol = "TCP"
  vpc_id   = aws_vpc.internal_lb_vpc.id

  health_check {
