resource "aws_route_table" "internal_lb_route_table" {
  vpc_id = aws_vpc.internal_lb_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.internal_lb_igw.id
  }

  tags = {
    Name = "internal-lb-route-table"
  }
}

resource "aws_route_table_association" "internal_lb_route_association" {
  subnet_id      = aws_subnet.internal_lb_subnet.id
  route_table_id = aws_route_table.internal_lb_route_table.id
}

resource "aws_network_interface" "internal_lb_nic" {
  subnet_id       = aws_subnet.internal_lb_subnet.id
  private_ips     = ["10.0.1.100", "10.0.1.101"] # Specified private IPs
  security_groups = [aws_security_group.internal_lb_sg.id]

  tags = {
    Name = "internal-lb-nic"
  }
}

resource "aws_security_group" "internal_lb_sg" {
  name        = "internal-lb-sg"
  description = "Security group for internal load balancer"
  vpc_id      = aws_vpc.internal_lb_vpc.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Allow traffic from VPC
  }

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Allow traffic from VPC
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "internal-lb-sg"
  }
}

resource "aws_lb" "internal_lb" {
  name               = "internal-lb"
  internal           = true
  load_balancer_type = "network"
  subnets            = [aws_subnet.internal_lb_subnet.id]

  enable_deletion_protection = false

  tags = {
    Name = "internal-lb"
  }
}

resource "aws_lb_target_group" "internal_lb_tg" {
  name     = "internal-lb-tg"
  port     = 80
  protocol = "TCP"
  vpc_id   = aws_vpc.internal_lb_vpc.id

  health_check {
    enabled             = true
    interval            = 30
    path                = "/"
    port                = "traffic-port"
    protocol            = "HTTP"
    healthy_threshold   = 3
    unhealthy_threshold = 3
    timeout             = 5
    matcher             = "200-399"
  }

  tags = {
    Name = "internal-lb-tg"
  }
}

resource "aws_lb_listener" "internal_lb_listener" {
  load_balancer_arn = aws_lb.internal_lb.arn
  port              = "80"
  protocol          = "TCP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.internal_lb_tg.arn
  }
}

resource "aws_lb_target_group_attachment" "internal_lb_tg_attachment" {
  target_group_arn = aws_lb_target_group.internal_lb_tg.arn
  target_id        = aws_network_interface.internal_lb_nic.id
  port             = 80
}

resource "aws_lb_target_group_attachment" "internal_lb_tg_attachment_2" {
  target_group_arn = aws_lb_target_group.internal_lb_tg.arn
  target_id        = aws_network_interface.internal_lb_nic.id
  port             = 80
  subnet_id        = aws_subnet.internal_lb_subnet.id
}

# Note: The above configuration is a simplified example. For a real internal load balancer,
# you would typically attach EC2 instances or other targets instead of network interfaces.
# If you need to attach EC2 instances, you would use aws_instance resources and attach them to the target group.
