terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_lb" "authenticate_cognito_lb" {
  name               = "authenticate-cognito-lb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.lb_sg.id]
  subnets            = [aws_subnet.public_subnet_1.id, aws_subnet.public_subnet_2.id] # Replace with your subnet IDs

  enable_deletion_protection = false # Set to true for production environments
}

resource "aws_security_group" "lb_sg" {
  name        = "authenticate-cognito-lb-sg"
  description = "Security group for ALB with Cognito authentication"
  vpc_id      = aws_vpc.main.id # Replace with your VPC ID

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "authenticate-cognito-lb-sg"
  }
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "authenticate-cognito-vpc"
  }
}

resource "aws_subnet" "public_subnet_1" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = true

  tags = {
    Name = "authenticate-cognito-public-subnet-1"
  }
}

resource "aws_subnet" "public_subnet_2" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-east-1b"
  map_public_ip_on_launch = true

  tags = {
    Name = "authenticate-cognito-public-subnet-2"
  }
}

resource "aws_lb_listener" "cognito_auth_listener" {
  load_balancer_arn = aws_lb.authenticate_cognito_lb.arn
  port              = 443
  protocol          = "HTTPS"
  ssl_policy        = "ELBSecurityPolicy-2016-08"
  certificate_arn   = "arn:aws:acm:us-east-1:123456789012:certificate/xxxxxxxx-xxxx-xxxx-xxxx-xxxxxxxxxxxx" # Replace with your ACM certificate ARN

  default_action {
    type = "authenticate-cognito"
    authenticate_cognito {
      user_pool_arn       = "arn:aws:cognito-idp:us-east-1:123456789012:userpool/us-east-1_xxxxxxxx" # Replace with your Cognito User Pool ARN
      user_pool_client_id = "xxxxxxxxxxxxxxxxxxxx" # Replace with your Cognito User Pool Client ID
      user_pool_domain    = "your-user-pool-domain.auth.us-east-1.amazoncognito.com" # Replace with your Cognito Domain
      authentication_request_extra_params = {
        redirect_uri = "https://your-app-domain.com/callback"
        response_type = "code"
        scope         = "openid email"
      }
    }
  }
}

resource "aws_lb_listener" "http_to_https" {
  load_balancer_arn = aws_lb.authenticate_cognito_lb.arn
  port              = 80
  protocol          = "HTTP"

  default_action {
    type = "redirect"
    redirect {
      port        = "443"
      protocol    = "HTTPS"
      status_code = "HTTP_301"
    }
  }
}

