provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# IAM Role for OIDC Authentication
resource "aws_iam_role" "oidc_auth_role" {
  name = "oidc-auth-loadbalancer-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRoleWithWebIdentity"
        Effect = "Allow"
        Principal = {
          Federated = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:oidc-provider/${replace(var.oidc_provider, "https://", "")}"
        }
        Condition = {
          StringLike = {
            "${replace(var.oidc_provider, "https://", "")}:sub" = "system:serviceaccount:kubernetes:default"
          }
        }
      }
    ]
  })
}

# IAM Policy for OIDC Authentication
resource "aws_iam_policy" "oidc_auth_policy" {
  name        = "oidc-auth-loadbalancer-policy"
  description = "Policy for OIDC authentication with ALB"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = ["sts:AssumeRoleWithWebIdentity"]
        Resource = aws_iam_role.oidc_auth_role.arn
      },
      {
        Effect = "Allow"
        Action = [
          "elasticloadbalancing:AddTags",
          "elasticloadbalancing:Describe*",
          "elasticloadbalancing:Modify*",
          "elasticloadbalancing:Register*",
          "elasticloadbalancing:Set*",
          "elasticloadbalancing:Delete*"
        ]
        Resource = "*"
      }
    ]
  })
}

# Attach IAM Policy to Role
resource "aws_iam_role_policy_attachment" "oidc_auth_attachment" {
  role       = aws_iam_role.oidc_auth_role.name
  policy_arn = aws_iam_policy.oidc_auth_policy.arn
}

# ALB (Application Load Balancer)
resource "aws_lb" "app_lb" {
  name               = "oidc-auth-alb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = [aws_subnet.public_subnet_1.id, aws_subnet.public_subnet_2.id]

  enable_deletion_protection = false
}

# Security Group for ALB
resource "aws_security_group" "alb_sg" {
  name        = "oidc-auth-alb-sg"
  description = "Allow HTTP/HTTPS traffic to ALB"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Target Group for ALB
resource "aws_lb_target_group" "app_tg" {
  name     = "oidc-auth-tg"
  port     = 80
  protocol = "HTTP"
  vpc_id   = aws_vpc.main.id

  health_check {
    path                = "/health"
    interval            = 30
    timeout             = 5
    healthy_threshold   = 2
    unhealthy_threshold = 2
    matcher             = "200-299"
  }
}

# Listener for ALB with OIDC Authentication
resource "aws_lb_listener" "oidc_auth_listener" {
  load_balancer_arn = aws_lb.app_lb.arn
  port              = 443
  protocol          = "HTTPS"
  ssl_policy        = "ELBSecurityPolicy-2016-08"
  certificate_arn   = aws_acm_certificate.lb_cert.arn

  default_action {
    type = "authenticate-oidc"

    authenticate_oidc {
      authorization_endpoint = var.oidc_authorization_endpoint
      client_id              = var.oidc_client_id
      client_secret          = var.oidc_client_secret
      issuer                 = var.oidc_issuer
      on_unauthenticated_request = "authenticate"
      scope                  = "openid email profile"
      token_endpoint         = var.oidc_token_endpoint
      user_info_endpoint     = var.oidc_user_info_endpoint
