terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# VPC Configuration
resource "aws_vpc" "gwlb_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "gwlb-vpc"
  }
}

# Internet Gateway
resource "aws_internet_gateway" "gwlb_igw" {
  vpc_id = aws_vpc.gwlb_vpc.id
  tags = {
    Name = "gwlb-igw"
  }
}

# Public Subnets
resource "aws_subnet" "gwlb_public_subnets" {
  count                   = 2 # Create 2 public subnets across 2 availability zones
  vpc_id                  = aws_vpc.gwlb_vpc.id
  cidr_block              = "10.0.${count.index}.0/24"
  availability_zone       = element(["us-east-1a", "us-east-1b"], count.index)
  map_public_ip_on_launch = true
  tags = {
    Name = "gwlb-public-subnet-${count.index}"
  }
}

# Route Table for Public Subnets
resource "aws_route_table" "gwlb_public_rt" {
  vpc_id = aws_vpc.gwlb_vpc.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.gwlb_igw.id
  }
  tags = {
    Name = "gwlb-public-rt"
  }
}

# Associate Route Table with Public Subnets
resource "aws_route_table_association" "gwlb_public_rt_association" {
  count          = 2
  subnet_id      = aws_subnet.gwlb_public_subnets[count.index].id
  route_table_id = aws_route_table.gwlb_public_rt.id
}

# Security Group for Gateway Load Balancer
resource "aws_security_group" "gwlb_sg" {
  name        = "gwlb-security-group"
  description = "Allow inbound traffic to Gateway Load Balancer"
  vpc_id      = aws_vpc.gwlb_vpc.id

  ingress {
    from_port   = 6081
    to_port     = 6081
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "gwlb-sg"
  }
}

# Gateway Load Balancer (GWLB)
resource "aws_lb" "gwlb" {
  name               = "gwlb-example"
  internal           = false
  load_balancer_type = "gateway"
  subnets            = aws_subnet.gwlb_public_subnets[*].id
  security_groups    = [aws_security_group.gwlb_sg.id]

  enable_deletion_protection = false

  tags = {
    Name = "gwlb-example"
  }
}

# Gateway Load Balancer Endpoint Group
resource "aws_lb_target_group" "gwlb_tg" {
  name        = "gwlb-target-group"
  port        = 6081
  protocol    = "TCP"
  target_type = "ip"
  vpc_id      = aws_vpc.gwlb_vpc.id
}

# Gateway Load Balancer Listener
resource "aws_lb_listener" "gwlb_listener" {
  load_balancer_arn = aws_lb.gwlb.arn
  port              = "6081"
  protocol          = "TCP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.gwlb_tg.arn
  }
}

