terraform {
  required_providers {
    google = {
      source  = "hashicorp/google"
      version = "~> 4.0"
    }
  }
}

provider "google" {
  project = var.project_id
  region  = var.region
}

variable "project_id" {
  description = "The GCP project ID"
  type        = string
}

variable "region" {
  description = "The GCP region"
  type        = string
  default     = "us-central1"
}

variable "network" {
  description = "The VPC network name"
  type        = string
  default     = "default"
}

variable "subnetwork" {
  description = "The subnetwork name"
  type        = string
  default     = "default"
}

resource "google_compute_region_network_endpoint_group" "neg" {
  name                  = "neg-${var.project_id}"
  network_endpoint_type = "SERVERLESS_LOAD_BALANCER"
  region                = var.region
  network               = var.network
  subnetwork            = var.subnetwork
}

resource "google_compute_region_target_http_proxy" "proxy" {
  name    = "proxy-${var.project_id}"
  region  = var.region
  url_map = google_compute_region_url_map.url_map.id
}

resource "google_compute_region_url_map" "url_map" {
  name            = "url-map-${var.project_id}"
  region          = var.region
  default_service = google_compute_region_backend_service.backend.id
}

resource "google_compute_region_backend_service" "backend" {
  name                  = "backend-${var.project_id}"
  region                = var.region
  health_checks         = [google_compute_health_check.http_health_check.id]
  security_policy       = var.security_policy
  session_affinity      = "CLIENT_IP"
  timeout_sec           = 30
  connection_draining_timeout_sec = 300

  backend {
    group = google_compute_region_network_endpoint_group.neg.id
  }
}

resource "google_compute_health_check" "http_health_check" {
  name                = "http-health-check-${var.project_id}"
  region              = var.region
  timeout_sec         = 1
  check_interval_sec  = 15
  healthy_threshold   = 2
  unhealthy_threshold = 5

  http_health_check {
    port = 80
    request_path = "/"
  }
}

resource "google_compute_region_forwarding_rule" "forwarding_rule" {
  name                  = "forwarding-rule-${var.project_id}"
  region                = var.region
  target                = google_compute_region_target_http_proxy.proxy.id
  port_range            = "80"
  ip_address            = google_compute_global_address.lb_ip.address
  load_balancing_scheme = "EXTERNAL"
}

resource "google_compute_global_address" "lb_ip" {
  name         = "lb-ip-${var.project_id}"
  project      = var.project_id
  address_type = "EXTERNAL"
  ip_version   = "IPV4"
}

resource "google_compute_firewall" "allow_http" {
  name    = "allow-http-${var.project_id}"
  network = var.network

  allow {
    protocol = "tcp"
    ports    = ["80"]
  }

  source_ranges = ["0.0.0.0/0"]
  target_tags   = ["http-server"]
}

