provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_db_instance" "memory_optimized_postgres" {
  allocated_storage    = 100 # Adjust based on your needs
  engine               = "aurora-postgresql"
  engine_version       = "15.4" # Latest stable version as of writing
  instance_class       = "db.r6g.large" # Memory-optimized instance type
  db_name              = "memory_optimized_db"
  username             = "admin"
  password             = "your_secure_password_here" # Use AWS Secrets Manager in production
  skip_final_snapshot  = true # Set to false if you want automated snapshots
  storage_encrypted    = true
  copy_tags_to_snapshot = true

  # Memory-optimized configuration
  parameter_group_name = aws_db_parameter_group.memory_optimized_postgres.name
  db_subnet_group_name = aws_db_subnet_group.memory_optimized_postgres.name

  # Performance tuning for memory optimization
  max_allocated_storage = 1000 # Adjust based on your needs
  storage_type          = "gp3" # General Purpose SSD for better performance
  iops                  = 3000  # Higher IOPS for memory workloads
}

resource "aws_db_parameter_group" "memory_optimized_postgres" {
  name        = "memory-optimized-postgres-pg"
  family      = "aurora-postgresql15"
  description = "Parameter group optimized for memory-intensive PostgreSQL workloads"

  parameter {
    name  = "shared_buffers"
    value = "256MB" # Adjust based on instance size (e.g., 16GB RAM = 4GB shared_buffers)
  }

  parameter {
    name  = "effective_cache_size"
    value = "12GB" # Typically 70-80% of total RAM
  }

  parameter {
    name  = "work_mem"
    value = "16MB" # Increased for complex queries
  }

  parameter {
    name  = "maintenance_work_mem"
    value = "512MB" # For VACUUM and other maintenance operations
  }

  parameter {
    name  = "random_page_cost"
    value = "1.1" # Optimized for SSD storage
  }

  parameter {
    name  = "effective_io_concurrency"
    value = "200" # Higher for SSD storage
  }
}

resource "aws_db_subnet_group" "memory_optimized_postgres" {
  name       = "memory-optimized-postgres-subnet-group"
  subnet_ids = [aws_subnet.private_subnet_1.id, aws_subnet.private_subnet_2.id] # Replace with your private subnets

  tags = {
    Name = "Memory-Optimized-Postgres-Subnet-Group"
  }
}

resource "aws_subnet" "private_subnet_1" {
