  allocated_storage    = 20 # Adjust based on your snapshot size
  engine               = "postgres" # Change to your preferred engine (e.g., "mysql", "oracle-ee")
  engine_version       = "15.4" # Adjust to match your snapshot's engine version
  instance_class       = "db.t3.micro" # Adjust based on your needs
  db_name              = "restored_db" # Change to your desired database name
