terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# S3 bucket to store the database backup
resource "aws_s3_bucket" "db_backup_bucket" {
  bucket = "my-db-backup-bucket-${random_id.bucket_suffix.hex}" # Unique bucket name
}

resource "random_id" "bucket_suffix" {
  byte_length = 4
}

# IAM role for RDS to access S3
resource "aws_iam_role" "rds_s3_access_role" {
  name = "rds-s3-access-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "rds_s3_access" {
  role       = aws_iam_role.rds_s3_access_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3ReadOnlyAccess"
}

# Database snapshot from S3 (using AWS DMS or manual process)
# Note: This example assumes you have a pre-uploaded DB snapshot in S3
# and will use AWS Database Migration Service (DMS) to restore it

resource "aws_dms_replication_instance" "db_restore" {
  allocated_storage    = 20
  engine_name         = "mysql" # Change to your DB engine (e.g., postgres, oracle)
  instance_class      = "dms.t3.medium"
  publicly_accessible = false
  vpc_security_group_ids = [aws_security_group.dms_sg.id]
  tags = {
    Name = "dms-replication-instance"
  }
}

resource "aws_security_group" "dms_sg" {
  name        = "dms-security-group"
  description = "Allow inbound traffic for DMS"
  vpc_id      = aws_vpc.main.id # Replace with your VPC ID or create one

  ingress {
    from_port   = 3306 # MySQL default port (change for other DBs)
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict this in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "main-vpc"
  }
}

resource "aws_subnet" "private" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"
  tags = {
    Name = "private-subnet"
  }
}

resource "aws_db_subnet_group" "db_subnet_group" {
  name       = "db-subnet-group"
  subnet_ids = [aws_subnet.private.id] # Add more private subnets for HA
  tags = {
    Name = "db-subnet-group"
  }
}

# Create a target RDS instance (this will be restored from S3)
resource "aws_db_instance" "restored_db" {
  allocated_storage      = 20
  engine                 = "mysql" # Change to your DB engine
  engine_version         = "8.0"   # Change to your DB version
  instance_class         = "db.t3.micro"
  db_name                = "restored_database"
  username               = "admin"
  password               = "your-secure-password" # Use secrets manager in production
  skip_final_snapshot    = true
  db_subnet_group_name   = aws_db_subnet_group.db_subnet_group.name
  vpc_security_group_ids = [aws_security_group.db_sg.id]
  storage_encrypted      = true
  backup_retention_period = 7
  multi_az               = false # Set to true for production
  publicly_accessible    = false
  tags = {
    Name = "restored-db-instance"
  }
}

resource "aws_security_group" "db_sg" {
  name        = "db-security-group"
  description = "Allow inbound traffic to DB"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306 # MySQL default port
    to_port     = 3306
    protocol    = "tcp"
    security_groups = [aws_security_group.dms_sg.id] # Allow DMS to access DB
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Example DMS task to restore from S3 (simplified)
# Note: This assumes you have a pre-configured S3 bucket with DB backup files
# and a DMS replication instance already set up
resource "aws_dms_endpoint" "source_endpoint" {
  endpoint_type = "source"
  engine_name   = "mysql" # Change to your DB engine
  server_name   = "s3://${aws_s3_bucket.db_backup_bucket.bucket}/path/to/backup" # Replace with your S3 path
  username      = "backup_user" # If applicable
  password      = "backup_password" # If applicable
}

resource "aws_dms_endpoint" "target_endpoint" {
  endpoint_type = "target"
  engine_name   = "mysql" # Change to your DB engine
  server_name   = aws_db_instance.restored_db.endpoint
  username      = aws_db_instance.restored_db.username
  password      = aws_db_instance.restored_db.password
}

resource "aws_dms_replication_task" "db_restore_task" {
  replication_instance_arn = aws_dms_replication_instance.db_restore.arn
  source_endpoint_arn      = aws_dms_endpoint.source_endpoint.arn
  target_endpoint_arn      = aws_dms_endpoint.target_endpoint.arn
  migration_type           = "full-load"
  table_mappings           = <<EOF
{
  "rules": [
    {
      "rule-type": "selection",
      "object-listing": "EXISTING_ONLY",
      "rule-id": "1",
      "rule-name": "SelectAllTables"
    },
    {
      "rule-type": "transform",
      "rule-id": "2",
      "rule-name": "AddSchemaToTables",
      "object-name": "%",
      "search-pattern": "%",
      "transform-value": "schema_name.%"
    }
  ]
}
EOF
  depends_on = [aws_db_instance.restored_db]
}

