  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_db_instance" "auto_scaling_db" {
  identifier             = "auto-scaling-db-instance"
  engine                 = "aurora-mysql" # Aurora MySQL for auto-scaling support
  engine_version         = "8.0.33"       # Latest stable version (adjust as needed)
  instance_class         = "db.t3.medium" # Starter instance class (will scale automatically)
  storage_type           = "aurora"       # Aurora storage engine
  allocated_storage      = 20             # Initial storage (will auto-scale)
  max_allocated_storage  = 1024           # Max storage limit (adjust as needed)
  storage_encrypted      = true           # Enable encryption
  publicly_accessible    = false          # Set to true if needed
  skip_final_snapshot    = true           # Disable final snapshot for demo (set to false in production)
  backup_retention_period = 7             # Backup retention in days
  multi_az               = true           # Enable Multi-AZ deployment for high availability

  # Auto-scaling configuration
  storage_autoscaling {
    auto_pause               = true
    enabled                  = true
    kms_key_id               = aws_kms_key.db_encryption_key.arn
    monitored_issues_threshold = 10.0
    scale_in_cooldown        = 300
    scale_out_cooldown       = 60
    target_percentage        = 70.0
  }

  # Database settings
  username = "admin"
  password = "your_secure_password_here" # Use AWS Secrets Manager in production
  db_name   = "autoscalingdb"

  # VPC and security group configuration (adjust as needed)
  vpc_security_group_ids = [aws_security_group.db_sg.id]
  db_subnet_group_name   = aws_db_subnet_group.db_subnet_group.name

  # Performance and maintenance
  copy_tags_to_snapshot = true
  parameter_group_name  = "default.aurora-mysql8.0"
  option_group_name     = "default:aurora-mysql"
}

resource "aws_kms_key" "db_encryption_key" {
  description = "KMS key for database encryption"
  policy      = data.aws_iam_policy_document.kms_key_policy.json
}

data "aws_iam_policy_document" "kms_key_policy" {
  statement {
    sid    = "Enable IAM User Permissions"
    effect = "Allow"
    principals {
      type        = "AWS"
      identifiers = ["arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"]
    }
    actions   = ["kms:*"]
    resources = ["*"]
  }
}

data "aws_caller_identity" "current" {}

resource "aws_security_group" "db_sg" {
  name        = "db-security-group"
  description = "Security group for database access"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Adjust based on your VPC CIDR
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  enable_dns_support = true
  enable_dns_hostnames = true
  tags = {
    Name = "main-vpc"
  }
}

resource "aws_subnet" "private_subnets" {
  count             = 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.${count.index}.0/24"
  availability_zone = element(data.aws_availability_zones.available.names, count.index)
  tags = {
    Name = "private-subnet-${count.index}"
  }
}

data "aws_availability_zones" "available" {}

resource "aws_db_subnet_group" "db_subnet_group" {
  name       = "db-subnet-group"
  subnet_ids = aws_subnet.private_subnets[*].id
  tags = {
    Name = "db-subnet-group"
  }
}

