```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create a KMS key for encrypting the database
resource "aws_kms_key" "db_kms_key" {
  description             = "KMS key for encrypting RDS database"
  deletion_window_in_days = 30
  enable_key_rotation     = true
  policy                  = data.aws_iam_policy_document.kms_key_policy.json
}

data "aws_iam_policy_document" "kms_key_policy" {
  statement {
    sid    = "Enable IAM User Permissions"
    effect = "Allow"
    principals {
      type        = "AWS"
      identifiers = ["arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"]
    }
    actions   = ["kms:*"]
    resources = ["*"]

    condition {
      test     = "Bool"
      variable = "kms:GrantIsForAWSResource"
      values   = ["true"]
    }
  }

  statement {
    sid    = "Allow RDS to use the key"
    effect = "Allow"
    principals {
      type        = "Service"
      identifiers = ["rds.amazonaws.com"]
    }
    actions = [
      "kms:Encrypt",
      "kms:Decrypt",
      "kms:ReEncrypt*",
      "kms:GenerateDataKey*",
      "kms:DescribeKey"
    ]
    resources = ["*"]
  }
}

# Create a secret for the database master password
resource "aws_secretsmanager_secret" "db_secret" {
  name        = "rds-master-password"
  description = "Master password for RDS database"
}

# Store the master password in Secrets Manager
resource "aws_secretsmanager_secret_version" "db_secret_version" {
  secret_id     = aws_secretsmanager_secret.db_secret.id
  secret_string = random_password.db_password.result
}

resource "random_password" "db_password" {
  length           = 32
  special          = true
  override_special = "_%@"
}

# Create an IAM policy for Secrets Manager to access the database
resource "aws_iam_policy" "secrets_manager_policy" {
  name        = "rds-secrets-manager-policy"
  description = "Policy for Secrets Manager to access RDS"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "secretsmanager:GetSecretValue",
          "secretsmanager:DescribeSecret"
        ]
        Resource = aws_secretsmanager_secret.db_secret.arn
      },
      {
        Effect = "Allow"
        Action = [
          "kms:Decrypt"
        ]
        Resource = aws_kms_key.db_kms_key.arn
      }
    ]
  })
}

# Create the RDS database instance
resource "aws_db_instance" "example" {
  identifier             = "managed-master-password-db"
  engine                 = "postgres" # Change to your preferred engine (e.g., "mysql", "oracle-ee")
  engine_version         = "15.3"     # Change to your preferred version
  instance_class         = "db.t3.micro" # Change to your preferred instance class
  allocated_storage      = 20
  storage_type           = "gp2"
  username               = "admin"     # Change to your preferred username
  password               = jsondecode(data.aws_secretsmanager_secret_version.db_secret_version.secret_string)["password"]
  parameter_group_name   = "default.postgres15" # Change to your preferred parameter group
  skip_final_snapshot    = true
  db_subnet_group_name   = aws_db_subnet_group.example.name
  vpc_security_group_ids = [aws_security_group.db_sg.id]
  kms_key_id             = aws_kms_key.db_kms_key.arn
  storage_encrypted      = true
  apply_immediately      = true

  # Enable Secrets Manager integration
  enable_performance_insights = false
  performance_insights_retention_period = 7

  # Use Secrets Manager for master password
  option_group_name = "default:postgres-15" # Change to your preferred option group

  depends_on = [
    aws_secretsmanager_secret_version.db_secret_version
  ]
}

# Create a DB subnet group
resource "aws_db_subnet_group" "example" {
  name       = "main-db-subnet-group"
  subnet_ids = [aws_subnet.example1.id, aws_subnet.example2.id] # Replace with your subnet IDs
}

# Create security group for the database
resource "aws_security_group" "db_sg" {
  name        = "db-security-group"
  description = "Security group for RDS database"
  vpc_id      = aws_vpc.example.id

  ingress {
    from_port   = 5432 # Change to your preferred port (e.g., 3306 for MySQL)
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict this to your VPC CIDR or specific IPs
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Create VPC and subnets for the database
resource "aws_vpc" "example" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "example1" {
  vpc_id            = aws_vpc.example.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "example2" {
  vpc_id            = aws_vpc.example.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

# Get current AWS account ID
