terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create an IAM policy for EFS lifecycle management
resource "aws_iam_policy" "efs_lifecycle_policy" {
  name        = "efs-lifecycle-policy"
  description = "Policy for managing EFS lifecycle"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = [
          "elasticfilesystem:DescribeLifecycleConfiguration",
          "elasticfilesystem:PutLifecycleConfiguration",
          "elasticfilesystem:DeleteLifecycleConfiguration"
        ]
        Resource = "*"
      }
    ]
  })
}

# Create an IAM role for EFS lifecycle management
resource "aws_iam_role" "efs_lifecycle_role" {
  name = "efs-lifecycle-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "efs.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the policy to the role
resource "aws_iam_role_policy_attachment" "efs_lifecycle_attachment" {
  role       = aws_iam_role.efs_lifecycle_role.name
  policy_arn = aws_iam_policy.efs_lifecycle_policy.arn
}

# Create an EFS file system
resource "aws_efs_file_system" "example" {
  creation_token = "my-efs-lifecycle-example"

  lifecycle_policy {
    transition_to_ia = "AFTER_30_DAYS"
  }

  tags = {
    Name = "EFS with Lifecycle Policy"
  }
}

# Create an EFS mount target (example for us-east-1a)
resource "aws_efs_mount_target" "example" {
  file_system_id  = aws_efs_file_system.example.id
  subnet_id       = "subnet-1234567890abcdef0" # Replace with your subnet ID
  security_groups = ["sg-1234567890abcdef0"]    # Replace with your security group ID
}

# Output the EFS DNS name
output "efs_dns_name" {
  value = aws_efs_file_system.example.dns_name
}

