provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_efs_file_system" "example" {
  creation_token = "my-efs-file-system"
  encrypted       = true
  performance_mode = "generalPurpose"
  throughput_mode  = "bursting"

  tags = {
    Name = "MyEFSFileSystem"
  }
}

resource "aws_efs_access_point" "example" {
  file_system_id = aws_efs_file_system.example.id

  posix_user {
    gid = 1000
    uid = 1000
  }

  root_directory {
    path = "/"
    creation_info {
      owner_gid   = 1000
      owner_uid   = 1000
      permissions = "755"
    }
  }
}

resource "aws_iam_policy" "efs_system_policy" {
  name        = "EFS-System-Policy"
  description = "Policy for managing EFS file systems"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "elasticfilesystem:CreateFileSystem",
          "elasticfilesystem:DeleteFileSystem",
          "elasticfilesystem:DescribeFileSystems",
          "elasticfilesystem:CreateMountTarget",
          "elasticfilesystem:DeleteMountTarget",
          "elasticfilesystem:DescribeMountTargets",
          "elasticfilesystem:DescribeAccessPoints",
          "elasticfilesystem:CreateAccessPoint",
          "elasticfilesystem:DeleteAccessPoint",
          "elasticfilesystem:DescribeTags",
          "elasticfilesystem:TagResource",
          "elasticfilesystem:UntagResource"
        ],
        Resource = "*"
      },
      {
        Effect = "Allow",
        Action = [
          "elasticfilesystem:DescribeLifecycleConfiguration",
          "elasticfilesystem:PutLifecycleConfiguration"
        ],
        Resource = aws_efs_file_system.example.arn
      },
      {
        Effect = "Allow",
        Action = [
          "elasticfilesystem:DescribeBackupPolicy",
          "elasticfilesystem:PutBackupPolicy",
          "elasticfilesystem:DescribeReplicationConfiguration",
          "elasticfilesystem:PutReplicationConfiguration"
        ],
        Resource = aws_efs_file_system.example.arn
      }
    ]
  })
}

