resource "aws_security_group" "example" {
  name        = "example-efs-sg"
  description = "Allow NFS traffic to EFS"
  vpc_id      = aws_vpc.example.id

  ingress {
    description     = "NFS traffic"
    from_port       = 2049
    to_port         = 2049
    protocol        = "tcp"
    security_groups = [aws_security_group.example.id] # Replace with your client security group IDs
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}
