resource "aws_efs_file_system" "example" {
  creation_token = "my-efs-filesystem"

  tags = {
    Name = "my-efs-filesystem"
  }
}

resource "aws_efs_mount_target" "example" {
  file_system_id  = aws_efs_file_system.example.id
  subnet_id       = "subnet-1234567890abcdef0" # Replace with your subnet ID
  security_groups = ["sg-1234567890abcdef0"] # Replace with your security group ID

  # Optional: Specify availability zone explicitly
  availability_zone = "us-east-1a" # Change to your preferred AZ
}

# Optional: IAM policy for EFS access (if needed)
resource "aws_iam_policy" "efs_access" {
  name        = "efs-access-policy"
  description = "Policy for EFS access"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "elasticfilesystem:ClientMount",
          "elasticfilesystem:ClientWrite"
        ]
        Resource = aws_efs_file_system.example.arn
      }
    ]
  })
}

# Optional: IAM role for EFS access (if needed)
resource "aws_iam_role" "efs_access_role" {
  name = "efs-access-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

# Optional: Attach IAM policy to role
resource "aws_iam_role_policy_attachment" "efs_access_attach" {
  role       = aws_iam_role.efs_access_role.name
  policy_arn = aws_iam_policy.efs_access.arn
}

