provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# VPC named "peer" with CIDR block 10.0.0.0/24
resource "aws_vpc" "peer" {
  cidr_block           = "10.0.0.0/24"
  instance_tenancy     = "default"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "peer"
  }
}

# VPC named "base" with CIDR block 10.1.0.0/24
resource "aws_vpc" "base" {
  cidr_block           = "10.1.0.0/24"
  instance_tenancy     = "default"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "base"
  }
}

# Internet Gateway for the "peer" VPC
resource "aws_internet_gateway" "peer_igw" {
  vpc_id = aws_vpc.peer.id
  tags = {
    Name = "peer-igw"
  }
}

# Internet Gateway for the "base" VPC
resource "aws_internet_gateway" "base_igw" {
  vpc_id = aws_vpc.base.id
  tags = {
    Name = "base-igw"
  }
}

# Route table for the "peer" VPC
resource "aws_route_table" "peer_rt" {
  vpc_id = aws_vpc.peer.id
  tags = {
    Name = "peer-rt"
  }
}

# Route table for the "base" VPC
resource "aws_route_table" "base_rt" {
  vpc_id = aws_vpc.base.id
  tags = {
    Name = "base-rt"
  }
}

# Route for the "peer" VPC to reach the "base" VPC via peering
resource "aws_route" "peer_to_base" {
  route_table_id            = aws_route_table.peer_rt.id
  destination_cidr_block    = aws_vpc.base.cidr_block
  vpc_peering_connection_id = aws_vpc_peering_connection.pike.id
  depends_on                = [aws_vpc_peering_connection.pike]
}

# Route for the "base" VPC to reach the "peer" VPC via peering
resource "aws_route" "base_to_peer" {
  route_table_id            = aws_route_table.base_rt.id
  destination_cidr_block    = aws_vpc.peer.cidr_block
  vpc_peering_connection_id = aws_vpc_peering_connection.pike.id
  depends_on                = [aws_vpc_peering_connection.pike]
}

# VPC Peering Connection named "pike"
resource "aws_vpc_peering_connection" "pike" {
  vpc_id      = aws_vpc.peer.id
  peer_vpc_id = aws_vpc.base.id
  auto_accept = true
  tags = {
    Name = "pike"
    pike = "permissions"
  }
}

# Subnet in the "peer" VPC
resource "aws_subnet" "peer_subnet" {
  vpc_id            = aws_vpc.peer.id
  cidr_block        = "10.0.0.0/25"
  availability_zone = "us-east-1a" # Change to your preferred AZ
  tags = {
    Name = "peer-subnet"
  }
}

# Subnet in the "base" VPC
resource "aws_subnet" "base_subnet" {
  vpc_id            = aws_vpc.base.id
  cidr_block        = "10.1.0.0/25"
  availability_zone = "us-east-1a" # Change to your preferred AZ
  tags = {
    Name = "base-subnet"
  }
}

# Associate route tables with subnets
resource "aws_route_table_association" "peer_association" {
  subnet_id      = aws_subnet.peer_subnet.id
  route_table_id = aws_route_table.peer_rt.id
}

resource "aws_route_table_association" "base_association" {
  subnet_id      = aws_subnet.base_subnet.id
  route_table_id = aws_route_table.base_rt.id
}

